def _server_only_allowlist_env(name: str) -> frozenset[str]:
    safe_name = str(name or "").strip()
    if not safe_name:
        return frozenset()
    raw = os.getenv(safe_name)
    if raw is None:
        return frozenset()
    return frozenset(token for token in [item.strip() for item in str(raw).split(",")] if token)


