def _normalize_plan_name(value: str) -> str:
    return PLAN_LIMITS[_plan_key_from_name(value)]["plan"]


def _plan_key_from_name(plan_name: str) -> str:
    token = str(plan_name or "").strip().lower()
    if token in PLAN_KEY_ALIASES:
        return PLAN_KEY_ALIASES[token]
    if token in PLAN_LIMITS:
        return token
    display_to_key = {str(cfg.get("plan") or "").strip().lower(): key for key, cfg in PLAN_LIMITS.items()}
    if token in display_to_key:
        return str(display_to_key[token] or "free")
    return "free"


def _is_known_plan_token(value: str) -> bool:
    token = str(value or "").strip().lower()
    if not token:
        return False
    if token in PLAN_KEY_ALIASES or token in PLAN_LIMITS:
        return True
    display_to_key = {str(cfg.get("plan") or "").strip().lower(): key for key, cfg in PLAN_LIMITS.items()}
    return token in display_to_key


def _normalize_coupon_plan_token(value: str) -> str:
    token = re.sub(r"[^a-z0-9_-]", "", str(value or "").strip().lower())
    if not token:
        return ""
    if not _is_known_plan_token(token):
        return token
    normalized = _plan_key_from_name(token)
    if normalized == "free":
        return ""
    return normalized


def _plan_config(plan_name: str) -> dict[str, Any]:
    return PLAN_LIMITS[_plan_key_from_name(plan_name)]


def _plan_allowed_engines(plan_key: str) -> tuple[str, ...]:
    normalized = _plan_key_from_name(plan_key)
    row = PLAN_FEATURE_FLAGS.get(normalized) or {}
    values = row.get("allowedEngines")
    if isinstance(values, (tuple, list)):
        out = tuple(
            engine
            for engine in [str(item or "").strip().upper() for item in values]
            if engine in set(TTS_ENGINE_KEYS)
        )
        if out:
            return out
    return tuple(TTS_ENGINE_KEYS)


def _plan_has_early_access(plan_key: str) -> bool:
    normalized = _plan_key_from_name(plan_key)
    row = PLAN_FEATURE_FLAGS.get(normalized) or {}
    return bool(row.get("earlyAccess"))


def _tts_success_bucket_for_plan(plan_key: str) -> str:
    normalized = _plan_key_from_name(plan_key)
    if normalized == "scale":
        return "scale"
    if normalized in {"pro"}:
        return "pro"
    if normalized in {"launcher", "starter", "creator"}:
        return "starter"
    return "free"


def _tts_pool_hint_plan_key(plan_key: str) -> str:
    normalized = _plan_key_from_name(plan_key)
    if normalized == "scale":
        return "plus"
    if normalized in {"pro", "launcher", "starter", "creator"}:
        return "pro"
    return "free"


def _tts_guardrail_for_plan(plan_name: str) -> tuple[str, dict[str, int]]:
    plan_key = _plan_key_from_name(plan_name)
    guardrails = TTS_PLAN_GUARDRAILS.get(plan_key) or TTS_PLAN_GUARDRAILS["free"]
    success_bucket = _tts_success_bucket_for_plan(plan_key)
    return plan_key, {
        "rpm": _TTS_SUCCESS_LIMITER.quota_for_plan(success_bucket),
        "maxChars": max(1, int(guardrails.get("maxChars") or 1)),
    }


def _success_rate_limit_headers(snapshot: Any) -> dict[str, str]:
    reset_at_ms = max(0, int(getattr(snapshot, "reset_at_ms", 0) or 0))
    reset_epoch_sec = max(0, reset_at_ms // 1000)
    return {
        "X-RateLimit-Success-Limit": str(max(1, int(getattr(snapshot, "limit", 1) or 1))),
        "X-RateLimit-Success-Remaining": str(max(0, int(getattr(snapshot, "remaining", 0) or 0))),
        "X-RateLimit-Success-Reset": str(reset_epoch_sec),
    }


def _serialize_tts_success_quota_reservation(
    reservation: SuccessQuotaReservation,
    *,
    uid: str,
    plan_name: str,
    plan_key: str,
    trace_id: str,
    request_fingerprint: str,
) -> dict[str, Any]:
    snapshot = reservation.snapshot
    return {
        "uid": str(uid or "").strip(),
        "planName": str(plan_name or "Free").strip() or "Free",
        "planKey": str(plan_key or "free").strip().lower() or "free",
        "traceId": str(trace_id or "").strip(),
        "requestFingerprint": str(request_fingerprint or "").strip(),
        "reservationId": str(reservation.reservation_id or "").strip(),
        "allowed": bool(reservation.allowed),
        "reserved": bool(reservation.reserved),
        "committed": bool(reservation.committed),
        "released": bool(reservation.released),
        "counted": bool(reservation.counted),
        "idempotentReuse": bool(reservation.idempotent_reuse),
        "backend": str(reservation.backend or "memory"),
        "redisAvailable": bool(reservation.redis_available),
        "redisRequired": bool(reservation.redis_required),
        "error": str(reservation.error or ""),
        "snapshot": {
            "limit": int(snapshot.limit),
            "used": int(snapshot.used),
            "remaining": int(snapshot.remaining),
            "resetAtMs": int(snapshot.reset_at_ms),
            "windowSeconds": int(snapshot.window_seconds),
        },
    }


def _deserialize_tts_success_quota_reservation(value: Any) -> Optional[SuccessQuotaReservation]:
    if not isinstance(value, dict):
        return None
    reservation_id = str(value.get("reservationId") or value.get("reservation_id") or "").strip()
    if not reservation_id:
        return None
    snapshot_raw = value.get("snapshot") if isinstance(value.get("snapshot"), dict) else {}
    snapshot = SuccessQuotaSnapshot(
        limit=max(1, int(snapshot_raw.get("limit") or 1)),
        used=max(0, int(snapshot_raw.get("used") or 0)),
        remaining=max(0, int(snapshot_raw.get("remaining") or 0)),
        reset_at_ms=max(0, int(snapshot_raw.get("resetAtMs") or snapshot_raw.get("reset_at_ms") or 0)),
        window_seconds=max(1, int(snapshot_raw.get("windowSeconds") or snapshot_raw.get("window_seconds") or 60)),
    )
    return SuccessQuotaReservation(
        allowed=bool(value.get("allowed", True)),
        reserved=bool(value.get("reserved", True)),
        committed=bool(value.get("committed", False)),
        released=bool(value.get("released", False)),
        counted=bool(value.get("counted", False)),
        idempotent_reuse=bool(value.get("idempotentReuse", value.get("idempotent_reuse", False))),
        reservation_id=reservation_id,
        backend=str(value.get("backend") or "memory"),
        redis_available=bool(value.get("redisAvailable", value.get("redis_available", False))),
        redis_required=bool(value.get("redisRequired", value.get("redis_required", False))),
        snapshot=snapshot,
        error=str(value.get("error") or ""),
    )


def _extract_tts_success_quota_reservation_payload(job: Any) -> Optional[dict[str, Any]]:
    if not isinstance(job, dict):
        return None
    direct = job.get("successQuotaReservation")
    if isinstance(direct, dict):
        return dict(direct)
    payload = job.get("payload")
    if isinstance(payload, dict) and isinstance(payload.get("successQuotaReservation"), dict):
        return dict(payload.get("successQuotaReservation") or {})
    return None


def _reserve_tts_success_quota(
    uid: str,
    plan_name: str,
    plan_key: str,
    trace_id: str,
    *,
    request_fingerprint: str,
) -> tuple[SuccessQuotaReservation, dict[str, str]]:
    quota_bucket = _tts_success_bucket_for_plan(plan_key)
    reservation = _TTS_SUCCESS_LIMITER.reserve_success(uid, quota_bucket, request_fingerprint=request_fingerprint)
    if reservation.allowed:
        return reservation, _success_rate_limit_headers(reservation.snapshot)
    retry_after_ms = max(250, int(reservation.snapshot.reset_at_ms) - int(time.time() * 1000))
    detail = {
        "errorCode": RATE_LIMIT_USER,
        "reason": "plan_success_limit_exceeded",
        "plan": plan_name,
        "windowSeconds": int(reservation.snapshot.window_seconds),
        "limit": int(reservation.snapshot.limit),
        "used": int(reservation.snapshot.used),
        "retryAfterMs": retry_after_ms,
        "trace_id": trace_id,
    }
    headers = _success_rate_limit_headers(reservation.snapshot)
    headers["Retry-After"] = str(max(1, int((retry_after_ms + 999) // 1000)))
    raise HTTPException(status_code=429, detail=detail, headers=headers)


def _commit_tts_success_quota_reservation(payload: Any) -> Optional[SuccessQuotaReservation]:
    reservation = _deserialize_tts_success_quota_reservation(payload)
    if reservation is None:
        return None
    return _TTS_SUCCESS_LIMITER.commit_success_reservation(reservation)


def _release_tts_success_quota_reservation(payload: Any) -> Optional[SuccessQuotaReservation]:
    reservation = _deserialize_tts_success_quota_reservation(payload)
    if reservation is None:
        return None
    return _TTS_SUCCESS_LIMITER.release_success_reservation(reservation)


def _enforce_tts_plan_guardrails(
    uid: str,
    text_chars: int,
    trace_id: str,
    *,
    engine: str,
    bypass: bool = False,
) -> tuple[str, str, dict[str, int]]:
    entitlement = _load_entitlement(uid)
    plan_name = _normalize_plan_name(str(entitlement.get("plan") or "Free"))
    plan_key, guardrails = _tts_guardrail_for_plan(plan_name)
    if bypass:
        return plan_name, plan_key, guardrails
    safe_engine = _resolve_internal_engine_token(engine) or _normalize_engine_name(engine)
    if safe_engine not in set(_plan_allowed_engines(plan_key)):
        raise HTTPException(
            status_code=403,
            detail={
                "errorCode": "VF_TTS_ENGINE_PLAN_FORBIDDEN",
                "reason": "plan_engine_forbidden",
                "plan": plan_name,
                "engine": safe_engine,
                "allowedEngines": list(_plan_allowed_engines(plan_key)),
                "trace_id": trace_id,
            },
        )
    max_chars = max(1, int(guardrails.get("maxChars") or 1))
    actual_chars = max(0, int(text_chars))
    if actual_chars > max_chars:
        raise HTTPException(
            status_code=400,
            detail={
                "errorCode": "VF_TTS_TEXT_TOO_LONG",
                "reason": "plan_char_limit_exceeded",
                "plan": plan_name,
                "maxChars": max_chars,
                "actualChars": actual_chars,
                "trace_id": trace_id,
            },
        )
    return plan_name, plan_key, guardrails


def _precheck_tts_success_quota(uid: str, plan_name: str, plan_key: str, trace_id: str) -> dict[str, str]:
    quota_bucket = _tts_success_bucket_for_plan(plan_key)
    snapshot = _TTS_SUCCESS_LIMITER.peek(uid, quota_bucket)
    if int(snapshot.remaining) <= 0:
        retry_after_ms = max(250, int(snapshot.reset_at_ms) - int(time.time() * 1000))
        detail = {
            "errorCode": RATE_LIMIT_USER,
            "reason": "plan_success_limit_exceeded",
            "plan": plan_name,
            "windowSeconds": int(snapshot.window_seconds),
            "limit": int(snapshot.limit),
            "used": int(snapshot.used),
            "retryAfterMs": retry_after_ms,
            "trace_id": trace_id,
        }
        headers = _success_rate_limit_headers(snapshot)
        headers["Retry-After"] = str(max(1, int((retry_after_ms + 999) // 1000)))
        raise HTTPException(status_code=429, detail=detail, headers=headers)
    return _success_rate_limit_headers(snapshot)


def _commit_tts_success_quota(
    uid: str,
    plan_name: str,
    plan_key: str,
    trace_id: str,
    *,
    request_fingerprint: str,
) -> SuccessQuotaDecision:
    quota_bucket = _tts_success_bucket_for_plan(plan_key)
    decision = _TTS_SUCCESS_LIMITER.commit_success(uid, quota_bucket, request_fingerprint=request_fingerprint)
    if decision.allowed:
        return decision
    retry_after_ms = max(250, int(decision.snapshot.reset_at_ms) - int(time.time() * 1000))
    detail = {
        "errorCode": RATE_LIMIT_USER,
        "reason": "plan_success_limit_exceeded",
        "plan": plan_name,
        "windowSeconds": int(decision.snapshot.window_seconds),
        "limit": int(decision.snapshot.limit),
        "used": int(decision.snapshot.used),
        "retryAfterMs": retry_after_ms,
        "trace_id": trace_id,
    }
    headers = _success_rate_limit_headers(decision.snapshot)
    headers["Retry-After"] = str(max(1, int((retry_after_ms + 999) // 1000)))
    raise HTTPException(status_code=429, detail=detail, headers=headers)


def _engine_rate(engine: str) -> float:
    engine_key = _resolve_internal_engine_token(engine)
    return _as_positive_number(VF_ENGINE_RATES.get(engine_key)) or 1.0


def _engine_rate_for_plan(plan_name: str, engine: str) -> float:
    # Kept as a compatibility wrapper while all pricing is engine-tier based.
    _ = plan_name
    return _engine_rate(engine)


def _round_inr(value: float) -> int:
    try:
        return max(1, int(round(float(value))))
    except Exception:
        return 1


def _billing_status_from_subscription(subscription_status: str) -> str:
    status = str(subscription_status or "").strip().lower()
    if status in {"active", "trialing"}:
        return "active"
    if status in {"past_due", "unpaid"}:
        return "past_due"
    if status in {"canceled", "incomplete_expired"}:
        return "cancelled"
    return status or "unknown"


def _firebase_ready() -> bool:
    if _FIREBASE_APP is None:
        _init_firebase_clients()
    return _FIREBASE_APP is not None and firebase_auth is not None


def _verify_firebase_id_token(id_token: str) -> dict[str, Any]:
    if not _firebase_ready():
        raise RuntimeError(_FIREBASE_INIT_ERROR or "Firebase is not configured.")
    assert firebase_auth is not None
    claims = firebase_auth.verify_id_token(id_token, check_revoked=True)  # type: ignore[no-any-return]
    if not isinstance(claims, dict):
        raise RuntimeError("Invalid auth claims.")
    return claims


def _inmemory_usage_month_doc_id(uid: str, now: Optional[datetime] = None) -> str:
    return f"{uid}_{_usage_month_key(now)}"


def _inmemory_usage_day_doc_id(uid: str, now: Optional[datetime] = None) -> str:
    return f"{uid}_{_usage_day_key(now)}"


def _month_window_bounds(now: Optional[datetime] = None) -> tuple[str, str]:
    dt = now or _utc_now()
    month_start = datetime(dt.year, dt.month, 1, tzinfo=timezone.utc)
    last_day = calendar.monthrange(dt.year, dt.month)[1]
    month_end = datetime(dt.year, dt.month, last_day, 23, 59, 59, tzinfo=timezone.utc)
    return month_start.isoformat(), month_end.isoformat()


def _day_window_bounds(now: Optional[datetime] = None) -> tuple[str, str]:
    dt = now or _utc_now()
    day_start = datetime(dt.year, dt.month, dt.day, 0, 0, 0, tzinfo=timezone.utc)
    day_end = datetime(dt.year, dt.month, dt.day, 23, 59, 59, tzinfo=timezone.utc)
    return day_start.isoformat(), day_end.isoformat()


def _as_positive_int(value: Any) -> int:
    try:
        number = int(value)
    except Exception:
        number = 0
    return max(0, number)


VF_DECIMAL_PRECISION = 4
VF_EPSILON = 1e-6


def _as_positive_number(value: Any) -> float:
    try:
        number = float(value)
    except Exception:
        number = 0.0
    if not math.isfinite(number):
        number = 0.0
    return round(max(0.0, number), VF_DECIMAL_PRECISION)


def _as_float(value: Any, default: float = 0.0) -> float:
    try:
        number = float(value)
    except Exception:
        number = float(default)
    if not math.isfinite(number):
        return float(default)
    return number


def _auth_exempt_path(path: str) -> bool:
    normalized = str(path or "").strip()
    public_paths = {
        "/health",
        "/system/version",
        "/billing/webhook",
    }
    if VF_DOCS_ENABLE:
        public_paths.update(
            {
                "/openapi.json",
                "/docs",
                "/docs/oauth2-redirect",
                "/redoc",
            }
        )
    if normalized in public_paths:
        return True
    return bool(VF_DOCS_ENABLE and normalized.startswith("/docs"))


def _user_id_requirement_exempt_path(path: str) -> bool:
    normalized = str(path or "").strip()
    if not normalized:
        return True
    exempt_paths = {
        "/health",
        "/system/version",
        "/account/profile",
        "/account/profile/bootstrap",
    }
    if VF_DOCS_ENABLE:
        exempt_paths.update(
            {
                "/openapi.json",
                "/docs",
                "/docs/oauth2-redirect",
                "/redoc",
            }
        )
    if normalized in exempt_paths:
        return True
    if normalized.startswith("/admin"):
        return True
    if normalized.startswith("/ops/guardian"):
        return True
    return False


@app.middleware("http")
async def _firebase_auth_middleware(request: Request, call_next: Any) -> Response:
    if _is_cors_preflight_request(request):
        return _cors_preflight_response(request)

    if not VF_AUTH_ENFORCE:
        return await call_next(request)

    if _auth_exempt_path(request.url.path):
        return await call_next(request)

    auth_header = str(request.headers.get("Authorization") or "").strip()
    if not auth_header.lower().startswith("bearer "):
        return _cors_json_response(request, status_code=401, content={"detail": "Missing bearer token."})

    id_token = auth_header.split(" ", 1)[1].strip()
    if not id_token:
        return _cors_json_response(request, status_code=401, content={"detail": "Missing bearer token."})

    try:
        claims = _verify_firebase_id_token(id_token)
    except Exception as exc:  # noqa: BLE001
        detail = "Invalid auth token."
        if "too early" in str(exc or "").lower() or "not yet valid" in str(exc or "").lower():
            detail = "Invalid auth token: token is not yet valid."
        return _cors_json_response(request, status_code=401, content={"detail": detail})

    uid = str(claims.get("uid") or "")
    if not uid:
        return _cors_json_response(request, status_code=401, content={"detail": "Auth token did not include uid."})

    if VF_REQUIRE_EMAIL_VERIFIED:
        email = str(claims.get("email") or "").strip()
        if (
            email
            and not _as_bool(claims.get("email_verified"))
            and not _claims_is_admin_for_email_verification(uid, claims)
        ):
            return _cors_json_response(
                request,
                status_code=403,
                content={
                    "detail": "Email verification required.",
                    "errorCode": "VF_EMAIL_NOT_VERIFIED",
                },
            )

    request.state.uid = uid
    request.state.auth_claims = claims
    return await call_next(request)


@app.middleware("http")
async def _user_id_requirement_middleware(request: Request, call_next: Any) -> Response:
    if not VF_USER_ID_REQUIRED or not VF_AUTH_ENFORCE:
        return await call_next(request)
    path = str(request.url.path or "/")
    if _auth_exempt_path(path) or _user_id_requirement_exempt_path(path):
        return await call_next(request)
    uid = str(getattr(request.state, "uid", "") or "").strip()
    if not uid:
        return await call_next(request)
    if _request_is_admin(request, uid):
        return await call_next(request)
    profile = _user_profile_read(uid)
    if isinstance(profile, dict):
        user_id = str(profile.get("userId") or "").strip().lower()
        if user_id:
            request.state.user_id = user_id
            return await call_next(request)
    return _cors_json_response(
        request,
        status_code=428,
        content={"detail": "Complete your userId before using this feature."},
    )


@app.middleware("http")
async def _ai_ops_observer_middleware(request: Request, call_next: Any) -> Response:
    path = str(request.url.path or "/")
    method = str(request.method or "GET").upper()
    throttle_payload = _ai_ops_throttle_payload(path)
    if throttle_payload is not None:
        _ai_ops_record_rejected_request(path, throttle_payload)
        _admin_usage_record_http(path, method, status_code=503, elapsed_ms=0)
        return JSONResponse(status_code=503, content=throttle_payload)

    started_ms = int(time.time() * 1000)
    _ai_ops_request_started(path)
    status_code = 500
    error_detail = ""
    try:
        response = await call_next(request)
        status_code = int(getattr(response, "status_code", 200))
        return response
    except Exception as exc:  # noqa: BLE001
        error_detail = str(exc)
        status_code = 500
        raise
    finally:
        elapsed_ms = max(0, int(time.time() * 1000) - started_ms)
        _ai_ops_request_finished(path, status_code=status_code, elapsed_ms=elapsed_ms, error_detail=error_detail)
        _admin_usage_record_http(path, method, status_code=status_code, elapsed_ms=elapsed_ms)


def _require_request_uid(request: Request) -> str:
    uid = str(getattr(request.state, "uid", "") or "").strip()
    if uid:
        return uid
    if not VF_AUTH_ENFORCE:
        header_uid = str(request.headers.get("x-dev-uid") or "").strip()
        return header_uid or VF_DEV_BYPASS_UID
    raise HTTPException(status_code=401, detail="Authentication required.")


def _request_source_ip(request: Optional[Request]) -> str:
    if request is None:
        return ""
    forwarded = str(request.headers.get("x-forwarded-for") or "").split(",")[0].strip()
    return forwarded or str(request.client.host if request.client else "").strip()


def _request_claim_email(request: Optional[Request]) -> str:
    if request is None:
        return ""
    claims = getattr(request.state, "auth_claims", None)
    if not isinstance(claims, dict):
        return ""
    return str(claims.get("email") or "").strip().lower()


def _request_claim_phone(request: Optional[Request]) -> str:
    if request is None:
        return ""
    claims = getattr(request.state, "auth_claims", None)
    if not isinstance(claims, dict):
        return ""
    return str(claims.get("phone_number") or claims.get("phoneNumber") or "").strip()


def _normalize_user_id_handle(raw_user_id: str) -> str:
    token = str(raw_user_id or "").strip().lower()
    token = re.sub(r"[^a-z0-9_]", "", token)
    if token.startswith("_"):
        token = token.lstrip("_")
    if not token:
        raise HTTPException(status_code=400, detail="userId is required.")
    if token in USER_ID_RESERVED_WORDS:
        raise HTTPException(status_code=400, detail="This userId is reserved.")
    if not USER_ID_HANDLE_PATTERN.fullmatch(token):
        raise HTTPException(
            status_code=400,
            detail="userId must match [a-z0-9_]{4,24} and cannot start with underscore.",
        )
    return token


def _user_profile_backfill_candidate(uid: str, email: str = "", display_name: str = "") -> str:
    safe_uid = str(uid or "").strip().lower()
    raw_email = str(email or "").strip().lower()
    raw_display = str(display_name or "").strip().lower()
    base = ""
    if raw_email and "@" in raw_email:
        base = raw_email.split("@", 1)[0]
    elif raw_display:
        base = raw_display.replace(" ", "_")
    if not base:
        base = f"user_{safe_uid[:12] or 'acct'}"
    base = re.sub(r"[^a-z0-9_]", "", base)
    base = base.lstrip("_")
    if len(base) < 4:
        base = f"user_{safe_uid[:12] or 'acct'}"
    if len(base) > 24:
        base = base[:24]
    if base in USER_ID_RESERVED_WORDS:
        base = f"{base}_id"
    base = re.sub(r"[^a-z0-9_]", "", base).lstrip("_")
    if len(base) < 4:
        base = f"user{safe_uid[:6]}".ljust(4, "0")
    if len(base) > 24:
        base = base[:24]
    return base


def _user_profile_backfill_candidates(uid: str, email: str = "", display_name: str = "") -> list[str]:
    base = _user_profile_backfill_candidate(uid, email, display_name)
    candidates = [base]
    safe_uid = re.sub(r"[^a-z0-9]", "", str(uid or "").strip().lower())
    suffixes: list[str] = []
    for length in (4, 6, 8, 10):
        suffix = safe_uid[-length:]
        if suffix and suffix not in suffixes:
            suffixes.append(suffix)
    if safe_uid:
        digest = hashlib.sha1(safe_uid.encode("utf-8")).hexdigest()[:6]
        if digest not in suffixes:
            suffixes.append(digest)
    for suffix in suffixes:
        max_base_len = 24 - len(suffix) - 1
        if max_base_len < 4:
            continue
        prefix = re.sub(r"_+$", "", base[:max_base_len]).strip("_")
        if len(prefix) < 4:
            prefix = base[:max_base_len]
        try:
            candidate = _normalize_user_id_handle(f"{prefix}_{suffix}")
        except HTTPException:
            continue
        if candidate not in candidates:
            candidates.append(candidate)
    return candidates


def _sanitize_user_profile_row(row: dict[str, Any]) -> dict[str, Any]:
    payload = dict(row or {})
    payload.pop(_USER_PROFILE_LOCAL_FALLBACK_FLAG, None)
    return payload


def _user_profile_read(uid: str) -> Optional[dict[str, Any]]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return None

    def _read_inmemory_fallback(*, require_local_fallback_marker: bool = False) -> Optional[dict[str, Any]]:
        with _INMEMORY_LOCK:
            row = _INMEMORY_USER_PROFILES.get(safe_uid)
            if not isinstance(row, dict):
                return None
            if require_local_fallback_marker and not bool(row.get(_USER_PROFILE_LOCAL_FALLBACK_FLAG)):
                return None
            return _sanitize_user_profile_row(row)

    collection = _firestore_collection(USER_PROFILES_COLLECTION)
    if collection is None:
        return _read_inmemory_fallback()
    try:
        doc_ref = collection.document(safe_uid)
        doc = doc_ref.get() if hasattr(doc_ref, "get") else doc_ref
    except Exception:
        return _read_inmemory_fallback()
    if not bool(getattr(doc, "exists", False)):
        return _read_inmemory_fallback(require_local_fallback_marker=True)
    payload = doc.to_dict() or {}
    payload["uid"] = safe_uid
    return payload


def _user_profile_find_by_user_id(user_id: str) -> Optional[dict[str, Any]]:
    safe_user_id = str(user_id or "").strip().lower()
    if not safe_user_id:
        return None
    index_collection = _firestore_collection(USER_ID_INDEX_COLLECTION)
    if index_collection is None:
        with _INMEMORY_LOCK:
            row = _INMEMORY_USER_ID_INDEX.get(safe_user_id)
            if not isinstance(row, dict):
                return None
            uid = str(row.get("uid") or "").strip()
        if not uid:
            return None
        return _user_profile_read(uid)
    try:
        index_doc = index_collection.document(safe_user_id).get()
    except Exception:
        return None
    if not index_doc.exists:
        with _INMEMORY_LOCK:
            row = _INMEMORY_USER_ID_INDEX.get(safe_user_id)
            if not isinstance(row, dict) or not bool(row.get(_USER_ID_INDEX_LOCAL_FALLBACK_FLAG)):
                return None
            uid = str(row.get("uid") or "").strip()
        if not uid:
            return None
        return _user_profile_read(uid)
    idx = index_doc.to_dict() or {}
    uid = str(idx.get("uid") or "").strip()
    if not uid:
        return None
    return _user_profile_read(uid)


def _user_id_for_uid(uid: str) -> str:
    profile = _user_profile_read(uid)
    if isinstance(profile, dict):
        return str(profile.get("userId") or "").strip().lower()
    return ""


def _is_firestore_transaction_wrapper_error(exc: Exception) -> bool:
    detail = str(exc or "").strip().lower()
    if not detail:
        return False
    if "transaction has no transaction id" in detail:
        return True
    if "transaction id" in detail and "cannot be rolled back" in detail:
        return True
    if "rollback" in detail and "transaction id" in detail:
        return True
    return False


def _classify_user_profile_write_error(exc: Exception) -> tuple[int, str]:
    detail = str(exc or "").strip()
    lowered = detail.lower()
    if "userid is immutable once set" in lowered or ("immutable" in lowered and "userid" in lowered):
        return 409, "userId is immutable once set."
    if "userid already exists" in lowered or ("already exists" in lowered and "userid" in lowered):
        return 409, "userId already exists."
    if (
        "service_disabled" in lowered
        or "firestore.googleapis.com" in lowered
        or "cloud firestore api has not been used" in lowered
        or "permission_denied" in lowered
        or "insufficient permissions" in lowered
        or "googleapis.com" in lowered
    ):
        return 503, "Profile service is temporarily unavailable. Please try again in a few minutes."
    if "deadline exceeded" in lowered or "timed out" in lowered or "timeout" in lowered:
        return 503, "Profile service timed out. Please try again."
    return 503, "Failed to save user profile. Please try again."


def _log_user_profile_write_error(stage: str, uid: str, user_id: str, exc: Exception) -> None:
    print(
        f"[user-profile-upsert] {stage} uid={str(uid or '').strip()} userId={str(user_id or '').strip()} "
        f"reason_class={type(exc).__name__} reason={str(exc)[:220]}",
        flush=True,
    )


def _is_user_profile_store_unavailable_error(exc: Exception) -> bool:
    lowered = str(exc or "").strip().lower()
    if not lowered:
        return False
    return (
        "service_disabled" in lowered
        or "cloud firestore api has not been used" in lowered
        or "firestore.googleapis.com" in lowered
        or "googleapis.com" in lowered
        or "permission_denied" in lowered
        or "insufficient permissions" in lowered
    )


def _user_profile_upsert(
    uid: str,
    *,
    user_id: Optional[str] = None,
    display_name: Optional[str] = None,
    email: Optional[str] = None,
    created_by: str = "",
    updated_by: str = "",
    force_change: bool = False,
    allow_existing_immutable: bool = False,
) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        raise HTTPException(status_code=400, detail="Missing user uid.")
    current = _user_profile_read(safe_uid) or {}
    now_iso = _utc_now().isoformat()
    current_user_id = str(current.get("userId") or "").strip().lower()
    next_user_id = _normalize_user_id_handle(
        str(user_id or current_user_id or _user_profile_backfill_candidate(safe_uid, str(email or ""), str(display_name or "")))
    )
    if current_user_id and next_user_id != current_user_id and not force_change and not allow_existing_immutable:
        raise HTTPException(status_code=409, detail="userId is immutable once set.")

    next_display_name = str(
        display_name
        if display_name is not None
        else current.get("displayName") or current.get("name") or ""
    ).strip()[:120]
    next_email = str(email if email is not None else current.get("email") or "").strip().lower()[:240]
    created_at = str(current.get("createdAt") or now_iso)
    row = {
        "uid": safe_uid,
        "userId": next_user_id,
        "displayName": next_display_name,
        "email": next_email,
        "status": str(current.get("status") or "active"),
        "createdAt": created_at,
        "updatedAt": now_iso,
        "createdBy": str(current.get("createdBy") or created_by or safe_uid)[:160],
        "updatedBy": str(updated_by or created_by or safe_uid)[:160],
    }

    profiles_collection = _firestore_collection(USER_PROFILES_COLLECTION)
    index_collection = _firestore_collection(USER_ID_INDEX_COLLECTION)
    fail_fast_unavailable = bool(VF_USER_PROFILE_FAILFAST and VF_FIRESTORE_ENABLE)

    def _raise_profile_store_unavailable(reason: Optional[Exception] = None) -> None:
        if reason is not None:
            _log_user_profile_write_error("store_unavailable_failfast", safe_uid, next_user_id, reason)
        raise HTTPException(
            status_code=503,
            detail="Profile service is temporarily unavailable. Please try again in a few minutes.",
        )
    def _apply_inmemory_upsert(*, reason: Optional[Exception] = None) -> dict[str, Any]:
        if reason is not None:
            _log_user_profile_write_error("inmemory_fallback", safe_uid, next_user_id, reason)
        mark_local_fallback = bool(reason is not None and _is_user_profile_store_unavailable_error(reason))
        with _INMEMORY_LOCK:
            existing = dict(_INMEMORY_USER_PROFILES.get(safe_uid) or {})
            existing_user_id = str(existing.get("userId") or "").strip().lower()
            if existing_user_id and existing_user_id != next_user_id and not force_change and not allow_existing_immutable:
                raise HTTPException(status_code=409, detail="userId is immutable once set.")
            owner = _INMEMORY_USER_ID_INDEX.get(next_user_id) or {}
            owner_uid = str(owner.get("uid") or "").strip()
            if owner_uid and owner_uid != safe_uid:
                raise HTTPException(status_code=409, detail="userId already exists.")
            if existing_user_id and existing_user_id != next_user_id:
                _INMEMORY_USER_ID_INDEX.pop(existing_user_id, None)
            index_row = {
                "userId": next_user_id,
                "uid": safe_uid,
                "createdAt": str(owner.get("createdAt") or now_iso),
                "updatedAt": now_iso,
            }
            if mark_local_fallback:
                index_row[_USER_ID_INDEX_LOCAL_FALLBACK_FLAG] = True
            _INMEMORY_USER_ID_INDEX[next_user_id] = dict(index_row)
            profile_row = dict(row)
            if mark_local_fallback:
                profile_row[_USER_PROFILE_LOCAL_FALLBACK_FLAG] = True
            _INMEMORY_USER_PROFILES[safe_uid] = dict(profile_row)
            _persist_inmemory_user_profile_store_locked()
            return dict(row)

    if (
        profiles_collection is None
        or index_collection is None
        or _FIRESTORE_DB is None
        or firebase_firestore is None
    ):
        if fail_fast_unavailable:
            _raise_profile_store_unavailable()
        return _apply_inmemory_upsert()

    profile_ref = _FIRESTORE_DB.collection(USER_PROFILES_COLLECTION).document(safe_uid)
    new_index_ref = _FIRESTORE_DB.collection(USER_ID_INDEX_COLLECTION).document(next_user_id)
    transaction = _FIRESTORE_DB.transaction()

    def _build_firestore_payload(existing_profile: dict[str, Any], *, index_created_at: str) -> dict[str, Any]:
        _ = index_created_at
        return {
            "uid": safe_uid,
            "userId": next_user_id,
            "displayName": next_display_name,
            "email": next_email,
            "status": str((existing_profile or {}).get("status") or "active"),
            "createdAt": str((existing_profile or {}).get("createdAt") or now_iso),
            "updatedAt": now_iso,
            "createdBy": str((existing_profile or {}).get("createdBy") or created_by or safe_uid)[:160],
            "updatedBy": str(updated_by or created_by or safe_uid)[:160],
        }

    def _raise_user_id_conflict_if_any(existing_user_id: str, owner_uid: str) -> None:
        if existing_user_id and existing_user_id != next_user_id and not force_change and not allow_existing_immutable:
            raise HTTPException(status_code=409, detail="userId is immutable once set.")
        if owner_uid and owner_uid != safe_uid:
            raise HTTPException(status_code=409, detail="userId already exists.")

    def _apply_non_transactional_fallback(transaction_error: Exception) -> dict[str, Any]:
        print(
            f"[user-profile-upsert] fallback_non_transactional uid={safe_uid} userId={next_user_id} "
            f"reason_class={type(transaction_error).__name__} reason={str(transaction_error)[:180]}",
            flush=True,
        )
        try:
            profile_doc = profile_ref.get()
            existing = profile_doc.to_dict() if profile_doc.exists else {}
            existing_user_id = str((existing or {}).get("userId") or "").strip().lower()
            index_doc = new_index_ref.get()
            index_payload = index_doc.to_dict() if index_doc.exists else {}
            owner_uid = str((index_payload or {}).get("uid") or "").strip()
            _raise_user_id_conflict_if_any(existing_user_id, owner_uid)

            old_index_ref = None
            if existing_user_id and existing_user_id != next_user_id:
                old_index_ref = _FIRESTORE_DB.collection(USER_ID_INDEX_COLLECTION).document(existing_user_id)
            payload = _build_firestore_payload(
                existing,
                index_created_at=str((index_payload or {}).get("createdAt") or now_iso),
            )
            profile_ref.set(payload, merge=True)
            new_index_ref.set(
                {
                    "userId": next_user_id,
                    "uid": safe_uid,
                    "createdAt": str((index_payload or {}).get("createdAt") or now_iso),
                    "updatedAt": now_iso,
                },
                merge=True,
            )
            if old_index_ref is not None:
                old_index_ref.delete()
            return dict(payload)
        except HTTPException:
            raise
        except Exception as fallback_exc:
            if _is_user_profile_store_unavailable_error(fallback_exc):
                if fail_fast_unavailable:
                    _raise_profile_store_unavailable(fallback_exc)
                return _apply_inmemory_upsert(reason=fallback_exc)
            _log_user_profile_write_error("fallback_failed", safe_uid, next_user_id, fallback_exc)
            status_code, detail = _classify_user_profile_write_error(fallback_exc)
            raise HTTPException(status_code=status_code, detail=detail) from fallback_exc

    @firebase_firestore.transactional
    def _apply(transaction_obj: Any) -> dict[str, Any]:
        profile_doc = profile_ref.get(transaction=transaction_obj)
        existing = profile_doc.to_dict() if profile_doc.exists else {}
        existing_user_id = str((existing or {}).get("userId") or "").strip().lower()
        index_doc = new_index_ref.get(transaction=transaction_obj)
        owner_uid = str((index_doc.to_dict() or {}).get("uid") or "").strip() if index_doc.exists else ""
        _raise_user_id_conflict_if_any(existing_user_id, owner_uid)
        old_index_ref = None
        if existing_user_id and existing_user_id != next_user_id:
            old_index_ref = _FIRESTORE_DB.collection(USER_ID_INDEX_COLLECTION).document(existing_user_id)
        index_payload = index_doc.to_dict() if index_doc.exists else {}
        payload = _build_firestore_payload(
            existing,
            index_created_at=str((index_payload or {}).get("createdAt") or now_iso),
        )
        index_created_at = str((index_payload or {}).get("createdAt") or now_iso)
        transaction_obj.set(profile_ref, payload, merge=True)
        transaction_obj.set(
            new_index_ref,
            {
                "userId": next_user_id,
                "uid": safe_uid,
                "createdAt": index_created_at,
                "updatedAt": now_iso,
            },
            merge=True,
        )
        if old_index_ref is not None:
            transaction_obj.delete(old_index_ref)
        return payload

    try:
        return _apply(transaction)
    except HTTPException:
        raise
    except RuntimeError as exc:
        if _is_firestore_transaction_wrapper_error(exc):
            return _apply_non_transactional_fallback(exc)
        if _is_user_profile_store_unavailable_error(exc):
            if fail_fast_unavailable:
                _raise_profile_store_unavailable(exc)
            return _apply_inmemory_upsert(reason=exc)
        _log_user_profile_write_error("transaction_runtime_error", safe_uid, next_user_id, exc)
        status_code, detail = _classify_user_profile_write_error(exc)
        raise HTTPException(status_code=status_code, detail=detail) from exc
    except Exception as exc:
        if _is_firestore_transaction_wrapper_error(exc):
            return _apply_non_transactional_fallback(exc)
        if _is_user_profile_store_unavailable_error(exc):
            if fail_fast_unavailable:
                _raise_profile_store_unavailable(exc)
            return _apply_inmemory_upsert(reason=exc)
        _log_user_profile_write_error("transaction_error", safe_uid, next_user_id, exc)
        status_code, detail = _classify_user_profile_write_error(exc)
        raise HTTPException(status_code=status_code, detail=detail) from exc


def _ensure_user_profile(
    uid: str,
    *,
    request: Optional[Request] = None,
    allow_auto_backfill: bool = True,
    seed_email: str = "",
    seed_display_name: str = "",
    repair_user_id_collisions: bool = False,
    suppress_backfill_errors: bool = False,
    fetch_firebase_identity: bool = True,
) -> Optional[dict[str, Any]]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return None
    existing = _user_profile_read(safe_uid)
    if isinstance(existing, dict):
        return existing
    if not allow_auto_backfill:
        return None
    email = _request_claim_email(request) or str(seed_email or "").strip().lower()
    display_name = str(seed_display_name or "").strip()
    if fetch_firebase_identity and _firebase_ready() and firebase_auth is not None:
        try:
            record = firebase_auth.get_user(safe_uid)  # type: ignore[attr-defined]
            display_name = str(getattr(record, "display_name", "") or "").strip()
            if not email:
                email = str(getattr(record, "email", "") or "").strip().lower()
        except Exception:
            pass
    candidates = (
        _user_profile_backfill_candidates(safe_uid, email, display_name)
        if repair_user_id_collisions
        else [_user_profile_backfill_candidate(safe_uid, email, display_name)]
    )
    last_error: Optional[Exception] = None
    last_candidate = candidates[0] if candidates else ""
    for candidate in candidates:
        last_candidate = candidate
        try:
            return _user_profile_upsert(
                safe_uid,
                user_id=candidate,
                display_name=display_name or None,
                email=email or None,
                created_by="system_backfill",
                updated_by="system_backfill",
                force_change=False,
                allow_existing_immutable=True,
            )
        except HTTPException as exc:
            last_error = exc
            detail = str(exc.detail or "").strip().lower()
            if exc.status_code == 409 and repair_user_id_collisions and "userid already exists" in detail:
                continue
            if suppress_backfill_errors:
                _log_user_profile_write_error("backfill_failed", safe_uid, candidate, exc)
                return _user_profile_read(safe_uid)
            raise
        except Exception as exc:
            last_error = exc
            if suppress_backfill_errors:
                _log_user_profile_write_error("backfill_failed", safe_uid, candidate, exc)
                return _user_profile_read(safe_uid)
            raise
    if suppress_backfill_errors:
        if last_error is None:
            last_error = RuntimeError("userId repair candidates exhausted.")
        _log_user_profile_write_error("backfill_candidates_exhausted", safe_uid, last_candidate, last_error)
        return _user_profile_read(safe_uid)
    if isinstance(last_error, HTTPException):
        raise last_error
    raise HTTPException(status_code=409, detail="userId already exists.")


def _resolve_request_user_id(request: Optional[Request], uid: str) -> str:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return ""
    allow_auto_backfill = (not VF_USER_ID_REQUIRED or not VF_AUTH_ENFORCE)
    if request is not None and _request_is_admin(request, safe_uid):
        allow_auto_backfill = False
    profile = _ensure_user_profile(
        safe_uid,
        request=request,
        allow_auto_backfill=allow_auto_backfill,
    )
    if isinstance(profile, dict):
        return str(profile.get("userId") or "").strip().lower()
    return ""


def _resolve_request_user_id_read_only(uid: str) -> str:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return ""
    return _user_id_for_uid(safe_uid)


def _require_user_id_ready(request: Request, uid: str) -> Optional[dict[str, Any]]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        raise HTTPException(status_code=401, detail="Authentication required.")
    if _request_is_admin(request, safe_uid):
        existing = _user_profile_read(safe_uid)
        if isinstance(existing, dict):
            return existing
        return {"uid": safe_uid, "userId": "", "status": "admin"}
    profile = _user_profile_read(safe_uid)
    if isinstance(profile, dict) and str(profile.get("userId") or "").strip():
        return profile
    if not VF_USER_ID_REQUIRED:
        return _ensure_user_profile(safe_uid, request=request, allow_auto_backfill=True)
    if not VF_AUTH_ENFORCE:
        return _ensure_user_profile(safe_uid, request=request, allow_auto_backfill=True)
    raise HTTPException(
        status_code=428,
        detail="Complete your userId before using this feature.",
    )


def _firestore_user_is_admin(uid: str) -> bool:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return False
    users_collection = _firestore_collection("users")
    if users_collection is None:
        return False
    try:
        doc = users_collection.document(safe_uid).get()
    except Exception:
        return False
    if not doc.exists:
        return False
    payload = doc.to_dict() or {}
    if _as_bool(payload.get("isAdmin")) or _as_bool(payload.get("admin")):
        return True
    role = str(payload.get("role") or "").strip().lower()
    if role == "admin":
        return True
    roles = payload.get("roles")
    if isinstance(roles, list):
        for item in roles:
            if str(item or "").strip().lower() == "admin":
                return True
    return False


def _request_claim_is_admin(request: Request) -> bool:
    claims = getattr(request.state, "auth_claims", None)
    if not isinstance(claims, dict):
        return False
    return _as_bool(claims.get("admin"))


def _claims_is_admin_for_email_verification(uid: str, claims: dict[str, Any]) -> bool:
    if _as_bool(claims.get("admin")):
        return True
    safe_uid = str(uid or "").strip()
    if safe_uid and safe_uid in VF_ADMIN_APPROVER_UIDS:
        return True
    email = str(claims.get("email") or "").strip().lower()
    if email and email in VF_ADMIN_APPROVER_EMAILS:
        return True
    if safe_uid and _firestore_user_is_admin(safe_uid):
        return True
    return False


def _request_is_admin(request: Request, uid: Optional[str] = None) -> bool:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        safe_uid = str(getattr(request.state, "uid", "") or "").strip()
    if not safe_uid and not VF_AUTH_ENFORCE:
        header_uid = str(request.headers.get("x-dev-uid") or "").strip()
        safe_uid = header_uid or VF_DEV_BYPASS_UID
    if not safe_uid:
        return False
    if (
        not VF_AUTH_ENFORCE
        and not VF_IS_PRODUCTION
        and (safe_uid == VF_DEV_BYPASS_UID or safe_uid.startswith("local_admin"))
    ):
        return True
    if _request_claim_is_admin(request):
        return True
    if safe_uid in VF_ADMIN_APPROVER_UIDS:
        return True
    if _firestore_user_is_admin(safe_uid):
        return True
    return False


def _tts_v2_session_redis_client() -> Any:
    candidate = getattr(_TTS_V2_ENGINE, "_redis", None)
    return candidate


def _tts_v2_session_uid_key(uid: str) -> str:
    return f"vf:tts:v2:session:uid:{str(uid or '').strip()}"


def _tts_v2_session_record_key(session_key: str) -> str:
    return f"vf:tts:v2:session:key:{str(session_key or '').strip()}"


def _tts_v2_prune_local_sessions_locked(now_ms: Optional[int] = None) -> None:
    now = int(now_ms or int(time.time() * 1000))
    expired: list[str] = []
    for key, row in list(_INMEMORY_TTS_V2_SESSIONS.items()):
        expires_at_ms = int((row or {}).get("expiresAtMs") or 0)
        if expires_at_ms > 0 and expires_at_ms <= now:
            expired.append(str(key))
    for key in expired:
        row = _INMEMORY_TTS_V2_SESSIONS.pop(key, None)
        safe_uid = str((row or {}).get("uid") or "").strip()
        if safe_uid and _INMEMORY_TTS_V2_ACTIVE_SESSION_BY_UID.get(safe_uid) == key:
            _INMEMORY_TTS_V2_ACTIVE_SESSION_BY_UID.pop(safe_uid, None)


def _issue_tts_v2_session(uid: str) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        raise HTTPException(status_code=401, detail="Authentication required.")
    now_ms = int(time.time() * 1000)
    ttl_seconds = max(60, int(VF_TTS_V2_SESSION_TTL_SECONDS or 1800))
    expires_at_ms = now_ms + (ttl_seconds * 1000)
    token_core = re.sub(r"[^A-Za-z0-9]", "", secrets.token_urlsafe(24))
    session_key = f"v2s_{token_core}"[:80]
    if len(session_key) < 16:
        session_key = f"v2s_{uuid.uuid4().hex}"
    payload = {
        "uid": safe_uid,
        "sessionKey": session_key,
        "createdAtMs": now_ms,
        "expiresAtMs": expires_at_ms,
        "ttlSeconds": ttl_seconds,
    }
    redis_client = _tts_v2_session_redis_client()
    if redis_client is not None:
        try:
            uid_key = _tts_v2_session_uid_key(safe_uid)
            old_key = str(redis_client.get(uid_key) or "").strip()
            pipe = redis_client.pipeline(transaction=True)
            if old_key:
                pipe.delete(_tts_v2_session_record_key(old_key))
            pipe.set(
                _tts_v2_session_record_key(session_key),
                json.dumps(payload, separators=(",", ":"), ensure_ascii=True),
                ex=ttl_seconds,
            )
            pipe.set(uid_key, session_key, ex=ttl_seconds)
            pipe.execute()
            return payload
        except Exception:
            pass
    with _TTS_V2_SESSION_LOCK:
        _tts_v2_prune_local_sessions_locked(now_ms)
        old_key = str(_INMEMORY_TTS_V2_ACTIVE_SESSION_BY_UID.get(safe_uid) or "").strip()
        if old_key:
            _INMEMORY_TTS_V2_SESSIONS.pop(old_key, None)
        _INMEMORY_TTS_V2_SESSIONS[session_key] = dict(payload)
        _INMEMORY_TTS_V2_ACTIVE_SESSION_BY_UID[safe_uid] = session_key
    return payload


def _require_tts_v2_session(request: Request, uid: str) -> dict[str, Any]:
    if not VF_TTS_V2_SESSION_ENFORCE:
        return {}
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        raise HTTPException(status_code=401, detail="Authentication required.")
    provided = str(request.headers.get(TTS_V2_SESSION_HEADER) or "").strip()
    if not provided:
        raise HTTPException(status_code=401, detail=f"Missing {TTS_V2_SESSION_HEADER} header.")
    now_ms = int(time.time() * 1000)
    redis_client = _tts_v2_session_redis_client()
    if redis_client is not None:
        try:
            active = str(redis_client.get(_tts_v2_session_uid_key(safe_uid)) or "").strip()
            if not active or active != provided:
                raise HTTPException(status_code=401, detail="Invalid or expired TTS session key.")
            encoded = redis_client.get(_tts_v2_session_record_key(provided))
            if not encoded:
                raise HTTPException(status_code=401, detail="Invalid or expired TTS session key.")
            row = json.loads(str(encoded) or "{}")
            owner_uid = str((row or {}).get("uid") or "").strip()
            if owner_uid != safe_uid:
                raise HTTPException(status_code=403, detail="TTS session key ownership mismatch.")
            expires_at_ms = int((row or {}).get("expiresAtMs") or 0)
            if expires_at_ms > 0 and expires_at_ms <= now_ms:
                raise HTTPException(status_code=401, detail="TTS session key expired.")
            return dict(row or {})
        except HTTPException:
            raise
        except Exception:
            pass
    with _TTS_V2_SESSION_LOCK:
        _tts_v2_prune_local_sessions_locked(now_ms)
        active = str(_INMEMORY_TTS_V2_ACTIVE_SESSION_BY_UID.get(safe_uid) or "").strip()
        if not active or active != provided:
            raise HTTPException(status_code=401, detail="Invalid or expired TTS session key.")
        row = dict(_INMEMORY_TTS_V2_SESSIONS.get(provided) or {})
        if not row:
            raise HTTPException(status_code=401, detail="Invalid or expired TTS session key.")
        owner_uid = str(row.get("uid") or "").strip()
        if owner_uid != safe_uid:
            raise HTTPException(status_code=403, detail="TTS session key ownership mismatch.")
        expires_at_ms = int(row.get("expiresAtMs") or 0)
        if expires_at_ms > 0 and expires_at_ms <= now_ms:
            _INMEMORY_TTS_V2_SESSIONS.pop(provided, None)
            if _INMEMORY_TTS_V2_ACTIVE_SESSION_BY_UID.get(safe_uid) == provided:
                _INMEMORY_TTS_V2_ACTIVE_SESSION_BY_UID.pop(safe_uid, None)
            raise HTTPException(status_code=401, detail="TTS session key expired.")
        return row


def _require_admin_uid(request: Request) -> str:
    uid = _require_request_uid(request)
    if _request_is_admin(request, uid):
        return uid
    raise HTTPException(status_code=403, detail="Admin access required.")


def _require_admin_unlock_uid(request: Request) -> str:
    uid = _require_request_uid(request)
    unlock_permissions = {
        PERM_USERS_WRITE,
        PERM_COUPONS_WRITE,
        PERM_BILLING_WRITE,
        PERM_OPS_MUTATE,
        PERM_GUARDIAN_MUTATE,
        PERM_ALERTS_WRITE,
        PERM_SCHEDULER_WRITE,
        PERM_RBAC_WRITE,
        PERM_TEAMS_WRITE,
        PERM_SUPPORT_REPLY,
        PERM_SUPPORT_AI_CONFIG,
    }
    try:
        actor = _resolve_actor(uid, request)
        if any(_has_permission(actor, perm) for perm in unlock_permissions):
            request.state.actor = actor
            return uid
    except Exception:
        pass
    if _request_is_admin(request, uid):
        return uid
    raise HTTPException(status_code=403, detail="Admin unlock access required.")


def _constant_time_equal(left: str, right: str) -> bool:
    return hmac.compare_digest(str(left or "").encode("utf-8"), str(right or "").encode("utf-8"))


def _admin_unlock_now_ms() -> int:
    return int(time.time() * 1000)


def _admin_unlock_session_iat(request: Request) -> int:
    claims = getattr(request.state, "auth_claims", None)
    if isinstance(claims, dict):
        for key in ("iat", "auth_time", "issued_at"):
            value = claims.get(key)
            try:
                parsed = int(value)
            except Exception:
                parsed = 0
            if parsed > 0:
                if parsed > 10_000_000_000:
                    return parsed
                return parsed * 1000
    # Dev fallback keeps unlock records session-scoped enough for local testing.
    return 0


def _admin_unlock_record_id(uid: str, session_iat_ms: int) -> str:
    safe_uid = str(uid or "").strip().lower()
    seed = f"{safe_uid}:{int(session_iat_ms)}"
    digest = hashlib.sha256(seed.encode("utf-8")).hexdigest()
    return f"unlock_{digest[:40]}"


def _admin_unlock_collection():
    return _firestore_collection(ADMIN_SESSION_UNLOCK_COLLECTION)


def _admin_unlock_get_record(record_id: str) -> Optional[dict[str, Any]]:
    safe_id = str(record_id or "").strip()
    if not safe_id:
        return None
    collection = _admin_unlock_collection()
    if collection is None:
        with _INMEMORY_LOCK:
            row = _INMEMORY_ADMIN_SESSION_UNLOCK.get(safe_id)
            return dict(row) if isinstance(row, dict) else None
    try:
        doc = collection.document(safe_id).get()
    except Exception:
        return None
    if not bool(getattr(doc, "exists", False)):
        return None
    return {**(doc.to_dict() or {}), "recordId": safe_id}


def _admin_unlock_set_record(record_id: str, payload: dict[str, Any]) -> dict[str, Any]:
    safe_id = str(record_id or "").strip()
    if not safe_id:
        raise HTTPException(status_code=400, detail="Invalid unlock session id.")
    row = dict(payload or {})
    row["recordId"] = safe_id
    collection = _admin_unlock_collection()
    if collection is None:
        with _INMEMORY_LOCK:
            _INMEMORY_ADMIN_SESSION_UNLOCK[safe_id] = dict(row)
        return row
    collection.document(safe_id).set(row, merge=True)
    return row


def _admin_unlock_hash_value(*, salt: str, unlock_key: str) -> str:
    payload = f"{str(salt or '').strip()}:{str(unlock_key or '').strip()}".encode("utf-8")
    return hashlib.sha256(payload).hexdigest()


def _admin_unlock_build_token(uid: str, session_iat_ms: int, expires_at_ms: int) -> str:
    body = {
        "uid": str(uid or "").strip(),
        "sessionIatMs": int(session_iat_ms),
        "expMs": int(expires_at_ms),
        "iatMs": _admin_unlock_now_ms(),
        "nonce": secrets.token_hex(8),
    }
    body_raw = json.dumps(body, ensure_ascii=True, separators=(",", ":"), sort_keys=True).encode("utf-8")
    body_b64 = base64.urlsafe_b64encode(body_raw).decode("ascii").rstrip("=")
    signature_raw = hmac.new(
        VF_ADMIN_UNLOCK_SIGNING_SECRET.encode("utf-8"),
        body_b64.encode("utf-8"),
        hashlib.sha256,
    ).digest()
    signature_b64 = base64.urlsafe_b64encode(signature_raw).decode("ascii").rstrip("=")
    return f"{body_b64}.{signature_b64}"


def _admin_unlock_parse_token(token: str) -> dict[str, Any]:
    safe_token = str(token or "").strip()
    if "." not in safe_token:
        raise HTTPException(status_code=403, detail="Invalid admin unlock token.")
    body_b64, signature_b64 = safe_token.split(".", 1)
    expected_raw = hmac.new(
        VF_ADMIN_UNLOCK_SIGNING_SECRET.encode("utf-8"),
        body_b64.encode("utf-8"),
        hashlib.sha256,
    ).digest()
    expected_b64 = base64.urlsafe_b64encode(expected_raw).decode("ascii").rstrip("=")
    if not _constant_time_equal(signature_b64, expected_b64):
        raise HTTPException(status_code=403, detail="Invalid admin unlock signature.")
    padded = body_b64 + ("=" * ((4 - len(body_b64) % 4) % 4))
    try:
        payload = json.loads(base64.urlsafe_b64decode(padded.encode("ascii")).decode("utf-8"))
    except Exception as exc:  # noqa: BLE001
        raise HTTPException(status_code=403, detail="Malformed admin unlock token.") from exc
    if not isinstance(payload, dict):
        raise HTTPException(status_code=403, detail="Malformed admin unlock token.")
    return payload


def _admin_unlock_extract_bearer(request: Request) -> str:
    header_value = str(request.headers.get("x-admin-unlock") or "").strip()
    if not header_value:
        raise HTTPException(status_code=403, detail="Missing X-Admin-Unlock header.")
    if not header_value.lower().startswith("bearer "):
        raise HTTPException(status_code=403, detail="X-Admin-Unlock must be a bearer token.")
    token = header_value.split(" ", 1)[1].strip()
    if not token:
        raise HTTPException(status_code=403, detail="Missing admin unlock bearer token.")
    return token


def _admin_unlock_issue_for_request(request: Request, uid: str) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    session_iat_ms = _admin_unlock_session_iat(request)
    now_ms = _admin_unlock_now_ms()
    key_expires_at_ms = now_ms + (VF_ADMIN_UNLOCK_KEY_TTL_SECONDS * 1000)
    unlock_key = "".join(
        secrets.choice("ABCDEFGHJKLMNPQRSTUVWXYZ23456789")
        for _ in range(10)
    )
    key_salt = secrets.token_hex(16)
    record_id = _admin_unlock_record_id(safe_uid, session_iat_ms)
    payload = {
        "uid": safe_uid,
        "sessionIatMs": int(session_iat_ms),
        "keySalt": key_salt,
        "keyHash": _admin_unlock_hash_value(salt=key_salt, unlock_key=unlock_key),
        "keyIssuedAtMs": now_ms,
        "keyExpiresAtMs": key_expires_at_ms,
        "unlockExpiresAtMs": 0,
        "failedAttempts": 0,
        "lockedUntilMs": 0,
        "lastVerifiedAtMs": 0,
        "updatedAtMs": now_ms,
    }
    _admin_unlock_set_record(record_id, payload)
    return {
        "recordId": record_id,
        "unlockKey": unlock_key,
        "keyExpiresAtMs": key_expires_at_ms,
        "keyExpiresAt": datetime.fromtimestamp(key_expires_at_ms / 1000, tz=timezone.utc).isoformat(),
    }


def _admin_unlock_status_for_request(request: Request, uid: str) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    session_iat_ms = _admin_unlock_session_iat(request)
    now_ms = _admin_unlock_now_ms()
    record_id = _admin_unlock_record_id(safe_uid, session_iat_ms)
    row = _admin_unlock_get_record(record_id) or {}
    locked_until_ms = int(row.get("lockedUntilMs") or 0)
    unlock_expires_at_ms = int(row.get("unlockExpiresAtMs") or 0)
    key_expires_at_ms = int(row.get("keyExpiresAtMs") or 0)
    failed_attempts = max(0, int(row.get("failedAttempts") or 0))
    return {
        "recordId": record_id,
        "hasIssuedKey": bool(key_expires_at_ms > 0),
        "isLocked": locked_until_ms > now_ms,
        "lockedUntilMs": locked_until_ms,
        "lockedUntil": datetime.fromtimestamp(locked_until_ms / 1000, tz=timezone.utc).isoformat() if locked_until_ms > 0 else "",
        "isUnlocked": unlock_expires_at_ms > now_ms,
        "unlockExpiresAtMs": unlock_expires_at_ms,
        "unlockExpiresAt": datetime.fromtimestamp(unlock_expires_at_ms / 1000, tz=timezone.utc).isoformat() if unlock_expires_at_ms > 0 else "",
        "keyExpiresAtMs": key_expires_at_ms,
        "keyExpiresAt": datetime.fromtimestamp(key_expires_at_ms / 1000, tz=timezone.utc).isoformat() if key_expires_at_ms > 0 else "",
        "failedAttempts": failed_attempts,
        "attemptsRemaining": max(0, VF_ADMIN_UNLOCK_MAX_ATTEMPTS - failed_attempts),
    }


def _admin_unlock_verify_for_request(
    request: Request,
    *,
    uid: str,
    unlock_key: str,
) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    safe_unlock_key = str(unlock_key or "").strip().upper()
    if not safe_unlock_key:
        raise HTTPException(status_code=400, detail="unlockKey is required.")
    session_iat_ms = _admin_unlock_session_iat(request)
    now_ms = _admin_unlock_now_ms()
    record_id = _admin_unlock_record_id(safe_uid, session_iat_ms)
    row = _admin_unlock_get_record(record_id)
    if not isinstance(row, dict):
        raise HTTPException(status_code=404, detail="No unlock key issued for this session.")
    if str(row.get("uid") or "").strip() != safe_uid:
        raise HTTPException(status_code=403, detail="Unlock session UID mismatch.")
    if int(row.get("sessionIatMs") or 0) != int(session_iat_ms):
        raise HTTPException(status_code=403, detail="Unlock session mismatch.")
    locked_until_ms = int(row.get("lockedUntilMs") or 0)
    if locked_until_ms > now_ms:
        raise HTTPException(status_code=429, detail="Unlock session is temporarily locked.")
    key_expires_at_ms = int(row.get("keyExpiresAtMs") or 0)
    if key_expires_at_ms <= now_ms:
        raise HTTPException(status_code=400, detail="Unlock key has expired. Issue a new key.")

    key_salt = str(row.get("keySalt") or "").strip()
    expected_hash = str(row.get("keyHash") or "").strip()
    provided_hash = _admin_unlock_hash_value(salt=key_salt, unlock_key=safe_unlock_key)
    is_valid = bool(expected_hash) and _constant_time_equal(provided_hash, expected_hash)
    failed_attempts = max(0, int(row.get("failedAttempts") or 0))
    if not is_valid:
        failed_attempts += 1
        next_locked_until = 0
        if failed_attempts >= VF_ADMIN_UNLOCK_MAX_ATTEMPTS:
            next_locked_until = now_ms + (VF_ADMIN_UNLOCK_LOCKOUT_SECONDS * 1000)
            failed_attempts = 0
        row["failedAttempts"] = failed_attempts
        row["lockedUntilMs"] = next_locked_until
        row["updatedAtMs"] = now_ms
        _admin_unlock_set_record(record_id, row)
        raise HTTPException(status_code=403, detail="Invalid unlock key.")

    unlock_expires_at_ms = now_ms + (VF_ADMIN_UNLOCK_TTL_SECONDS * 1000)
    row["failedAttempts"] = 0
    row["lockedUntilMs"] = 0
    row["lastVerifiedAtMs"] = now_ms
    row["unlockExpiresAtMs"] = unlock_expires_at_ms
    row["updatedAtMs"] = now_ms
    _admin_unlock_set_record(record_id, row)
    unlock_token = _admin_unlock_build_token(
        uid=safe_uid,
        session_iat_ms=session_iat_ms,
        expires_at_ms=unlock_expires_at_ms,
    )
    return {
        "unlockToken": unlock_token,
        "expiresAtMs": unlock_expires_at_ms,
        "expiresAt": datetime.fromtimestamp(unlock_expires_at_ms / 1000, tz=timezone.utc).isoformat(),
    }


def _require_admin_mutation_unlock(request: Request, *, expected_uid: Optional[str] = None) -> str:
    safe_uid = str(expected_uid or "").strip() or _require_request_uid(request)
    if not VF_AUTH_ENFORCE and not VF_IS_PRODUCTION:
        return safe_uid
    token = _admin_unlock_extract_bearer(request)
    payload = _admin_unlock_parse_token(token)
    token_uid = str(payload.get("uid") or "").strip()
    token_session_iat_ms = int(payload.get("sessionIatMs") or 0)
    token_exp_ms = int(payload.get("expMs") or 0)
    now_ms = _admin_unlock_now_ms()
    if token_exp_ms <= now_ms:
        raise HTTPException(status_code=403, detail="Admin unlock token expired.")
    if token_uid != safe_uid:
        raise HTTPException(status_code=403, detail="Admin unlock token UID mismatch.")
    session_iat_ms = _admin_unlock_session_iat(request)
    if int(token_session_iat_ms) != int(session_iat_ms):
        raise HTTPException(status_code=403, detail="Admin unlock token session mismatch.")
    record_id = _admin_unlock_record_id(safe_uid, session_iat_ms)
    row = _admin_unlock_get_record(record_id)
    if not isinstance(row, dict):
        raise HTTPException(status_code=403, detail="Admin unlock session not found.")
    unlock_expires_at_ms = int(row.get("unlockExpiresAtMs") or 0)
    if unlock_expires_at_ms <= now_ms:
        raise HTTPException(status_code=403, detail="Admin unlock session expired.")
    return safe_uid


def _rbac_default_permissions_for_role(role: str) -> set[str]:
    safe_role = str(role or "").strip().lower()
    return set(RBAC_ROLE_PERMISSION_MAP.get(safe_role) or set())


def _rbac_normalize_role(role: str) -> str:
    safe_role = str(role or "").strip().lower()
    if safe_role in RBAC_ROLES:
        return safe_role
    return RBAC_ROLE_READ_ONLY_OPS


def _rbac_normalize_status(status: str) -> str:
    safe = str(status or "").strip().lower()
    if safe in {"active", "disabled"}:
        return safe
    return "active"


def _rbac_normalize_overrides(values: Any) -> list[str]:
    if not isinstance(values, list):
        return []
    normalized: list[str] = []
    for token in values:
        item = str(token or "").strip().lower()
        if item in RBAC_PERMISSIONS and item not in normalized:
            normalized.append(item)
    return normalized


def _rbac_cache_get(uid: str) -> Optional[dict[str, Any]]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return None
    now = _ai_ops_now_ms()
    with _RBAC_CACHE_LOCK:
        item = _RBAC_ACTOR_CACHE.get(safe_uid)
        if not isinstance(item, dict):
            return None
        expires_at = int(item.get("expiresAtMs") or 0)
        if expires_at <= now:
            _RBAC_ACTOR_CACHE.pop(safe_uid, None)
            return None
        return dict(item)


def _rbac_cache_put(uid: str, actor: dict[str, Any]) -> None:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return
    payload = dict(actor or {})
    payload["expiresAtMs"] = _ai_ops_now_ms() + 60_000
    with _RBAC_CACHE_LOCK:
        _RBAC_ACTOR_CACHE[safe_uid] = payload


def _rbac_invalidate_cache(uid: str) -> None:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return
    with _RBAC_CACHE_LOCK:
        _RBAC_ACTOR_CACHE.pop(safe_uid, None)


def _rbac_load_assignment(uid: str) -> Optional[dict[str, Any]]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return None
    collection = _firestore_collection(ADMIN_ROLES_COLLECTION)
    if collection is None:
        with _INMEMORY_LOCK:
            row = _INMEMORY_ADMIN_ROLES.get(safe_uid)
            return dict(row) if isinstance(row, dict) else None
    try:
        doc = collection.document(safe_uid).get()
    except Exception:
        return None
    if not doc.exists:
        return None
    payload = doc.to_dict() or {}
    payload["uid"] = safe_uid
    return payload


def _rbac_write_assignment(uid: str, payload: dict[str, Any]) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        raise HTTPException(status_code=400, detail="Missing target uid.")
    current = _rbac_load_assignment(safe_uid) or {}
    now_iso = _utc_now().isoformat()
    version = int(current.get("version") or 0) + 1
    row = {
        "uid": safe_uid,
        "role": _rbac_normalize_role(str(payload.get("role") or current.get("role") or RBAC_ROLE_READ_ONLY_OPS)),
        "allowOverrides": _rbac_normalize_overrides(
            payload.get("allowOverrides") if payload.get("allowOverrides") is not None else current.get("allowOverrides")
        ),
        "denyOverrides": _rbac_normalize_overrides(
            payload.get("denyOverrides") if payload.get("denyOverrides") is not None else current.get("denyOverrides")
        ),
        "status": _rbac_normalize_status(str(payload.get("status") or current.get("status") or "active")),
        "version": version,
        "updatedAt": now_iso,
        "updatedBy": str(payload.get("updatedBy") or current.get("updatedBy") or "").strip(),
    }
    collection = _firestore_collection(ADMIN_ROLES_COLLECTION)
    if collection is None:
        with _INMEMORY_LOCK:
            _INMEMORY_ADMIN_ROLES[safe_uid] = dict(row)
    else:
        try:
            collection.document(safe_uid).set(row, merge=True)
        except Exception as exc:
            raise HTTPException(status_code=503, detail=f"Failed to write RBAC assignment: {exc}") from exc
    _rbac_invalidate_cache(safe_uid)
    return row


def _rbac_bootstrap_actor(uid: str, request: Request) -> Optional[dict[str, Any]]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return None
    if _request_is_admin(request, safe_uid):
        role = RBAC_ROLE_SUPER_ADMIN
    else:
        return None
    return {
        "uid": safe_uid,
        "role": role,
        "permissions": sorted(_rbac_default_permissions_for_role(role)),
        "status": "active",
        "version": 0,
        "source": "legacy_bootstrap",
    }


def _resolve_actor(uid: str, request: Request) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        raise HTTPException(status_code=401, detail="Authentication required.")
    def _with_identity(actor_payload: dict[str, Any]) -> dict[str, Any]:
        payload = dict(actor_payload or {})
        # Permission checks must stay read-only; profile auto-backfill belongs to explicit profile flows.
        payload["userId"] = _resolve_request_user_id_read_only(safe_uid)
        return payload
    if not VF_RBAC_ENABLED:
        if _request_is_admin(request, safe_uid):
            return _with_identity({
                "uid": safe_uid,
                "role": RBAC_ROLE_SUPER_ADMIN,
                "permissions": sorted(RBAC_PERMISSIONS),
                "status": "active",
                "version": 0,
                "source": "rbac_disabled_admin",
            })
        return _with_identity({
            "uid": safe_uid,
            "role": RBAC_ROLE_READ_ONLY_OPS,
            "permissions": [],
            "status": "disabled",
            "version": 0,
            "source": "rbac_disabled_non_admin",
        })
    cached = _rbac_cache_get(safe_uid)
    if isinstance(cached, dict):
        return _with_identity({key: value for key, value in cached.items() if key != "expiresAtMs"})
    assignment = _rbac_load_assignment(safe_uid)
    if isinstance(assignment, dict):
        role = _rbac_normalize_role(str(assignment.get("role") or ""))
        deny = _rbac_normalize_overrides(assignment.get("denyOverrides"))
        allow = _rbac_normalize_overrides(assignment.get("allowOverrides"))
        permissions = _rbac_default_permissions_for_role(role)
        permissions.update(allow)
        permissions.difference_update(set(deny))
        actor = {
            "uid": safe_uid,
            "role": role,
            "permissions": sorted(permissions),
            "status": _rbac_normalize_status(str(assignment.get("status") or "active")),
            "version": int(assignment.get("version") or 0),
            "source": "admin_roles",
            "allowOverrides": allow,
            "denyOverrides": deny,
        }
        _rbac_cache_put(safe_uid, actor)
        return _with_identity(actor)
    bootstrap = _rbac_bootstrap_actor(safe_uid, request)
    if bootstrap is not None:
        _rbac_cache_put(safe_uid, bootstrap)
        return _with_identity(bootstrap)
    actor = {
        "uid": safe_uid,
        "role": RBAC_ROLE_READ_ONLY_OPS,
        "permissions": [],
        "status": "disabled",
        "version": 0,
        "source": "unassigned",
    }
    _rbac_cache_put(safe_uid, actor)
    return _with_identity(actor)


def _has_permission(actor: dict[str, Any], permission: str) -> bool:
    safe_permission = str(permission or "").strip().lower()
    if safe_permission not in RBAC_PERMISSIONS:
        return False
    if str(actor.get("status") or "active").strip().lower() == "disabled":
        return False
    role = _rbac_normalize_role(str(actor.get("role") or ""))
    if role == RBAC_ROLE_SUPER_ADMIN:
        return True
    deny = set(_rbac_normalize_overrides(actor.get("denyOverrides")))
    if safe_permission in deny:
        return False
    allow = set(_rbac_normalize_overrides(actor.get("allowOverrides")))
    permissions = set(actor.get("permissions") or [])
    if safe_permission in allow:
        return True
    return safe_permission in permissions


def _require_permission(request: Request, permission: str) -> tuple[str, dict[str, Any]]:
    uid = _require_request_uid(request)
    actor = _resolve_actor(uid, request)
    if _has_permission(actor, permission):
        request.state.actor = actor
        return uid, actor
    if not VF_RBAC_ENFORCE and _request_is_admin(request, uid):
        fallback_actor = {
            "uid": uid,
            "role": RBAC_ROLE_SUPER_ADMIN,
            "permissions": sorted(RBAC_PERMISSIONS),
            "status": "active",
            "version": int(actor.get("version") or 0),
            "source": "legacy_admin_fallback",
        }
        request.state.actor = fallback_actor
        return uid, fallback_actor
    raise HTTPException(status_code=403, detail=f"Missing permission: {permission}")


def _rbac_roles_payload() -> dict[str, Any]:
    return {
        "ok": True,
        "roles": sorted(RBAC_ROLES),
        "permissions": sorted(RBAC_PERMISSIONS),
        "matrix": {
            role: sorted(_rbac_default_permissions_for_role(role))
            for role in sorted(RBAC_ROLES)
        },
    }


def _rbac_list_assignments(limit: int = 100, cursor: str = "", q: str = "") -> tuple[list[dict[str, Any]], Optional[str]]:
    safe_limit = max(1, min(200, int(limit)))
    safe_cursor = str(cursor or "").strip()
    needle = str(q or "").strip().lower()
    rows: list[dict[str, Any]] = []
    next_cursor: Optional[str] = None
    collection = _firestore_collection(ADMIN_ROLES_COLLECTION)
    if collection is None:
        with _INMEMORY_LOCK:
            keys = sorted(_INMEMORY_ADMIN_ROLES.keys())
            if safe_cursor:
                keys = [key for key in keys if key > safe_cursor]
            for uid in keys:
                row = _INMEMORY_ADMIN_ROLES.get(uid)
                if not isinstance(row, dict):
                    continue
                user_id = _user_id_for_uid(uid).lower()
                if needle and needle not in uid.lower() and needle not in str(row.get("role") or "").lower() and needle not in user_id:
                    continue
                item = dict(row)
                item["userId"] = user_id
                rows.append(item)
                if len(rows) >= safe_limit:
                    break
            if len(rows) == safe_limit:
                next_cursor = str(rows[-1].get("uid") or "")
        return rows, next_cursor
    try:
        docs = list(collection.limit(max(20, safe_limit * 3)).stream())
    except Exception:
        docs = []
    docs.sort(key=lambda doc: str(doc.id or ""))
    for doc in docs:
        uid = str(doc.id or "").strip()
        if not uid:
            continue
        if safe_cursor and uid <= safe_cursor:
            continue
        row = doc.to_dict() or {}
        row["uid"] = uid
        role_token = str(row.get("role") or "").lower()
        user_id = _user_id_for_uid(uid).lower()
        if needle and needle not in uid.lower() and needle not in role_token and needle not in user_id:
            continue
        row["userId"] = user_id
        rows.append(row)
        if len(rows) >= safe_limit:
            break
    if len(rows) == safe_limit:
        next_cursor = str(rows[-1].get("uid") or "")
    return rows, next_cursor


def _firestore_collection(name: str) -> Any:
    if _FIRESTORE_DB is None and _FIREBASE_APP is None:
        _init_firebase_clients()
    if _FIRESTORE_DB is None and _FIREBASE_APP is not None and VF_FIRESTORE_ENABLE:
        global _FIRESTORE_RETRY_LAST_ATTEMPT_MS
        now_ms = int(time.time() * 1000)
        should_retry = (now_ms - int(_FIRESTORE_RETRY_LAST_ATTEMPT_MS or 0)) >= int(_FIRESTORE_RETRY_COOLDOWN_MS)
        if should_retry:
            _FIRESTORE_RETRY_LAST_ATTEMPT_MS = now_ms
            try:
                _init_firebase_clients(force=True)
            except Exception:
                pass
    if _FIRESTORE_DB is None:
        return None
    return _FIRESTORE_DB.collection(name)


def _notification_email_feature_enabled() -> bool:
    return bool(
        VF_NOTIFICATIONS_EMAIL_ENABLED
        and RESEND_API_KEY
        and VF_NOTIFICATIONS_EMAIL_FROM
    )


def _notification_items_collection(uid: str) -> Any:
    if _FIRESTORE_DB is None:
        return None
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return None
    return (
        _FIRESTORE_DB
        .collection(NOTIFICATION_INBOX_COLLECTION)
        .document(safe_uid)
        .collection(NOTIFICATION_INBOX_ITEMS_SUBCOLLECTION)
    )


def _notification_preferences_default(uid: str, *, is_admin: bool = False) -> dict[str, Any]:
    return {
        "uid": str(uid or "").strip(),
        "emailAsyncJobs": True,
        "emailBilling": True,
        "emailSupport": True,
        "emailAdminAlerts": bool(is_admin),
        "updatedAt": _utc_now().isoformat(),
    }


def _notification_preferences_get(uid: str, *, is_admin: bool = False) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    defaults = _notification_preferences_default(safe_uid, is_admin=is_admin)
    if not safe_uid:
        return defaults
    collection = _firestore_collection(NOTIFICATION_PREFERENCES_COLLECTION)
    if collection is None:
        with _INMEMORY_LOCK:
            row = dict(_INMEMORY_NOTIFICATION_PREFERENCES.get(safe_uid) or {})
        merged = dict(defaults)
        merged.update(row)
        return merged
    try:
        doc = collection.document(safe_uid).get()
    except Exception:
        doc = None
    if doc is None or not getattr(doc, "exists", False):
        return defaults
    merged = dict(defaults)
    merged.update(doc.to_dict() or {})
    return merged


def _notification_preferences_patch(uid: str, patch: dict[str, Any], *, is_admin: bool = False) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        raise HTTPException(status_code=400, detail="Missing uid.")
    current = _notification_preferences_get(safe_uid, is_admin=is_admin)
    next_payload = dict(current)
    for field in ("emailAsyncJobs", "emailBilling", "emailSupport", "emailAdminAlerts"):
        if field in patch and patch.get(field) is not None:
            next_payload[field] = bool(patch.get(field))
    next_payload["uid"] = safe_uid
    next_payload["updatedAt"] = _utc_now().isoformat()
    collection = _firestore_collection(NOTIFICATION_PREFERENCES_COLLECTION)
    if collection is None:
        with _INMEMORY_LOCK:
            _INMEMORY_NOTIFICATION_PREFERENCES[safe_uid] = dict(next_payload)
        return next_payload
    collection.document(safe_uid).set(next_payload, merge=True)
    return next_payload


def _notification_action_target(target: Any) -> Optional[dict[str, Any]]:
    if not isinstance(target, dict):
        return None
    payload: dict[str, Any] = {}
    for key in ("screen", "tab", "adminTab", "conversationId", "jobId", "href"):
        value = str(target.get(key) or "").strip()
        if value:
            payload[key] = value[:240]
    return payload or None


def _notification_email_for_uid(uid: str) -> str:
    profile = _user_profile_read(uid) or {}
    email = str(profile.get("email") or "").strip().lower()
    if email:
        return email
    if firebase_auth is None or not _firebase_ready():
        return ""
    try:
        record = firebase_auth.get_user(str(uid or "").strip())  # type: ignore[attr-defined]
    except Exception:
        return ""
    return str(getattr(record, "email", "") or "").strip().lower()


def _notification_normalize_item(uid: str, row: dict[str, Any]) -> dict[str, Any]:
    now_iso = _utc_now().isoformat()
    created_at = row.get("createdAt") if isinstance(row.get("createdAt"), str) else now_iso
    updated_at = row.get("updatedAt") if isinstance(row.get("updatedAt"), str) else created_at
    severity = str(row.get("severity") or "info").strip().lower()
    if severity not in {"success", "info", "warning", "error", "critical"}:
        severity = "info"
    category = str(row.get("category") or "activity").strip().lower()
    if category not in {"system", "activity", "security", "tips"}:
        category = "activity"
    audience = str(row.get("audience") or "user").strip().lower()
    if audience not in {"user", "admin", "all"}:
        audience = "user"
    status = str(row.get("status") or "active").strip().lower()
    if status not in {"active", "resolved"}:
        status = "active"
    normalized = {
        "id": str(row.get("id") or "").strip() or f"notif_{uuid.uuid4().hex[:12]}",
        "uid": str(uid or "").strip(),
        "eventCode": str(row.get("eventCode") or "custom.message").strip() or "custom.message",
        "entityKey": str(row.get("entityKey") or "").strip(),
        "title": str(row.get("title") or "Notification").strip()[:160] or "Notification",
        "message": str(row.get("message") or "Notification").strip()[:1200] or "Notification",
        "details": str(row.get("details") or "").strip()[:6000],
        "severity": severity,
        "category": category,
        "audience": audience,
        "channel": "inbox",
        "scope": "persisted",
        "status": status,
        "resolvedAt": str(row.get("resolvedAt") or "").strip() or None,
        "resolvedBy": str(row.get("resolvedBy") or "").strip() or None,
        "createdAt": created_at,
        "updatedAt": updated_at,
        "readAt": str(row.get("readAt") or "").strip() or None,
        "dismissedAt": str(row.get("dismissedAt") or "").strip() or None,
        "sticky": bool(row.get("sticky")),
        "dedupeKey": str(row.get("dedupeKey") or "").strip() or None,
        "requiredPermission": str(row.get("requiredPermission") or "").strip() or None,
        "emailEligible": bool(row.get("emailEligible")),
        "action": None,
        "metadata": row.get("metadata") if isinstance(row.get("metadata"), dict) else {},
    }
    action_payload: dict[str, Any] = {}
    action = row.get("action") if isinstance(row.get("action"), dict) else {}
    label = str(action.get("label") or row.get("actionLabel") or "").strip()
    if label:
        action_payload["label"] = label[:80]
    target = _notification_action_target(action.get("target") if isinstance(action, dict) else row.get("actionTarget"))
    if target is not None:
        action_payload["target"] = target
    if action_payload:
        normalized["action"] = action_payload
    if not normalized["entityKey"]:
        normalized["entityKey"] = None
    if not normalized["details"]:
        normalized["details"] = None
    return normalized


def _notification_get_item(uid: str, notification_id: str) -> Optional[dict[str, Any]]:
    safe_uid = str(uid or "").strip()
    safe_id = str(notification_id or "").strip()
    if not safe_uid or not safe_id:
        return None
    collection = _notification_items_collection(safe_uid)
    if collection is None:
        with _INMEMORY_LOCK:
            row = ((_INMEMORY_NOTIFICATION_INBOX.get(safe_uid) or {}).get(safe_id))
            return dict(row) if isinstance(row, dict) else None
    try:
        doc = collection.document(safe_id).get()
    except Exception:
        return None
    if not doc.exists:
        return None
    payload = doc.to_dict() or {}
    payload["id"] = safe_id
    payload["uid"] = safe_uid
    return _notification_normalize_item(safe_uid, payload)


def _notification_find_by_dedupe_key(uid: str, dedupe_key: str) -> Optional[dict[str, Any]]:
    safe_uid = str(uid or "").strip()
    safe_key = str(dedupe_key or "").strip()
    if not safe_uid or not safe_key:
        return None
    collection = _notification_items_collection(safe_uid)
    if collection is None:
        with _INMEMORY_LOCK:
            rows = list((_INMEMORY_NOTIFICATION_INBOX.get(safe_uid) or {}).values())
        for row in rows:
            if not isinstance(row, dict):
                continue
            if str(row.get("dedupeKey") or "").strip() != safe_key:
                continue
            return _notification_normalize_item(safe_uid, row)
        return None
    try:
        docs = list(collection.where("dedupeKey", "==", safe_key).limit(1).stream())
    except Exception:
        return None
    if not docs:
        return None
    row = docs[0].to_dict() or {}
    row["id"] = str(docs[0].id or "")
    row["uid"] = safe_uid
    return _notification_normalize_item(safe_uid, row)


def _notification_upsert_item(
    uid: str,
    row: dict[str, Any],
    *,
    resurface_unread: bool = True,
) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        raise HTTPException(status_code=400, detail="Missing notification recipient.")
    now_iso = _utc_now().isoformat()
    safe_row = _notification_normalize_item(safe_uid, row)
    existing = None
    dedupe_key = str(safe_row.get("dedupeKey") or "").strip()
    if dedupe_key:
        existing = _notification_find_by_dedupe_key(safe_uid, dedupe_key)
    elif str(safe_row.get("id") or "").strip():
        existing = _notification_get_item(safe_uid, str(safe_row.get("id") or ""))
    payload = dict(existing or {})
    payload.update(safe_row)
    payload["uid"] = safe_uid
    payload["id"] = str((existing or {}).get("id") or safe_row.get("id") or f"notif_{uuid.uuid4().hex[:12]}").strip()
    payload["createdAt"] = str((existing or {}).get("createdAt") or safe_row.get("createdAt") or now_iso)
    payload["updatedAt"] = now_iso
    if resurface_unread:
        payload["readAt"] = None
        payload["dismissedAt"] = None
    else:
        payload["readAt"] = str(payload.get("readAt") or "").strip() or None
        payload["dismissedAt"] = str(payload.get("dismissedAt") or "").strip() or None
    collection = _notification_items_collection(safe_uid)
    if collection is None:
        with _INMEMORY_LOCK:
            bucket = _INMEMORY_NOTIFICATION_INBOX.setdefault(safe_uid, {})
            bucket[payload["id"]] = dict(payload)
        return _notification_normalize_item(safe_uid, payload)
    collection.document(payload["id"]).set(payload, merge=True)
    return _notification_normalize_item(safe_uid, payload)


def _notification_patch_item(uid: str, notification_id: str, patch: dict[str, Any]) -> Optional[dict[str, Any]]:
    current = _notification_get_item(uid, notification_id)
    if not isinstance(current, dict):
        return None
    next_payload = dict(current)
    next_payload.update({key: value for key, value in dict(patch or {}).items() if value is not None})
    next_payload["updatedAt"] = _utc_now().isoformat()
    return _notification_upsert_item(uid, next_payload, resurface_unread=False)


def _notification_list_items(
    uid: str,
    *,
    limit: int = 200,
    actor: Optional[dict[str, Any]] = None,
    include_dismissed: bool = False,
) -> list[dict[str, Any]]:
    safe_uid = str(uid or "").strip()
    safe_limit = max(1, min(500, int(limit)))
    collection = _notification_items_collection(safe_uid)
    rows: list[dict[str, Any]] = []
    if collection is None:
        with _INMEMORY_LOCK:
            rows = [
                _notification_normalize_item(safe_uid, dict(item))
                for item in (_INMEMORY_NOTIFICATION_INBOX.get(safe_uid) or {}).values()
                if isinstance(item, dict)
            ]
    else:
        try:
            docs = list(collection.limit(max(50, safe_limit * 2)).stream())
        except Exception:
            docs = []
        for doc in docs:
            row = doc.to_dict() or {}
            row["id"] = str(doc.id or "")
            rows.append(_notification_normalize_item(safe_uid, row))
    filtered: list[dict[str, Any]] = []
    for row in rows:
        if not include_dismissed and row.get("dismissedAt"):
            continue
        audience = str(row.get("audience") or "user").strip().lower()
        required_permission = str(row.get("requiredPermission") or "").strip()
        if audience == "admin":
            if not isinstance(actor, dict):
                continue
            if str(actor.get("status") or "active").strip().lower() == "disabled":
                continue
            if required_permission and not _has_permission(actor, required_permission):
                continue
        filtered.append(row)
    filtered.sort(
        key=lambda item: (
            str(item.get("createdAt") or ""),
            str(item.get("id") or ""),
        ),
        reverse=True,
    )
    return filtered[:safe_limit]


def _notification_mark_all(
    uid: str,
    *,
    patch: dict[str, Any],
    actor: Optional[dict[str, Any]] = None,
) -> int:
    count = 0
    for item in _notification_list_items(uid, limit=500, actor=actor, include_dismissed=True):
        if item.get("dismissedAt"):
            continue
        updated = _notification_patch_item(uid, str(item.get("id") or ""), patch)
        if updated is not None:
            count += 1
    return count


def _notification_email_outbox_upsert(delivery_id: str, row: dict[str, Any]) -> dict[str, Any]:
    safe_id = str(delivery_id or "").strip() or f"ndlv_{uuid.uuid4().hex[:12]}"
    payload = dict(row or {})
    payload["id"] = safe_id
    collection = _firestore_collection(NOTIFICATION_EMAIL_OUTBOX_COLLECTION)
    if collection is None:
        with _INMEMORY_LOCK:
            _INMEMORY_NOTIFICATION_EMAIL_OUTBOX[safe_id] = dict(payload)
        return dict(payload)
    collection.document(safe_id).set(payload, merge=True)
    return dict(payload)


def _notification_email_subject(item: dict[str, Any]) -> str:
    title = str(item.get("title") or "Notification").strip()
    message = str(item.get("message") or "").strip()
    if not title:
        title = "Notification"
    if not message:
        return f"VoiceFlow: {title}"
    compact_message = message if len(message) <= 90 else f"{message[:87].rstrip()}..."
    return f"VoiceFlow: {title} - {compact_message}"


def _notification_email_text(item: dict[str, Any], *, recipient_role: str = "") -> str:
    lines = [
        str(item.get("title") or "Notification").strip() or "Notification",
        "",
        str(item.get("message") or "").strip() or "You have a new notification.",
    ]
    details = str(item.get("details") or "").strip()
    if details:
        lines.extend(["", details])
    action = item.get("action") if isinstance(item.get("action"), dict) else {}
    label = str(action.get("label") or "").strip()
    target = action.get("target") if isinstance(action.get("target"), dict) else {}
    if label and isinstance(target, dict):
        summary_parts = [
            str(target.get("screen") or "").strip(),
            str(target.get("tab") or "").strip(),
            str(target.get("adminTab") or "").strip(),
        ]
        summary = " / ".join([part for part in summary_parts if part])
        if summary:
            lines.extend(["", f"Action: {label} ({summary})"])
        elif str(target.get("href") or "").strip():
            lines.extend(["", f"Action: {label} ({str(target.get('href') or '').strip()})"])
    if str(recipient_role or "").strip().lower() == RBAC_ROLE_READ_ONLY_OPS:
        lines.extend(["", "This alert is informational for your read-only operator role."])
    return "\n".join(lines).strip()


def _notification_send_email_via_resend(
    *,
    to_email: str,
    subject: str,
    text_body: str,
) -> tuple[bool, str]:
    if not _notification_email_feature_enabled():
        return False, "email_disabled"
    headers = {
        "Authorization": f"Bearer {RESEND_API_KEY}",
        "Content-Type": "application/json",
    }
    payload: dict[str, Any] = {
        "from": VF_NOTIFICATIONS_EMAIL_FROM,
        "to": [str(to_email or "").strip()],
        "subject": str(subject or "VoiceFlow notification").strip() or "VoiceFlow notification",
        "text": str(text_body or "").strip() or "VoiceFlow notification",
    }
    if VF_NOTIFICATIONS_EMAIL_REPLY_TO:
        payload["reply_to"] = VF_NOTIFICATIONS_EMAIL_REPLY_TO
    try:
        response = requests.post(
            "https://api.resend.com/emails",
            headers=headers,
            json=payload,
            timeout=15,
        )
    except Exception as exc:
        return False, str(exc)
    if response.ok:
        try:
            body = response.json()
        except Exception:
            body = {}
        return True, str(body.get("id") or "")
    return False, response.text[:400] or f"http_{response.status_code}"


def _notification_attempt_email_delivery(delivery_id: str) -> dict[str, Any]:
    collection = _firestore_collection(NOTIFICATION_EMAIL_OUTBOX_COLLECTION)
    delivery = None
    if collection is None:
        with _INMEMORY_LOCK:
            raw = _INMEMORY_NOTIFICATION_EMAIL_OUTBOX.get(str(delivery_id or "").strip())
            delivery = dict(raw) if isinstance(raw, dict) else None
    else:
        try:
            doc = collection.document(str(delivery_id or "").strip()).get()
        except Exception:
            doc = None
        if doc is not None and getattr(doc, "exists", False):
            delivery = doc.to_dict() or {}
            delivery["id"] = str(doc.id or "")
    if not isinstance(delivery, dict):
        return {"ok": False, "status": "missing"}

    to_email = str(delivery.get("to") or "").strip().lower()
    subject = str(delivery.get("subject") or "").strip()
    text_body = str(delivery.get("text") or "").strip()
    attempts = max(0, int(delivery.get("attempts") or 0)) + 1
    delivered, detail = _notification_send_email_via_resend(
        to_email=to_email,
        subject=subject,
        text_body=text_body,
    )
    now_iso = _utc_now().isoformat()
    patch: dict[str, Any] = {
        "attempts": attempts,
        "lastAttemptAt": now_iso,
        "updatedAt": now_iso,
    }
    if delivered:
        patch.update(
            {
                "status": "delivered",
                "providerMessageId": detail or None,
                "deliveredAt": now_iso,
                "lastError": None,
                "nextAttemptAtMs": None,
            }
        )
    else:
        patch.update(
            {
                "status": "retry_pending" if attempts < 3 else "failed",
                "lastError": detail or "delivery_failed",
                "nextAttemptAtMs": int(time.time() * 1000) + (30_000 * attempts) if attempts < 3 else None,
            }
        )
    merged = dict(delivery)
    merged.update(patch)
    return _notification_email_outbox_upsert(str(delivery.get("id") or delivery_id or ""), merged)


def _notification_queue_email_delivery(
    *,
    uid: str,
    item: dict[str, Any],
    recipient_role: str = "",
) -> Optional[dict[str, Any]]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        return None
    to_email = _notification_email_for_uid(safe_uid)
    if not to_email:
        return None
    now_iso = _utc_now().isoformat()
    delivery = _notification_email_outbox_upsert(
        "",
        {
            "uid": safe_uid,
            "notificationId": str(item.get("id") or "").strip(),
            "eventCode": str(item.get("eventCode") or "").strip(),
            "to": to_email,
            "subject": _notification_email_subject(item),
            "text": _notification_email_text(item, recipient_role=recipient_role),
            "status": "pending",
            "attempts": 0,
            "createdAt": now_iso,
            "updatedAt": now_iso,
        },
    )
    delivery_id = str(delivery.get("id") or "").strip()
    if not delivery_id:
        return delivery
    worker = threading.Thread(
        target=_notification_attempt_email_delivery,
        args=(delivery_id,),
        daemon=True,
        name=f"notif-email-{delivery_id[:8]}",
    )
    worker.start()
    return delivery


def _notification_pref_enabled(preferences: dict[str, Any], pref_key: str) -> bool:
    safe_key = str(pref_key or "").strip()
    if not safe_key:
        return False
    return bool(preferences.get(safe_key))


def _notification_actor_has_admin_access(actor: Optional[dict[str, Any]]) -> bool:
    if not isinstance(actor, dict):
        return False
    if str(actor.get("status") or "active").strip().lower() == "disabled":
        return False
    permissions = actor.get("permissions")
    if isinstance(permissions, list):
        for permission in permissions:
            if str(permission or "").strip().lower() in RBAC_PERMISSIONS:
                return True
    return False


def _notification_emit_persisted(
    uid: str,
    *,
    event_code: str,
    title: str,
    message: str,
    details: str = "",
    severity: str = "info",
    category: str = "activity",
    audience: str = "user",
    entity_key: str = "",
    dedupe_key: str = "",
    sticky: bool = False,
    status: str = "active",
    required_permission: str = "",
    action_label: str = "",
    action_target: Optional[dict[str, Any]] = None,
    email_eligible: bool = False,
    email_pref_key: str = "",
    metadata: Optional[dict[str, Any]] = None,
    recipient_role: str = "",
) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    if not safe_uid:
        raise HTTPException(status_code=400, detail="Missing notification recipient.")
    item = _notification_upsert_item(
        safe_uid,
        {
            "eventCode": event_code,
            "entityKey": entity_key,
            "title": title,
            "message": message,
            "details": details,
            "severity": severity,
            "category": category,
            "audience": audience,
            "status": status,
            "sticky": bool(sticky),
            "dedupeKey": dedupe_key or f"{event_code}::{entity_key or 'global'}",
            "requiredPermission": required_permission or None,
            "emailEligible": bool(email_eligible),
            "action": (
                {
                    "label": str(action_label or "").strip()[:80],
                    "target": _notification_action_target(action_target) or {},
                }
                if str(action_label or "").strip()
                else None
            ),
            "metadata": metadata or {},
        },
        resurface_unread=True,
    )
    if email_eligible and email_pref_key and _notification_email_feature_enabled():
        is_admin = str(audience or "").strip().lower() == "admin"
        prefs = _notification_preferences_get(safe_uid, is_admin=is_admin)
        if _notification_pref_enabled(prefs, email_pref_key):
            _notification_queue_email_delivery(uid=safe_uid, item=item, recipient_role=recipient_role)
    return item


def _notification_actor_from_assignment(uid: str, assignment: dict[str, Any]) -> dict[str, Any]:
    role = _rbac_normalize_role(str(assignment.get("role") or ""))
    allow = _rbac_normalize_overrides(assignment.get("allowOverrides"))
    deny = _rbac_normalize_overrides(assignment.get("denyOverrides"))
    permissions = _rbac_default_permissions_for_role(role)
    permissions.update(allow)
    permissions.difference_update(set(deny))
    return {
        "uid": str(uid or "").strip(),
        "role": role,
        "permissions": sorted(permissions),
        "status": _rbac_normalize_status(str(assignment.get("status") or "active")),
        "allowOverrides": allow,
        "denyOverrides": deny,
    }


def _notification_admin_recipients(required_permission: str) -> list[dict[str, Any]]:
    safe_permission = str(required_permission or "").strip().lower()
    recipients: dict[str, dict[str, Any]] = {}
    for uid in VF_ADMIN_APPROVER_UIDS:
        safe_uid = str(uid or "").strip()
        if not safe_uid:
            continue
        actor = {
            "uid": safe_uid,
            "role": RBAC_ROLE_SUPER_ADMIN,
            "permissions": sorted(RBAC_PERMISSIONS),
            "status": "active",
        }
        recipients[safe_uid] = actor
    cursor = ""
    while True:
        rows, next_cursor = _rbac_list_assignments(limit=200, cursor=cursor)
        for row in rows:
            if not isinstance(row, dict):
                continue
            safe_uid = str(row.get("uid") or "").strip()
            if not safe_uid:
                continue
            actor = _notification_actor_from_assignment(safe_uid, row)
            if safe_permission and not _has_permission(actor, safe_permission):
                continue
            recipients[safe_uid] = actor
        if not next_cursor or next_cursor == cursor:
            break
        cursor = str(next_cursor or "").strip()
    return list(recipients.values())


def _notification_required_permission_for_alert(event: dict[str, Any]) -> str:
    policy_id = str(event.get("policyId") or "").strip().lower()
    resource_type = str(event.get("resourceType") or "").strip().lower()
    if resource_type == "support_conversation" or policy_id.startswith("support"):
        return PERM_SUPPORT_READ
    if policy_id.startswith("guardian") or resource_type in {"guardian_issue", "guardian_approval"}:
        return PERM_GUARDIAN_READ
    if policy_id.startswith("audit") or resource_type.startswith("audit"):
        return PERM_AUDIT_READ
    if policy_id.startswith("rbac") or resource_type.startswith("rbac"):
        return PERM_RBAC_READ
    if (
        policy_id.startswith("billing")
        or policy_id.startswith("coupon")
        or resource_type in {"billing", "coupon", "coupon_campaign"}
    ):
        return PERM_BILLING_READ
    if policy_id.startswith("analytics"):
        return PERM_ANALYTICS_READ
    if resource_type in {"runtime", "queue", "backend", "ops"}:
        return PERM_OPS_READ
    return PERM_ALERTS_READ


def _notification_admin_tab_for_permission(permission: str) -> str:
    safe_permission = str(permission or "").strip().lower()
    if safe_permission in {PERM_SUPPORT_READ, PERM_SUPPORT_REPLY}:
        return "alerts"
    if safe_permission in {PERM_AUDIT_READ, PERM_RBAC_READ}:
        return "audit"
    if safe_permission == PERM_BILLING_READ:
        return "accounting"
    if safe_permission == PERM_ANALYTICS_READ:
        return "analytics"
    if safe_permission in {PERM_GUARDIAN_READ, PERM_OPS_READ}:
        return "guardian"
    if safe_permission == PERM_SCHEDULER_READ:
        return "scheduler"
    return "alerts"


def _notification_alert_copy(event: dict[str, Any]) -> tuple[str, str, str]:
    policy_id = str(event.get("policyId") or "alert").strip()
    resource_type = str(event.get("resourceType") or "resource").strip().replace("_", " ")
    resource_id = str(event.get("resourceId") or "").strip()
    severity = str(event.get("severity") or "warning").strip().lower()
    samples = event.get("samples") if isinstance(event.get("samples"), list) else []
    latest_sample = samples[-1] if samples and isinstance(samples[-1], dict) else {}
    reason = str((latest_sample or {}).get("reason") or "").strip()
    title = f"{resource_type.title()} Alert"
    if severity == "critical":
        title = f"Critical {resource_type.title()} Alert"
    detail_tokens = [f"Policy: {policy_id}"]
    if resource_id:
        detail_tokens.append(f"Resource: {resource_id}")
    if reason:
        detail_tokens.append(f"Reason: {reason}")
    message = f"{resource_type.title()} alert opened."
    if resource_id:
        message = f"{resource_type.title()} alert opened for {resource_id}."
    if reason:
        message = f"{message} {reason}"
    return title, message[:600], "\n".join(detail_tokens)


def _notification_emit_admin_broadcast(
    *,
    event_code: str,
    title: str,
    message: str,
    details: str = "",
    severity: str = "warning",
    category: str = "system",
    entity_key: str = "",
    dedupe_key: str = "",
    required_permission: str,
    action_label: str = "",
    action_target: Optional[dict[str, Any]] = None,
    email_eligible: bool = False,
    metadata: Optional[dict[str, Any]] = None,
) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for actor in _notification_admin_recipients(required_permission):
        uid = str(actor.get("uid") or "").strip()
        if not uid:
            continue
        rows.append(
            _notification_emit_persisted(
                uid,
                event_code=event_code,
                title=title,
                message=message,
                details=details,
                severity=severity,
                category=category,
                audience="admin",
                entity_key=entity_key,
                dedupe_key=f"{dedupe_key or event_code}::{uid}",
                sticky=severity in {"error", "critical"},
                required_permission=required_permission,
                action_label=action_label,
                action_target=action_target,
                email_eligible=email_eligible,
                email_pref_key="emailAdminAlerts",
                metadata=metadata,
                recipient_role=str(actor.get("role") or ""),
            )
        )
    return rows


def _notification_sync_account_usage(uid: str, entitlements: dict[str, Any]) -> None:
    safe_uid = str(uid or "").strip()
    if not safe_uid or not isinstance(entitlements, dict):
        return
    daily = entitlements.get("daily") if isinstance(entitlements.get("daily"), dict) else {}
    wallet = entitlements.get("wallet") if isinstance(entitlements.get("wallet"), dict) else {}
    period_key = str(daily.get("periodKey") or "").strip() or _usage_day_period_label(_utc_now())
    spendable = wallet.get("spendableNowByEngine") if isinstance(wallet.get("spendableNowByEngine"), dict) else {}
    spendable_values = [max(0.0, float(value or 0.0)) for value in spendable.values()]
    max_spendable = max(spendable_values) if spendable_values else 0.0
    if max_spendable <= 1000.0:
        _notification_emit_persisted(
            safe_uid,
            event_code="wallet.low_balance",
            title="Low Balance",
            message="Your remaining VoiceFlow balance is running low.",
            severity="warning",
            category="activity",
            entity_key=period_key,
            action_label="Open Billing",
            action_target={"screen": "main", "tab": "STUDIO"},
            email_eligible=True,
            email_pref_key="emailBilling",
        )


def _notification_emit_tts_job_terminal(job: dict[str, Any], *, status: str, detail: str = "") -> None:
    safe_job = dict(job or {})
    uid = str(safe_job.get("uid") or "").strip()
    if not uid:
        return
    job_id = str(safe_job.get("jobId") or safe_job.get("requestId") or "").strip()
    raw_engine = str(safe_job.get("engine") or "PRIME").strip()
    engine = _resolve_internal_engine_token(raw_engine or "PRIME") or "PRIME"
    created_at_ms = max(0, int(safe_job.get("createdAtMs") or 0))
    finished_at_ms = max(created_at_ms, int(safe_job.get("finishedAtMs") or int(time.time() * 1000)))
    duration_ms = max(0, finished_at_ms - created_at_ms)
    safe_status = str(status or "").strip().lower()
    if safe_status == "completed":
        event_code = "tts.job.completed"
        title = "Queued TTS Job Complete"
        message = f"Your queued {engine} TTS job completed."
        severity = "success"
        email_eligible = duration_ms >= int(VF_NOTIFICATIONS_JOB_EMAIL_MIN_DURATION_MS)
    elif safe_status == "cancelled":
        event_code = "tts.job.cancelled"
        title = "Queued TTS Job Cancelled"
        message = f"Your queued {engine} TTS job was cancelled."
        severity = "info"
        email_eligible = False
    else:
        event_code = "tts.job.failed"
        title = "Queued TTS Job Failed"
        message = f"Your queued {engine} TTS job failed."
        severity = "error"
        email_eligible = True
    extra_detail = detail or ""
    if not extra_detail and isinstance(safe_job.get("error"), dict):
        extra_detail = str((safe_job.get("error") or {}).get("detail") or "").strip()
    _notification_emit_persisted(
        uid,
        event_code=event_code,
        title=title,
        message=message,
        details=f"jobId={job_id}\nengine={engine}\ndurationMs={duration_ms}\n{extra_detail}".strip(),
        severity=severity,
        category="activity",
        entity_key=job_id,
        dedupe_key=f"{event_code}::{job_id or 'unknown'}",
        sticky=safe_status == "failed",
        action_label="Open History",
        action_target={"screen": "main", "tab": "HISTORY", "jobId": job_id},
        email_eligible=email_eligible,
        email_pref_key="emailAsyncJobs",
        metadata={"jobId": job_id, "engine": engine, "durationMs": duration_ms, "status": safe_status},
    )


def _paid_vf_credit_source(reason: str, metadata: Optional[dict[str, Any]] = None) -> str:
    safe_reason = str(reason or "").strip().lower()
    safe_metadata = metadata if isinstance(metadata, dict) else {}
    kind = str(safe_metadata.get("kind") or "").strip().lower()
    if kind == "token_pack" or safe_reason.startswith("stripe_token_pack"):
        return "token_pack"
    if safe_reason.startswith("wallet_coupon"):
        return "coupon"
    if safe_reason.startswith("stripe_"):
        return "stripe"
    if safe_reason.startswith("legacy"):
        return "legacy"
    if kind:
        return re.sub(r"[^a-z0-9_]", "_", kind).strip("_") or "manual"
    return "manual"


def _paid_vf_lot_expiry(source: str, now: datetime) -> Optional[str]:
    if str(source or "").strip().lower() == "token_pack":
        return _add_months_utc(now, VF_TOKEN_PACK_VALIDITY_MONTHS).isoformat()
    return None


def _paid_vf_lot_sort_key(lot: dict[str, Any]) -> tuple[float, float, str]:
    expires_dt = _parse_optional_datetime(str(lot.get("expiresAt") or ""))
    created_dt = _parse_optional_datetime(str(lot.get("createdAt") or ""))
    expires_key = expires_dt.timestamp() if expires_dt is not None else float("inf")
    created_key = created_dt.timestamp() if created_dt is not None else 0.0
    return (expires_key, created_key, str(lot.get("id") or ""))


def _normalize_paid_vf_lot(raw_lot: Any, now: datetime) -> Optional[dict[str, Any]]:
    if not isinstance(raw_lot, dict):
        return None
    lot_id = str(raw_lot.get("id") or raw_lot.get("lotId") or "").strip() or f"paid_lot_{uuid.uuid4().hex}"
    amount_total = _as_positive_number(raw_lot.get("amountTotal"))
    if amount_total <= 0:
        amount_total = _as_positive_number(raw_lot.get("amount") or raw_lot.get("amountRemaining"))
    amount_remaining = _as_positive_number(raw_lot.get("amountRemaining"))
    if amount_remaining <= 0:
        amount_remaining = _as_positive_number(raw_lot.get("amount") or amount_total)
    if amount_remaining <= 0:
        return None
    amount_total = max(_as_positive_number(amount_total), amount_remaining)
    created_at_dt = _parse_optional_datetime(str(raw_lot.get("createdAt") or "")) or now
    expires_at_dt = _parse_optional_datetime(str(raw_lot.get("expiresAt") or ""))
    if expires_at_dt is not None and expires_at_dt <= now:
        return None
    source = str(raw_lot.get("source") or "").strip().lower() or "manual"
    reason = str(raw_lot.get("reason") or "").strip()
    metadata = raw_lot.get("metadata") if isinstance(raw_lot.get("metadata"), dict) else {}
    return {
        "id": lot_id,
        "amountTotal": amount_total,
        "amountRemaining": amount_remaining,
        "createdAt": created_at_dt.isoformat(),
        "expiresAt": expires_at_dt.isoformat() if expires_at_dt is not None else None,
        "source": source,
        "reason": reason,
        "metadata": metadata,
    }


def _normalize_paid_vf_lots(raw_lots: Any, now: datetime) -> tuple[list[dict[str, Any]], float]:
    if not isinstance(raw_lots, list):
        return [], 0.0
    normalized: list[dict[str, Any]] = []
    for entry in raw_lots:
        lot = _normalize_paid_vf_lot(entry, now)
        if lot is None:
            continue
        normalized.append(lot)
    normalized.sort(key=_paid_vf_lot_sort_key)
    total = _as_positive_number(sum(_as_positive_number(item.get("amountRemaining")) for item in normalized))
    return normalized, total


def _append_paid_vf_credit_lot(
    entitlement: dict[str, Any],
    *,
    amount: float,
    reason: str,
    transaction_id: str,
    metadata: Optional[dict[str, Any]] = None,
    now: Optional[datetime] = None,
) -> dict[str, Any]:
    current = now or _utc_now()
    credit_amount = _as_positive_number(amount)
    normalized = dict(_normalize_entitlement_wallet(dict(entitlement or {}), current))
    if credit_amount <= 0:
        return normalized
    lots, _ = _normalize_paid_vf_lots(normalized.get("paidVfLots"), current)
    lot_id = str(transaction_id or "").strip() or f"paid_lot_{uuid.uuid4().hex}"
    safe_metadata = metadata if isinstance(metadata, dict) else {}
    source = _paid_vf_credit_source(reason, safe_metadata)
    expires_at = _paid_vf_lot_expiry(source, current)
    existing = next((item for item in lots if str(item.get("id") or "") == lot_id), None)
    if existing is None:
        lots.append(
            {
                "id": lot_id,
                "amountTotal": credit_amount,
                "amountRemaining": credit_amount,
                "createdAt": current.isoformat(),
                "expiresAt": expires_at,
                "source": source,
                "reason": str(reason or "").strip(),
                "metadata": safe_metadata,
            }
        )
    else:
        existing["amountTotal"] = _as_positive_number(_as_positive_number(existing.get("amountTotal")) + credit_amount)
        existing["amountRemaining"] = _as_positive_number(_as_positive_number(existing.get("amountRemaining")) + credit_amount)
        if not str(existing.get("source") or "").strip():
            existing["source"] = source
        if str(reason or "").strip():
            existing["reason"] = str(reason or "").strip()
        if expires_at and not existing.get("expiresAt"):
            existing["expiresAt"] = expires_at
        if safe_metadata:
            merged_metadata = existing.get("metadata") if isinstance(existing.get("metadata"), dict) else {}
            existing["metadata"] = {**merged_metadata, **safe_metadata}
    normalized_lots, total = _normalize_paid_vf_lots(lots, current)
    normalized["paidVfLots"] = normalized_lots
    normalized["paidVfBalance"] = total
    return normalized


def _consume_paid_vf_lots(
    entitlement: dict[str, Any],
    amount: float,
    now: Optional[datetime] = None,
) -> tuple[list[dict[str, Any]], list[dict[str, Any]], float, float]:
    current = now or _utc_now()
    target = _as_positive_number(amount)
    normalized = _normalize_entitlement_wallet(dict(entitlement or {}), current)
    lots, _ = _normalize_paid_vf_lots(normalized.get("paidVfLots"), current)
    if target <= 0 or not lots:
        total = _as_positive_number(sum(_as_positive_number(item.get("amountRemaining")) for item in lots))
        return lots, [], 0.0, total

    remaining = target
    spent = 0.0
    debits: list[dict[str, Any]] = []
    next_lots: list[dict[str, Any]] = []

    for lot in lots:
        lot_copy = dict(lot)
        available = _as_positive_number(lot_copy.get("amountRemaining"))
        if available <= 0:
            continue
        if remaining > 0:
            debit_amount = min(available, remaining)
            if debit_amount > 0:
                lot_copy["amountRemaining"] = _as_positive_number(available - debit_amount)
                remaining = _as_positive_number(remaining - debit_amount)
                spent = _as_positive_number(spent + debit_amount)
                debits.append(
                    {
                        "lotId": str(lot_copy.get("id") or ""),
                        "amount": _as_positive_number(debit_amount),
                        "source": str(lot_copy.get("source") or ""),
                        "expiresAt": lot_copy.get("expiresAt"),
                    }
                )
        if _as_positive_number(lot_copy.get("amountRemaining")) > 0:
            next_lots.append(lot_copy)

    normalized_next_lots, total = _normalize_paid_vf_lots(next_lots, current)
    return normalized_next_lots, debits, spent, total


def _restore_paid_vf_lots(
    entitlement: dict[str, Any],
    debits: Any,
    *,
    fallback_amount: float = 0.0,
    now: Optional[datetime] = None,
) -> dict[str, Any]:
    current = now or _utc_now()
    normalized = dict(_normalize_entitlement_wallet(dict(entitlement or {}), current))
    lots, _ = _normalize_paid_vf_lots(normalized.get("paidVfLots"), current)
    by_id = {str(item.get("id") or ""): item for item in lots}
    restored_amount = 0.0

    if isinstance(debits, list):
        for item in debits:
            if not isinstance(item, dict):
                continue
            amount_value = _as_positive_number(item.get("amount"))
            if amount_value <= 0:
                continue
            lot_id = str(item.get("lotId") or "").strip() or f"restored_lot_{uuid.uuid4().hex}"
            lot = by_id.get(lot_id)
            if lot is None:
                expires_at_dt = _parse_optional_datetime(str(item.get("expiresAt") or ""))
                if expires_at_dt is not None and expires_at_dt <= current:
                    expires_at_dt = None
                lot = {
                    "id": lot_id,
                    "amountTotal": amount_value,
                    "amountRemaining": amount_value,
                    "createdAt": current.isoformat(),
                    "expiresAt": expires_at_dt.isoformat() if expires_at_dt is not None else None,
                    "source": str(item.get("source") or "").strip().lower() or "restored",
                    "reason": "usage_revert",
                    "metadata": {},
                }
                lots.append(lot)
                by_id[lot_id] = lot
            else:
                lot["amountRemaining"] = _as_positive_number(_as_positive_number(lot.get("amountRemaining")) + amount_value)
                lot["amountTotal"] = max(_as_positive_number(lot.get("amountTotal")), _as_positive_number(lot.get("amountRemaining")))
            restored_amount = _as_positive_number(restored_amount + amount_value)

    if restored_amount <= 0:
        fallback_value = _as_positive_number(fallback_amount)
        if fallback_value > 0:
            lots.append(
                {
                    "id": f"restored_lot_{uuid.uuid4().hex}",
                    "amountTotal": fallback_value,
                    "amountRemaining": fallback_value,
                    "createdAt": current.isoformat(),
                    "expiresAt": None,
                    "source": "restored",
                    "reason": "usage_revert_fallback",
                    "metadata": {},
                }
            )

    normalized_lots, total = _normalize_paid_vf_lots(lots, current)
    normalized["paidVfLots"] = normalized_lots
    normalized["paidVfBalance"] = total
    return normalized


def _recalculate_token_pack_lots_for_entitlement(
    entitlement: dict[str, Any],
    *,
    now: Optional[datetime] = None,
) -> tuple[dict[str, Any], dict[str, int], bool]:
    current = now or _utc_now()
    normalized = dict(_normalize_entitlement_wallet(dict(entitlement or {}), current))
    raw_lots = normalized.get("paidVfLots") if isinstance(normalized.get("paidVfLots"), list) else []
    next_lots: list[dict[str, Any]] = []
    stats = {"tokenLotsSeen": 0, "tokenLotsUpdated": 0, "tokenLotsExpiredRemoved": 0}
    changed = False
    for raw_lot in raw_lots:
        if not isinstance(raw_lot, dict):
            continue
        lot = dict(raw_lot)
        source = str(lot.get("source") or "").strip().lower()
        if source != "token_pack":
            next_lots.append(lot)
            continue
        stats["tokenLotsSeen"] += 1
        created_dt = _parse_optional_datetime(str(lot.get("createdAt") or "")) or current
        next_expiry = _add_months_utc(created_dt, VF_TOKEN_PACK_VALIDITY_MONTHS)
        if next_expiry <= current:
            changed = True
            stats["tokenLotsExpiredRemoved"] += 1
            continue
        next_expiry_iso = next_expiry.isoformat()
        if str(lot.get("expiresAt") or "") != next_expiry_iso:
            lot["expiresAt"] = next_expiry_iso
            changed = True
            stats["tokenLotsUpdated"] += 1
        next_lots.append(lot)

    if not changed:
        return normalized, stats, False
    patched = dict(normalized)
    patched["paidVfLots"] = next_lots
    patched = _normalize_entitlement_wallet(patched, current)
    patched["updatedAt"] = current.isoformat()
    return patched, stats, True


def _recalculate_token_pack_expiry_migration(
    *,
    dry_run: bool,
    requested_by: str,
) -> dict[str, Any]:
    now = _utc_now()
    summary = {
        "dryRun": bool(dry_run),
        "requestedBy": str(requested_by or "").strip(),
        "ranAt": now.isoformat(),
        "usersScanned": 0,
        "usersChanged": 0,
        "tokenLotsSeen": 0,
        "tokenLotsUpdated": 0,
        "tokenLotsExpiredRemoved": 0,
    }
    collection = None if _prefer_inmemory_entitlement_store() else _firestore_collection("entitlements")
    if collection is None or _FIRESTORE_DB is None:
        with _INMEMORY_LOCK:
            user_ids = sorted(_INMEMORY_ENTITLEMENTS.keys())
        for uid in user_ids:
            with _INMEMORY_LOCK:
                current_row = dict(_INMEMORY_ENTITLEMENTS.get(uid) or {})
            if not current_row:
                continue
            summary["usersScanned"] += 1
            patched, stats, changed = _recalculate_token_pack_lots_for_entitlement(current_row, now=now)
            summary["tokenLotsSeen"] += int(stats.get("tokenLotsSeen") or 0)
            summary["tokenLotsUpdated"] += int(stats.get("tokenLotsUpdated") or 0)
            summary["tokenLotsExpiredRemoved"] += int(stats.get("tokenLotsExpiredRemoved") or 0)
            if changed:
                summary["usersChanged"] += 1
                if not dry_run:
                    with _INMEMORY_LOCK:
                        _INMEMORY_ENTITLEMENTS[uid] = dict(patched)
        return summary

    try:
        docs = list(collection.stream())
    except Exception as exc:
        raise HTTPException(status_code=503, detail=f"Failed to stream entitlements for token-pack migration: {exc}") from exc
    for doc in docs:
        uid = str(doc.id or "").strip()
        current_row = doc.to_dict() or {}
        if not uid or not isinstance(current_row, dict):
            continue
        current_row["uid"] = uid
        summary["usersScanned"] += 1
        patched, stats, changed = _recalculate_token_pack_lots_for_entitlement(current_row, now=now)
        summary["tokenLotsSeen"] += int(stats.get("tokenLotsSeen") or 0)
        summary["tokenLotsUpdated"] += int(stats.get("tokenLotsUpdated") or 0)
        summary["tokenLotsExpiredRemoved"] += int(stats.get("tokenLotsExpiredRemoved") or 0)
        if changed:
            summary["usersChanged"] += 1
            if not dry_run:
                doc.reference.set(
                    {
                        "paidVfLots": patched.get("paidVfLots") or [],
                        "paidVfBalance": _as_positive_number(patched.get("paidVfBalance")),
                        "updatedAt": patched.get("updatedAt") or now.isoformat(),
                    },
                    merge=True,
                )
    return summary


def _normalize_entitlement_wallet(entitlement: dict[str, Any], now: Optional[datetime] = None) -> dict[str, Any]:
    current = now or _utc_now()
    month_key = _wallet_month_key(current)
    normalized = dict(entitlement or {})
    plan_cfg = _plan_config(_normalize_plan_name(str(normalized.get("plan") or "Free")))
    normalized["plan"] = plan_cfg["plan"]
    plan_key = _plan_key_from_name(plan_cfg["plan"])
    if plan_key == "free":
        normalized["monthlyVfLimit"] = plan_cfg["monthlyVfLimit"]
    else:
        normalized["monthlyVfLimit"] = _as_positive_int(normalized.get("monthlyVfLimit") or plan_cfg["monthlyVfLimit"])
        if normalized["monthlyVfLimit"] <= 0:
            normalized["monthlyVfLimit"] = plan_cfg["monthlyVfLimit"]
    normalized.pop("dailyGenerationLimit", None)

    legacy_paid_balance = _as_positive_number(normalized.get("paidVfBalance"))
    paid_lots, paid_lots_total = _normalize_paid_vf_lots(normalized.get("paidVfLots"), current)
    if legacy_paid_balance > paid_lots_total + VF_EPSILON:
        legacy_delta = _as_positive_number(legacy_paid_balance - paid_lots_total)
        if legacy_delta > 0:
            paid_lots.append(
                {
                    "id": f"legacy_paid_vf_{uuid.uuid4().hex}",
                    "amountTotal": legacy_delta,
                    "amountRemaining": legacy_delta,
                    "createdAt": current.isoformat(),
                    "expiresAt": None,
                    "source": "legacy",
                    "reason": "legacy_balance_migration",
                    "metadata": {},
                }
            )
            paid_lots, paid_lots_total = _normalize_paid_vf_lots(paid_lots, current)
    normalized["paidVfLots"] = paid_lots
    normalized["paidVfBalance"] = paid_lots_total

    vff_grant = float(VF_FREE_MONTHLY_VFF_GRANT) if plan_key == "free" else 0.0
    vff_cap: Optional[float] = float(VF_FREE_MONTHLY_VFF_CAP) if plan_key == "free" else None
    saved_month = str(normalized.get("vffMonthKey") or "").strip()
    grant_month = str(normalized.get("vffGrantMonthKey") or "").strip()
    current_vff = _as_positive_number(normalized.get("vffBalance"))
    if saved_month != month_key:
        current_vff = 0.0
        saved_month = month_key
    if grant_month != month_key:
        current_vff = max(current_vff, vff_grant)
        grant_month = month_key
    if vff_cap is not None:
        current_vff = min(vff_cap, current_vff)
    normalized["vffBalance"] = _as_positive_number(current_vff)
    normalized["vffMonthKey"] = saved_month or month_key
    normalized["vffGrantMonthKey"] = grant_month or month_key

    vc_paid_balance = _as_positive_number(normalized.get("vcPaidBalance"))
    normalized["vcPaidBalance"] = vc_paid_balance
    vc_saved_month = str(normalized.get("vcMonthKey") or "").strip()
    vc_grant_month = str(normalized.get("vcGrantMonthKey") or "").strip()
    vc_free_balance = _as_positive_number(normalized.get("vcFreeBalance"))
    vc_grant_for_plan = _as_positive_number(VC_FREE_MONTHLY_GRANT_BY_PLAN.get(plan_key, 0.0))
    if vc_saved_month != month_key:
        vc_free_balance = 0.0
        vc_saved_month = month_key
    if vc_grant_month != month_key:
        vc_free_balance = max(vc_free_balance, vc_grant_for_plan)
        vc_grant_month = month_key
    normalized["vcFreeBalance"] = _as_positive_number(vc_free_balance)
    normalized["vcMonthKey"] = vc_saved_month or month_key
    normalized["vcGrantMonthKey"] = vc_grant_month or month_key
    normalized["launcherOfferConsumed"] = bool(normalized.get("launcherOfferConsumed"))

    raw_clone_map = normalized.get("dunoVoiceCloneMap")
    if isinstance(raw_clone_map, dict):
        normalized_clone_map: dict[str, dict[str, Any]] = {}
        for raw_key, raw_value in raw_clone_map.items():
            key = str(raw_key or "").strip()
            if not key or not isinstance(raw_value, dict):
                continue
            voice_id = str(raw_value.get("voiceId") or raw_value.get("voice_id") or "").strip()
            if not voice_id:
                continue
            normalized_clone_map[key] = {
                "voiceId": voice_id,
                "speaker": str(raw_value.get("speaker") or "").strip(),
                "referenceHash": str(raw_value.get("referenceHash") or "").strip(),
                "model": str(raw_value.get("model") or "").strip(),
                "updatedAt": str(raw_value.get("updatedAt") or "").strip() or current.isoformat(),
            }
        normalized["dunoVoiceCloneMap"] = normalized_clone_map
    else:
        normalized["dunoVoiceCloneMap"] = {}
    return normalized


def _monthly_free_remaining(entitlement: dict[str, Any], monthly: dict[str, Any]) -> float:
    monthly_limit = _as_positive_number(entitlement.get("monthlyVfLimit"))
    monthly_free_used = _as_positive_number(monthly.get("monthlyFreeVfUsed"))
    return _as_positive_number(monthly_limit - monthly_free_used)


def _wallet_spendable_now(entitlement: dict[str, Any], monthly: dict[str, Any], engine: str) -> float:
    safe_engine = _resolve_internal_engine_token(engine)
    monthly_remaining = _monthly_free_remaining(entitlement, monthly)
    paid_balance = _as_positive_number(entitlement.get("paidVfBalance"))
    vff_balance = _as_positive_number(entitlement.get("vffBalance"))
    if safe_engine not in TTS_ENGINE_KEYS:
        return _as_positive_number(monthly_remaining + paid_balance)
    return _as_positive_number(monthly_remaining + vff_balance + paid_balance)


def _wallet_charge_breakdown(
    entitlement: dict[str, Any],
    monthly: dict[str, Any],
    engine: str,
    vf_cost: float,
) -> dict[str, float]:
    remaining = _as_positive_number(vf_cost)
    breakdown: dict[str, float] = {"vff": 0.0, "monthlyVf": 0.0, "paidVf": 0.0}
    if remaining <= 0:
        return breakdown
    monthly_remaining = _monthly_free_remaining(entitlement, monthly)
    paid_balance = _as_positive_number(entitlement.get("paidVfBalance"))
    vff_balance = _as_positive_number(entitlement.get("vffBalance"))

    def spend(bucket: str, available: float) -> None:
        nonlocal remaining
        if remaining <= 0:
            return
        use = min(_as_positive_number(available), remaining)
        if use <= 0:
            return
        breakdown[bucket] = _as_positive_number(use)
        remaining = _as_positive_number(remaining - use)

    # Unified cross-engine spending order: monthly free -> VFF -> paid VF.
    spend("monthlyVf", monthly_remaining)
    spend("vff", vff_balance)
    spend("paidVf", paid_balance)
    return breakdown


def _prefer_inmemory_entitlement_store() -> bool:
    if str(os.getenv("PYTEST_CURRENT_TEST") or "").strip():
        return True
    if "pytest" in sys.modules:
        return True
    return bool((not VF_AUTH_ENFORCE) and (not VF_IS_PRODUCTION))


def _load_entitlement(uid: str, *, create_missing: bool = True) -> dict[str, Any]:
    defaults = _default_entitlement(uid)
    collection = None if _prefer_inmemory_entitlement_store() else _firestore_collection("entitlements")
    if collection is None:
        with _INMEMORY_LOCK:
            existing = _INMEMORY_ENTITLEMENTS.get(uid)
            if not existing:
                current = _normalize_entitlement_wallet({**defaults})
                if create_missing:
                    _INMEMORY_ENTITLEMENTS[uid] = current
                return {**current}
            current = _normalize_entitlement_wallet(existing)
            if create_missing:
                _INMEMORY_ENTITLEMENTS[uid] = current
            return {**current}
    doc = collection.document(uid).get()
    if not doc.exists:
        if create_missing:
            collection.document(uid).set(defaults)
        return {**defaults}
    payload = doc.to_dict() or {}
    merged = {**defaults, **payload}
    plan_cfg = _plan_config(_normalize_plan_name(str(merged.get("plan") or "Free")))
    merged["plan"] = plan_cfg["plan"]
    merged["monthlyVfLimit"] = _as_positive_int(merged.get("monthlyVfLimit") or plan_cfg["monthlyVfLimit"])
    if merged["monthlyVfLimit"] <= 0:
        merged["monthlyVfLimit"] = plan_cfg["monthlyVfLimit"]
    merged.pop("dailyGenerationLimit", None)
    merged = _normalize_entitlement_wallet(merged)
    return merged


def _write_entitlement(uid: str, payload: dict[str, Any]) -> None:
    patch = {**payload, "updatedAt": _safe_now_iso()}
    if "monthlyVfLimit" in patch:
        patch["monthlyVfLimit"] = _as_positive_int(patch.get("monthlyVfLimit"))
    patch.pop("dailyGenerationLimit", None)
    if "paidVfBalance" in patch:
        patch["paidVfBalance"] = _as_positive_number(patch.get("paidVfBalance"))
    if "vcPaidBalance" in patch:
        patch["vcPaidBalance"] = _as_positive_number(patch.get("vcPaidBalance"))
    if "vcFreeBalance" in patch:
        patch["vcFreeBalance"] = _as_positive_number(patch.get("vcFreeBalance"))
    if "paidVfLots" in patch and not isinstance(patch.get("paidVfLots"), list):
        patch["paidVfLots"] = []
    if "vffBalance" in patch:
        patch["vffBalance"] = _as_positive_number(patch.get("vffBalance"))
    if "vffMonthKey" in patch:
        patch["vffMonthKey"] = str(patch.get("vffMonthKey") or _wallet_month_key()).strip() or _wallet_month_key()
    if "vffGrantMonthKey" in patch:
        patch["vffGrantMonthKey"] = str(patch.get("vffGrantMonthKey") or _wallet_month_key()).strip() or _wallet_month_key()

    collection = _firestore_collection("entitlements")
    if collection is None:
        with _INMEMORY_LOCK:
            current = _normalize_entitlement_wallet(_INMEMORY_ENTITLEMENTS.get(uid) or _default_entitlement(uid))
            current.update(patch)
            _INMEMORY_ENTITLEMENTS[uid] = _normalize_entitlement_wallet(current)
        return
    collection.document(uid).set(patch, merge=True)


def _link_customer_uid(customer_id: str, uid: str) -> None:
    safe_customer = str(customer_id or "").strip()
    safe_uid = str(uid or "").strip()
    if not safe_customer or not safe_uid:
        return
    collection = None if _prefer_inmemory_entitlement_store() else _firestore_collection("stripe_customers")
    if collection is None:
        with _INMEMORY_LOCK:
            _INMEMORY_STRIPE_CUSTOMERS[safe_customer] = safe_uid
        return
    collection.document(safe_customer).set({"uid": safe_uid, "updatedAt": _utc_now().isoformat()}, merge=True)


def _resolve_uid_from_customer(customer_id: str) -> str:
    safe_customer = str(customer_id or "").strip()
    if not safe_customer:
        return ""
    collection = None if _prefer_inmemory_entitlement_store() else _firestore_collection("stripe_customers")
    if collection is None:
        with _INMEMORY_LOCK:
            return str(_INMEMORY_STRIPE_CUSTOMERS.get(safe_customer) or "")
    doc = collection.document(safe_customer).get()
    if not doc.exists:
        return ""
    payload = doc.to_dict() or {}
    return str(payload.get("uid") or "")


def _usage_defaults(uid: str, now: Optional[datetime] = None) -> tuple[dict[str, Any], dict[str, Any]]:
    current = now or _utc_now()
    def _empty_by_engine() -> dict[str, dict[str, Any]]:
        return {
            engine: {"chars": 0, "vf": 0.0}
            for engine in TTS_ENGINE_KEYS
        }
    monthly = {
        "uid": uid,
        "periodKey": _usage_month_period_label(current),
        "vfUsed": 0.0,
        "monthlyFreeVfUsed": 0.0,
        "generationCount": 0,
        "byEngine": _empty_by_engine(),
        "updatedAt": current.isoformat(),
    }
    daily = {
        "uid": uid,
        "periodKey": _usage_day_period_label(current),
        "vfUsed": 0.0,
        "generationCount": 0,
        "byEngine": _empty_by_engine(),
        "updatedAt": current.isoformat(),
    }
    return monthly, daily


def _load_usage_windows(
    uid: str,
    now: Optional[datetime] = None,
    *,
    create_missing: bool = True,
) -> tuple[dict[str, Any], dict[str, Any]]:
    current = now or _utc_now()
    monthly_doc_id = _inmemory_usage_month_doc_id(uid, current)
    daily_doc_id = _inmemory_usage_day_doc_id(uid, current)
    default_monthly, default_daily = _usage_defaults(uid, current)

    monthly_collection = None if _prefer_inmemory_entitlement_store() else _firestore_collection("usage_monthly")
    daily_collection = None if _prefer_inmemory_entitlement_store() else _firestore_collection("usage_daily")
    if monthly_collection is None or daily_collection is None:
        with _INMEMORY_LOCK:
            monthly = _INMEMORY_USAGE_MONTHLY.get(monthly_doc_id) or {**default_monthly}
            daily = _INMEMORY_USAGE_DAILY.get(daily_doc_id) or {**default_daily}
            if create_missing:
                _INMEMORY_USAGE_MONTHLY[monthly_doc_id] = monthly
                _INMEMORY_USAGE_DAILY[daily_doc_id] = daily
            return {**monthly}, {**daily}

    monthly_ref = monthly_collection.document(monthly_doc_id)
    daily_ref = daily_collection.document(daily_doc_id)
    monthly_doc = monthly_ref.get()
    daily_doc = daily_ref.get()
    if not monthly_doc.exists and create_missing:
        monthly_ref.set(default_monthly)
    if not daily_doc.exists and create_missing:
        daily_ref.set(default_daily)
    monthly = monthly_doc.to_dict() if monthly_doc.exists else default_monthly
    daily = daily_doc.to_dict() if daily_doc.exists else default_daily
    return {**default_monthly, **(monthly or {})}, {**default_daily, **(daily or {})}


def _reserve_usage(
    uid: str,
    request_id: str,
    engine: str,
    char_count: int,
    bypass_limits: bool = False,
    bypass_reason: str = "",
) -> dict[str, Any]:
    safe_engine = str(engine or "").strip().upper()
    if safe_engine not in VF_ENGINE_RATES:
        safe_engine = "PRIME"
    safe_chars = _as_positive_int(char_count)
    now = _utc_now()
    monthly_doc_id = _inmemory_usage_month_doc_id(uid, now)
    daily_doc_id = _inmemory_usage_day_doc_id(uid, now)
    event_doc_id = f"{uid}_{request_id}"

    if _prefer_inmemory_entitlement_store() or _firestore_collection("usage_events") is None:
        with _INMEMORY_LOCK:
            entitlement = _normalize_entitlement_wallet(_INMEMORY_ENTITLEMENTS.get(uid) or _default_entitlement(uid), now)
            _INMEMORY_ENTITLEMENTS[uid] = entitlement
            monthly = _INMEMORY_USAGE_MONTHLY.get(monthly_doc_id) or _usage_defaults(uid, now)[0]
            daily = _INMEMORY_USAGE_DAILY.get(daily_doc_id) or _usage_defaults(uid, now)[1]
            event = _INMEMORY_USAGE_EVENTS.get(event_doc_id)
            if event and str(event.get("status")) in {"reserved", "committed"}:
                return {"ok": True, "alreadyReserved": True, "event": event, "monthly": monthly, "daily": daily, "entitlement": entitlement}

            monthly.setdefault("monthlyFreeVfUsed", _as_positive_number(monthly.get("monthlyFreeVfUsed")))

            rate = _engine_rate(safe_engine)
            vf_cost = _as_positive_number(float(safe_chars) * float(rate))

            charge_breakdown = _wallet_charge_breakdown(entitlement, monthly, safe_engine, vf_cost)
            covered = (
                _as_positive_number(charge_breakdown.get("vff"))
                + _as_positive_number(charge_breakdown.get("monthlyVf"))
                + _as_positive_number(charge_breakdown.get("paidVf"))
            )
            if not bypass_limits and covered + VF_EPSILON < vf_cost:
                raise HTTPException(status_code=429, detail="Insufficient VF balance for this generation.")

            entitlement["vffBalance"] = _as_positive_number(
                _as_positive_number(entitlement.get("vffBalance")) - _as_positive_number(charge_breakdown.get("vff"))
            )
            paid_vf_lot_debits: list[dict[str, Any]] = []
            paid_vf_charge = _as_positive_number(charge_breakdown.get("paidVf"))
            if paid_vf_charge > 0:
                next_paid_lots, paid_vf_lot_debits, paid_vf_spent, next_paid_total = _consume_paid_vf_lots(
                    entitlement,
                    paid_vf_charge,
                    now,
                )
                if paid_vf_spent + VF_EPSILON < paid_vf_charge:
                    raise HTTPException(status_code=429, detail="Insufficient VF balance for this generation.")
                entitlement["paidVfLots"] = next_paid_lots
                entitlement["paidVfBalance"] = next_paid_total
            entitlement["updatedAt"] = now.isoformat()

            monthly["vfUsed"] = _as_positive_number(_as_positive_number(monthly.get("vfUsed")) + vf_cost)
            monthly["monthlyFreeVfUsed"] = _as_positive_number(
                _as_positive_number(monthly.get("monthlyFreeVfUsed")) + _as_positive_number(charge_breakdown.get("monthlyVf"))
            )
            monthly["generationCount"] = _as_positive_int(monthly.get("generationCount")) + 1
            monthly_engine = dict((monthly.get("byEngine") or {}).get(safe_engine) or {})
            monthly_engine["chars"] = _as_positive_int(monthly_engine.get("chars")) + safe_chars
            monthly_engine["vf"] = _as_positive_number(_as_positive_number(monthly_engine.get("vf")) + vf_cost)
            monthly.setdefault("byEngine", {})[safe_engine] = monthly_engine
            monthly["updatedAt"] = now.isoformat()

            daily["vfUsed"] = _as_positive_number(_as_positive_number(daily.get("vfUsed")) + vf_cost)
            daily["generationCount"] = _as_positive_int(daily.get("generationCount")) + 1
            daily_engine = dict((daily.get("byEngine") or {}).get(safe_engine) or {})
            daily_engine["chars"] = _as_positive_int(daily_engine.get("chars")) + safe_chars
            daily_engine["vf"] = _as_positive_number(_as_positive_number(daily_engine.get("vf")) + vf_cost)
            daily.setdefault("byEngine", {})[safe_engine] = daily_engine
            daily["updatedAt"] = now.isoformat()

            event_payload = {
                "uid": uid,
                "requestId": request_id,
                "status": "reserved",
                "engine": safe_engine,
                "chars": safe_chars,
                "vfCost": vf_cost,
                "rate": rate,
                "monthDocId": monthly_doc_id,
                "dayDocId": daily_doc_id,
                "chargeBreakdown": {
                    "vff": _as_positive_number(charge_breakdown.get("vff")),
                    "monthlyVf": _as_positive_number(charge_breakdown.get("monthlyVf")),
                    "paidVf": _as_positive_number(charge_breakdown.get("paidVf")),
                    "paidVfLots": paid_vf_lot_debits,
                },
                "limitBypass": {
                    "enabled": bool(bypass_limits),
                    "reason": str(bypass_reason or "").strip(),
                },
                "createdAt": now.isoformat(),
                "updatedAt": now.isoformat(),
            }

            _INMEMORY_ENTITLEMENTS[uid] = entitlement
            _INMEMORY_USAGE_MONTHLY[monthly_doc_id] = monthly
            _INMEMORY_USAGE_DAILY[daily_doc_id] = daily
            _INMEMORY_USAGE_EVENTS[event_doc_id] = event_payload
            return {"ok": True, "alreadyReserved": False, "event": event_payload, "monthly": monthly, "daily": daily, "entitlement": entitlement}

    assert _FIRESTORE_DB is not None
    assert firebase_firestore is not None

    entitlements_ref = _FIRESTORE_DB.collection("entitlements").document(uid)
    monthly_ref = _FIRESTORE_DB.collection("usage_monthly").document(monthly_doc_id)
    daily_ref = _FIRESTORE_DB.collection("usage_daily").document(daily_doc_id)
    event_ref = _FIRESTORE_DB.collection("usage_events").document(event_doc_id)

    transaction = _FIRESTORE_DB.transaction()

    @firebase_firestore.transactional
    def _apply(transaction_obj: Any) -> dict[str, Any]:
        entitlement_doc = entitlements_ref.get(transaction=transaction_obj)
        entitlement = entitlement_doc.to_dict() if entitlement_doc.exists else _default_entitlement(uid)
        entitlement = _normalize_entitlement_wallet(entitlement, now)
        rate = _engine_rate(safe_engine)
        vf_cost = _as_positive_number(float(safe_chars) * float(rate))

        monthly_doc = monthly_ref.get(transaction=transaction_obj)
        daily_doc = daily_ref.get(transaction=transaction_obj)
        default_monthly, default_daily = _usage_defaults(uid, now)
        monthly = {**default_monthly, **(monthly_doc.to_dict() or {})} if monthly_doc.exists else {**default_monthly}
        daily = {**default_daily, **(daily_doc.to_dict() or {})} if daily_doc.exists else {**default_daily}
        monthly.setdefault("monthlyFreeVfUsed", _as_positive_number(monthly.get("monthlyFreeVfUsed")))

        event_doc = event_ref.get(transaction=transaction_obj)
        if event_doc.exists:
            existing_event = event_doc.to_dict() or {}
            if str(existing_event.get("status")) in {"reserved", "committed"}:
                return {"ok": True, "alreadyReserved": True, "event": existing_event, "monthly": monthly, "daily": daily, "entitlement": entitlement}

        charge_breakdown = _wallet_charge_breakdown(entitlement, monthly, safe_engine, vf_cost)
        covered = (
            _as_positive_number(charge_breakdown.get("vff"))
            + _as_positive_number(charge_breakdown.get("monthlyVf"))
            + _as_positive_number(charge_breakdown.get("paidVf"))
        )
        if not bypass_limits and covered + VF_EPSILON < vf_cost:
            raise RuntimeError("Insufficient VF balance for this generation.")

        entitlement["vffBalance"] = _as_positive_number(
            _as_positive_number(entitlement.get("vffBalance")) - _as_positive_number(charge_breakdown.get("vff"))
        )
        paid_vf_lot_debits: list[dict[str, Any]] = []
        paid_vf_charge = _as_positive_number(charge_breakdown.get("paidVf"))
        if paid_vf_charge > 0:
            next_paid_lots, paid_vf_lot_debits, paid_vf_spent, next_paid_total = _consume_paid_vf_lots(
                entitlement,
                paid_vf_charge,
                now,
            )
            if paid_vf_spent + VF_EPSILON < paid_vf_charge:
                raise RuntimeError("Insufficient VF balance for this generation.")
            entitlement["paidVfLots"] = next_paid_lots
            entitlement["paidVfBalance"] = next_paid_total
        entitlement["updatedAt"] = now.isoformat()

        monthly["vfUsed"] = _as_positive_number(_as_positive_number(monthly.get("vfUsed")) + vf_cost)
        monthly["monthlyFreeVfUsed"] = _as_positive_number(
            _as_positive_number(monthly.get("monthlyFreeVfUsed")) + _as_positive_number(charge_breakdown.get("monthlyVf"))
        )
        monthly["generationCount"] = _as_positive_int(monthly.get("generationCount")) + 1
        monthly_engine = dict((monthly.get("byEngine") or {}).get(safe_engine) or {})
        monthly_engine["chars"] = _as_positive_int(monthly_engine.get("chars")) + safe_chars
        monthly_engine["vf"] = _as_positive_number(_as_positive_number(monthly_engine.get("vf")) + vf_cost)
        monthly.setdefault("byEngine", {})[safe_engine] = monthly_engine
        monthly["updatedAt"] = now.isoformat()

        daily["vfUsed"] = _as_positive_number(_as_positive_number(daily.get("vfUsed")) + vf_cost)
        daily["generationCount"] = _as_positive_int(daily.get("generationCount")) + 1
        daily_engine = dict((daily.get("byEngine") or {}).get(safe_engine) or {})
        daily_engine["chars"] = _as_positive_int(daily_engine.get("chars")) + safe_chars
        daily_engine["vf"] = _as_positive_number(_as_positive_number(daily_engine.get("vf")) + vf_cost)
        daily.setdefault("byEngine", {})[safe_engine] = daily_engine
        daily["updatedAt"] = now.isoformat()

        event_payload = {
            "uid": uid,
            "requestId": request_id,
            "status": "reserved",
            "engine": safe_engine,
            "chars": safe_chars,
            "vfCost": vf_cost,
            "rate": rate,
            "monthDocId": monthly_doc_id,
            "dayDocId": daily_doc_id,
            "chargeBreakdown": {
                "vff": _as_positive_number(charge_breakdown.get("vff")),
                "monthlyVf": _as_positive_number(charge_breakdown.get("monthlyVf")),
                "paidVf": _as_positive_number(charge_breakdown.get("paidVf")),
                "paidVfLots": paid_vf_lot_debits,
            },
            "limitBypass": {
                "enabled": bool(bypass_limits),
                "reason": str(bypass_reason or "").strip(),
            },
            "createdAt": now.isoformat(),
            "updatedAt": now.isoformat(),
        }

        transaction_obj.set(entitlements_ref, entitlement, merge=True)
        transaction_obj.set(monthly_ref, monthly, merge=True)
        transaction_obj.set(daily_ref, daily, merge=True)
        transaction_obj.set(event_ref, event_payload, merge=True)
        return {"ok": True, "alreadyReserved": False, "event": event_payload, "monthly": monthly, "daily": daily, "entitlement": entitlement}

    try:
        return _apply(transaction)
    except RuntimeError as exc:
        raise HTTPException(status_code=429, detail=str(exc)) from exc


def _finalize_usage(uid: str, request_id: str, success: bool, error_detail: str = "") -> None:
    event_doc_id = f"{uid}_{request_id}"
    now_dt = _utc_now()
    now = now_dt.isoformat()

    if _prefer_inmemory_entitlement_store() or _firestore_collection("usage_events") is None:
        with _INMEMORY_LOCK:
            event = _INMEMORY_USAGE_EVENTS.get(event_doc_id)
            if not event:
                return
            status = str(event.get("status") or "")
            if status == "committed":
                return
            if success:
                event["status"] = "committed"
                event["updatedAt"] = now
                _INMEMORY_USAGE_EVENTS[event_doc_id] = event
                return
            if status == "reserved":
                monthly = _INMEMORY_USAGE_MONTHLY.get(str(event.get("monthDocId") or ""))
                daily = _INMEMORY_USAGE_DAILY.get(str(event.get("dayDocId") or ""))
                entitlement = _normalize_entitlement_wallet(_INMEMORY_ENTITLEMENTS.get(uid) or _default_entitlement(uid))
                engine = str(event.get("engine") or "PRIME").upper()
                vf_cost = _as_positive_number(event.get("vfCost"))
                chars = _as_positive_int(event.get("chars"))
                charge_breakdown = event.get("chargeBreakdown") if isinstance(event.get("chargeBreakdown"), dict) else {}
                refund_vff = _as_positive_number(charge_breakdown.get("vff"))
                refund_paid = _as_positive_number(charge_breakdown.get("paidVf"))
                paid_vf_lot_debits = charge_breakdown.get("paidVfLots") if isinstance(charge_breakdown.get("paidVfLots"), list) else []
                refund_monthly = _as_positive_number(charge_breakdown.get("monthlyVf"))
                if monthly is not None:
                    monthly["vfUsed"] = _as_positive_number(_as_positive_number(monthly.get("vfUsed")) - vf_cost)
                    monthly["monthlyFreeVfUsed"] = _as_positive_number(
                        _as_positive_number(monthly.get("monthlyFreeVfUsed")) - refund_monthly
                    )
                    monthly["generationCount"] = max(0, _as_positive_int(monthly.get("generationCount")) - 1)
                    monthly_engine = dict((monthly.get("byEngine") or {}).get(engine) or {})
                    monthly_engine["vf"] = _as_positive_number(_as_positive_number(monthly_engine.get("vf")) - vf_cost)
                    monthly_engine["chars"] = max(0, _as_positive_int(monthly_engine.get("chars")) - chars)
                    monthly.setdefault("byEngine", {})[engine] = monthly_engine
                    monthly["updatedAt"] = now
                if daily is not None:
                    daily["vfUsed"] = _as_positive_number(_as_positive_number(daily.get("vfUsed")) - vf_cost)
                    daily["generationCount"] = max(0, _as_positive_int(daily.get("generationCount")) - 1)
                    daily_engine = dict((daily.get("byEngine") or {}).get(engine) or {})
                    daily_engine["vf"] = _as_positive_number(_as_positive_number(daily_engine.get("vf")) - vf_cost)
                    daily_engine["chars"] = max(0, _as_positive_int(daily_engine.get("chars")) - chars)
                    daily.setdefault("byEngine", {})[engine] = daily_engine
                    daily["updatedAt"] = now
                if refund_vff > 0 or refund_paid > 0:
                    entitlement["vffBalance"] = _as_positive_number(_as_positive_number(entitlement.get("vffBalance")) + refund_vff)
                    entitlement = _restore_paid_vf_lots(
                        entitlement,
                        paid_vf_lot_debits,
                        fallback_amount=refund_paid,
                        now=now_dt,
                    )
                    entitlement["updatedAt"] = now
                    _INMEMORY_ENTITLEMENTS[uid] = entitlement
            event["status"] = "reverted"
            event["updatedAt"] = now
            event["error"] = str(error_detail or "")
            _INMEMORY_USAGE_EVENTS[event_doc_id] = event
        return

    assert _FIRESTORE_DB is not None
    assert firebase_firestore is not None
    event_ref = _FIRESTORE_DB.collection("usage_events").document(event_doc_id)
    transaction = _FIRESTORE_DB.transaction()

    @firebase_firestore.transactional
    def _apply(transaction_obj: Any) -> None:
        event_doc = event_ref.get(transaction=transaction_obj)
        if not event_doc.exists:
            return
        event = event_doc.to_dict() or {}
        status = str(event.get("status") or "")
        if status == "committed":
            return
        if success:
            transaction_obj.set(event_ref, {"status": "committed", "updatedAt": now}, merge=True)
            return
        if status != "reserved":
            transaction_obj.set(event_ref, {"status": "reverted", "updatedAt": now, "error": str(error_detail)}, merge=True)
            return
        entitlements_ref = _FIRESTORE_DB.collection("entitlements").document(uid)
        monthly_ref = _FIRESTORE_DB.collection("usage_monthly").document(str(event.get("monthDocId") or ""))
        daily_ref = _FIRESTORE_DB.collection("usage_daily").document(str(event.get("dayDocId") or ""))
        entitlement_doc = entitlements_ref.get(transaction=transaction_obj)
        monthly_doc = monthly_ref.get(transaction=transaction_obj)
        daily_doc = daily_ref.get(transaction=transaction_obj)
        entitlement = _normalize_entitlement_wallet(
            entitlement_doc.to_dict() if entitlement_doc.exists else _default_entitlement(uid)
        )
        engine = str(event.get("engine") or "PRIME").upper()
        vf_cost = _as_positive_number(event.get("vfCost"))
        chars = _as_positive_int(event.get("chars"))
        charge_breakdown = event.get("chargeBreakdown") if isinstance(event.get("chargeBreakdown"), dict) else {}
        refund_vff = _as_positive_number(charge_breakdown.get("vff"))
        refund_paid = _as_positive_number(charge_breakdown.get("paidVf"))
        paid_vf_lot_debits = charge_breakdown.get("paidVfLots") if isinstance(charge_breakdown.get("paidVfLots"), list) else []
        refund_monthly = _as_positive_number(charge_breakdown.get("monthlyVf"))
        if monthly_doc.exists:
            monthly = monthly_doc.to_dict() or {}
            monthly["vfUsed"] = _as_positive_number(_as_positive_number(monthly.get("vfUsed")) - vf_cost)
            monthly["monthlyFreeVfUsed"] = _as_positive_number(
                _as_positive_number(monthly.get("monthlyFreeVfUsed")) - refund_monthly
            )
            monthly["generationCount"] = max(0, _as_positive_int(monthly.get("generationCount")) - 1)
            monthly_engine = dict((monthly.get("byEngine") or {}).get(engine) or {})
            monthly_engine["vf"] = _as_positive_number(_as_positive_number(monthly_engine.get("vf")) - vf_cost)
            monthly_engine["chars"] = max(0, _as_positive_int(monthly_engine.get("chars")) - chars)
            monthly.setdefault("byEngine", {})[engine] = monthly_engine
            monthly["updatedAt"] = now
            transaction_obj.set(monthly_ref, monthly, merge=True)
        if daily_doc.exists:
            daily = daily_doc.to_dict() or {}
            daily["vfUsed"] = _as_positive_number(_as_positive_number(daily.get("vfUsed")) - vf_cost)
            daily["generationCount"] = max(0, _as_positive_int(daily.get("generationCount")) - 1)
            daily_engine = dict((daily.get("byEngine") or {}).get(engine) or {})
            daily_engine["vf"] = _as_positive_number(_as_positive_number(daily_engine.get("vf")) - vf_cost)
            daily_engine["chars"] = max(0, _as_positive_int(daily_engine.get("chars")) - chars)
            daily.setdefault("byEngine", {})[engine] = daily_engine
            daily["updatedAt"] = now
            transaction_obj.set(daily_ref, daily, merge=True)
        if refund_vff > 0 or refund_paid > 0:
            entitlement["vffBalance"] = _as_positive_number(_as_positive_number(entitlement.get("vffBalance")) + refund_vff)
            entitlement = _restore_paid_vf_lots(
                entitlement,
                paid_vf_lot_debits,
                fallback_amount=refund_paid,
                now=now_dt,
            )
            entitlement["updatedAt"] = now
            transaction_obj.set(entitlements_ref, entitlement, merge=True)
        transaction_obj.set(event_ref, {"status": "reverted", "updatedAt": now, "error": str(error_detail)}, merge=True)

    _apply(transaction)


def _entitlement_usage_payload(uid: str) -> dict[str, Any]:
    entitlement = _normalize_entitlement_wallet(_load_entitlement(uid))
    monthly, daily = _load_usage_windows(uid)
    monthly_used = _as_positive_number(monthly.get("vfUsed"))
    monthly_limit = _as_positive_int(entitlement.get("monthlyVfLimit"))
    monthly_free_used = _as_positive_number(monthly.get("monthlyFreeVfUsed"))
    daily_used = _as_positive_int(daily.get("generationCount"))
    plan_name = _normalize_plan_name(str(entitlement.get("plan") or "Free"))
    month_key = _wallet_month_key()
    if str(entitlement.get("vffMonthKey") or "") != month_key:
        entitlement["vffBalance"] = 0.0
        entitlement["vffMonthKey"] = month_key
    vff_balance = _as_positive_number(entitlement.get("vffBalance"))
    paid_balance = _as_positive_number(entitlement.get("paidVfBalance"))
    monthly_free_remaining = _as_positive_number(float(monthly_limit) - monthly_free_used)
    month_start, month_end = _month_window_bounds()
    day_start, day_end = _day_window_bounds()
    plan_key = _plan_key_from_name(plan_name)
    guardrails = TTS_PLAN_GUARDRAILS.get(plan_key) or TTS_PLAN_GUARDRAILS["free"]
    allowed_engines = list(_plan_allowed_engines(plan_key))
    return {
        "uid": uid,
        "plan": plan_name,
        "status": str(entitlement.get("status") or "free_active"),
        "monthly": {
            "vfLimit": monthly_limit,
            "vfUsed": monthly_used,
            "monthlyFreeVfUsed": monthly_free_used,
            "vfRemaining": monthly_free_remaining,
            "generationCount": _as_positive_int(monthly.get("generationCount")),
            "periodKey": str(monthly.get("periodKey") or _usage_month_period_label()),
            "windowStartUtc": month_start,
            "windowEndUtc": month_end,
            "byEngine": monthly.get("byEngine") or {},
        },
        "daily": {
            "generationUsed": daily_used,
            "vfUsed": _as_positive_number(daily.get("vfUsed")),
            "periodKey": str(daily.get("periodKey") or _usage_day_period_label()),
            "windowStartUtc": day_start,
            "windowEndUtc": day_end,
            "byEngine": daily.get("byEngine") or {},
        },
        "billing": {
            "stripeCustomerId": entitlement.get("stripeCustomerId"),
            "subscriptionId": entitlement.get("subscriptionId"),
            "currencyMode": entitlement.get("currencyMode") or "INR_BASE_AUTO_FX",
            "billingCountry": entitlement.get("billingCountry"),
        },
        "wallet": {
            "monthlyFreeRemaining": monthly_free_remaining,
            "monthlyFreeLimit": monthly_limit,
            "vffBalance": vff_balance,
            "paidVfBalance": paid_balance,
            "spendableNowByEngine": {
                engine: _wallet_spendable_now(entitlement, monthly, engine)
                for engine in TTS_ENGINE_KEYS
            },
            "vffMonthKey": str(entitlement.get("vffMonthKey") or month_key),
        },
        "limits": {
            "vfRates": {
                engine: _engine_rate(engine)
                for engine in TTS_ENGINE_KEYS
            },
            "monthlyPlanCaps": {
                str(cfg.get("plan") or key): _as_positive_int(cfg.get("monthlyVfLimit"))
                for key, cfg in PLAN_LIMITS.items()
            },
            "maxCharsPerGeneration": max(1, int(guardrails.get("maxChars") or 1)),
            "allowedEngines": allowed_engines,
            "tokenPackDiscountPercent": _token_pack_discount_percent_for_plan(plan_name),
        },
        "features": {
            "earlyAccess": _plan_has_early_access(plan_key),
        },
    }

