def _alert_upsert_policy(policy_id: str, row: dict[str, Any]) -> dict[str, Any]:
    safe_id = str(policy_id or "").strip()
    if not safe_id:
        safe_id = f"apol_{uuid.uuid4().hex[:12]}"
    payload = dict(row or {})
    payload["id"] = safe_id
