def _reader_region_language_code(region_id: str, *, fallback: str = "en") -> str:
    region = reader_region(region_id)
    for code in list(region.get("languageCodes") or []):
        token = str(code or "").strip().lower()
        if len(token) >= 2:
            return token.split("-", 1)[0]
    return str(fallback or "en").strip().lower() or "en"


def _reader_default_discovery_query(*, surface: str, region_id: str) -> str:
    region_label = str(reader_region(region_id).get("label") or "global").strip()
    if normalize_reader_surface(surface) == "comics":
        return f"{region_label} comic panel"
    return f"{region_label} public domain book"


def _reader_parse_xml_entries(payload: str) -> list[ET.Element]:
    try:
        root = ET.fromstring(str(payload or ""))
    except ET.ParseError:
        return []
    return list(root.findall("atom:entry", _READER_ATOM_NS))


def _reader_fetch_project_gutenberg_catalog(region_id: str, *, search_query: str = "") -> list[dict[str, Any]]:
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    if _reader_region_language_code(safe_region_id) != "en":
        return []
    safe_search = _reader_search_term(search_query)
    try:
        response = requests.get(
            "https://www.gutenberg.org/ebooks/search.opds/",
            params={"query": safe_search},
            headers={"User-Agent": _reader_public_user_agent(), "Accept": "application/atom+xml,application/xml,text/xml"},
            timeout=(4, 12),
        )
        response.raise_for_status()
    except Exception:
        return []
    out: list[dict[str, Any]] = []
    for entry in _reader_parse_xml_entries(response.text):
        ebook_ref = str(entry.findtext("atom:id", default="", namespaces=_READER_ATOM_NS) or "").strip()
        match = re.search(r"/ebooks/(\d+)(?:\.opds)?$", ebook_ref)
        if not match:
            continue
        ebook_id = str(match.group(1) or "").strip()
        title = collapse_whitespace(entry.findtext("atom:title", default="", namespaces=_READER_ATOM_NS))
        if not title:
            continue
        author_names = [
            collapse_whitespace(author.findtext("atom:name", default="", namespaces=_READER_ATOM_NS))
            for author in entry.findall("atom:author", _READER_ATOM_NS)
            if collapse_whitespace(author.findtext("atom:name", default="", namespaces=_READER_ATOM_NS))
        ]
        author = ", ".join(author_names) or collapse_whitespace(entry.findtext("atom:content", default="", namespaces=_READER_ATOM_NS)) or "Project Gutenberg"
        updated_at = collapse_whitespace(entry.findtext("atom:updated", default="", namespaces=_READER_ATOM_NS))
        out.append(
            normalize_reader_catalog_item(
                {
                    "id": f"project_gutenberg_{ebook_id}",
                    "title": title,
                    "author": author,
                    "regionId": safe_region_id,
                    "contentKind": "book",
                    "provider": "project_gutenberg",
                    "license": "Public domain in the United States; Project Gutenberg permission terms apply",
                    "sourceUrl": f"https://www.gutenberg.org/ebooks/{ebook_id}",
                    "contentUrl": f"https://www.gutenberg.org/ebooks/{ebook_id}.txt.utf-8",
                    "summary": "Public-domain ebook sourced from Project Gutenberg.",
                    "supportsReadHere": True,
                    "collectionLabel": "Project Gutenberg",
                    "updatedAt": updated_at,
                    "sourceMeta": {"ebookId": ebook_id, "rightsTerritory": "us"},
                }
            )
        )
        if len(out) >= 8:
            break
    return out


def _reader_fetch_standard_ebooks_catalog(region_id: str, *, search_query: str = "") -> list[dict[str, Any]]:
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    if _reader_region_language_code(safe_region_id) != "en":
        return []
    safe_search = _reader_search_term(search_query)
    try:
        response = requests.get(
            "https://standardebooks.org/feeds/atom/all",
            params={"query": safe_search, "per-page": "8", "page": "1"},
            headers={"User-Agent": _reader_public_user_agent(), "Accept": "application/atom+xml,application/xml,text/xml"},
            timeout=(4, 12),
        )
        response.raise_for_status()
    except Exception:
        return []
    out: list[dict[str, Any]] = []
    for entry in _reader_parse_xml_entries(response.text):
        title = collapse_whitespace(entry.findtext("atom:title", default="", namespaces=_READER_ATOM_NS))
        book_url = collapse_whitespace(entry.findtext("atom:id", default="", namespaces=_READER_ATOM_NS))
        if not title or not book_url:
            continue
        author_names = [
            collapse_whitespace(author.findtext("atom:name", default="", namespaces=_READER_ATOM_NS))
            for author in entry.findall("atom:author", _READER_ATOM_NS)
            if collapse_whitespace(author.findtext("atom:name", default="", namespaces=_READER_ATOM_NS))
        ]
        content_url = ""
        for link in entry.findall("atom:link", _READER_ATOM_NS):
            href = str(link.attrib.get("href") or "").strip()
            link_type = str(link.attrib.get("type") or "").strip().lower()
            relation = str(link.attrib.get("rel") or "").strip().lower()
            if not href:
                continue
            if not book_url and relation == "alternate":
                book_url = href
            if relation == "enclosure" and link_type == "application/xhtml+xml" and "/text/single-page" in href:
                content_url = href
        cover_url = ""
        thumbnail = entry.find("media:thumbnail", _READER_ATOM_NS)
        if thumbnail is not None:
            cover_url = str(thumbnail.attrib.get("url") or "").strip()
        rights = collapse_whitespace(entry.findtext("atom:rights", default="", namespaces=_READER_ATOM_NS))
        summary = collapse_whitespace(entry.findtext("atom:summary", default="", namespaces=_READER_ATOM_NS))
        created_at = collapse_whitespace(entry.findtext("atom:published", default="", namespaces=_READER_ATOM_NS))
        updated_at = collapse_whitespace(entry.findtext("atom:updated", default="", namespaces=_READER_ATOM_NS))
        item_key = re.sub(r"[^a-z0-9]+", "_", book_url.lower()).strip("_")
        out.append(
            normalize_reader_catalog_item(
                {
                    "id": f"standard_ebooks_{item_key}",
                    "title": title,
                    "author": ", ".join(author_names) or "Standard Ebooks",
                    "regionId": safe_region_id,
                    "contentKind": "book",
                    "provider": "standard_ebooks",
                    "license": rights or "Public domain in the United States; Standard Ebooks original content is CC0",
                    "sourceUrl": book_url,
                    "contentUrl": content_url,
                    "summary": summary or "Polished public-domain ebook from Standard Ebooks.",
                    "coverUrl": cover_url,
                    "supportsReadHere": bool(content_url),
                    "collectionLabel": "Standard Ebooks",
                    "createdAt": created_at,
                    "updatedAt": updated_at,
                    "sourceMeta": {"rightsTerritory": "us", "singlePageUrl": content_url},
                }
            )
        )
    return out


def _reader_fetch_gutendex_catalog(region_id: str, *, search_query: str = "") -> list[dict[str, Any]]:
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    safe_search = _reader_search_term(search_query)
    language = _reader_region_language_code(safe_region_id)
    query = safe_search or _reader_default_discovery_query(surface="books", region_id=safe_region_id)
    try:
        response = requests.get(
            "https://gutendex.com/books",
            params={"languages": language, "search": query},
            headers={"User-Agent": _reader_public_user_agent(), "Accept": "application/json"},
            timeout=(4, 12),
        )
        response.raise_for_status()
        payload = response.json() or {}
    except Exception:
        return []
    out: list[dict[str, Any]] = []
    for entry in list(payload.get("results") or []):
        if not isinstance(entry, dict):
            continue
        title = collapse_whitespace(entry.get("title"))
        if not title:
            continue
        formats = dict(entry.get("formats") or {})
        text_url = ""
        for format_key in (
            "text/plain; charset=utf-8",
            "text/plain; charset=us-ascii",
            "text/plain",
            "text/html; charset=utf-8",
            "text/html",
        ):
            candidate = str(formats.get(format_key) or "").strip()
            if candidate:
                text_url = candidate
                break
        source_url = str(entry.get("url") or "").strip()
        if not source_url:
            source_url = str(formats.get("text/html") or text_url).strip()
        if not source_url:
            source_url = f"https://www.gutenberg.org/ebooks/{str(entry.get('id') or '').strip()}"
        cover_url = str(formats.get("image/jpeg") or "").strip()
        author_names = [
            collapse_whitespace(author.get("name"))
            for author in list(entry.get("authors") or [])
            if isinstance(author, dict) and collapse_whitespace(author.get("name"))
        ]
        rights_restricted = bool(entry.get("copyright"))
        license_label = "Rights vary by jurisdiction" if rights_restricted else "Public domain"
        item_id = str(entry.get("id") or "").strip()
        safe_item_id = re.sub(r"[^a-z0-9]+", "_", item_id.lower()).strip("_") or hashlib.sha1(title.encode("utf-8")).hexdigest()[:10]
        out.append(
            normalize_reader_catalog_item(
                {
                    "id": f"gutendex_{safe_item_id}",
                    "title": title,
                    "author": ", ".join(author_names) or "Gutendex",
                    "regionId": safe_region_id,
                    "contentKind": "book",
                    "provider": "gutendex",
                    "license": license_label,
                    "sourceUrl": source_url,
                    "contentUrl": text_url,
                    "coverUrl": cover_url,
                    "summary": "Global public-domain book discovery powered by Gutendex.",
                    "supportsReadHere": bool(text_url),
                    "collectionLabel": "Gutendex",
                    "sourceMeta": {
                        "gutendexId": item_id,
                        "attributionUrl": source_url,
                        "license": license_label,
                        "language": language,
                        "copyright": rights_restricted,
                    },
                }
            )
        )
        if len(out) >= 8:
            break
    return out


def _reader_fetch_wikisource_catalog(region_id: str, *, search_query: str = "") -> list[dict[str, Any]]:
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    safe_search = _reader_search_term(search_query)
    domain = _READER_WIKISOURCE_DOMAIN_BY_REGION.get(safe_region_id, "en.wikisource.org")
    query = safe_search or _reader_default_discovery_query(surface="books", region_id=safe_region_id)
    try:
        response = requests.get(
            f"https://{domain}/w/api.php",
            params={
                "action": "query",
                "format": "json",
                "generator": "search",
                "gsrsearch": query,
                "gsrlimit": 8,
                "gsrnamespace": 0,
                "prop": "info|extracts",
                "inprop": "url",
                "explaintext": 1,
                "exintro": 1,
                "exchars": 420,
                "origin": "*",
            },
            headers={"User-Agent": _reader_public_user_agent(), "Accept": "application/json"},
            timeout=(4, 12),
        )
        response.raise_for_status()
        payload = response.json() or {}
    except Exception:
        return []
    query_payload = payload.get("query")
    pages_payload = dict(query_payload.get("pages") or {}) if isinstance(query_payload, dict) else {}
    pages = [item for item in pages_payload.values() if isinstance(item, dict)]
    pages.sort(key=lambda item: int(item.get("index") or 999999))
    out: list[dict[str, Any]] = []
    source_language = _reader_region_language_code(safe_region_id)
    for entry in pages:
        title = collapse_whitespace(entry.get("title"))
        full_url = str(entry.get("fullurl") or "").strip()
        page_id = str(entry.get("pageid") or "").strip()
        if not title or not full_url:
            continue
        excerpt = collapse_whitespace(entry.get("extract"))
        item_key = page_id or re.sub(r"[^a-z0-9]+", "_", title.lower()).strip("_")
        out.append(
            normalize_reader_catalog_item(
                {
                    "id": f"wikisource_{safe_region_id}_{item_key}",
                    "title": title,
                    "author": "Wikisource community",
                    "regionId": safe_region_id,
                    "sourceLanguage": source_language,
                    "contentKind": "book",
                    "provider": "wikisource",
                    "license": "CC BY-SA 4.0",
                    "sourceUrl": full_url,
                    "contentUrl": full_url,
                    "summary": excerpt or f"Open licensed reading discovery from {domain}.",
                    "supportsReadHere": True,
                    "collectionLabel": "Wikisource",
                    "sourceMeta": {
                        "domain": domain,
                        "pageId": page_id,
                        "attributionUrl": full_url,
                        "license": "CC BY-SA 4.0",
                    },
                }
            )
        )
        if len(out) >= 8:
            break
    return out


def _reader_fetch_openlibrary_catalog(region_id: str, *, search_query: str = "") -> list[dict[str, Any]]:
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    safe_search = _reader_search_term(search_query)
    language = _reader_region_language_code(safe_region_id)
    query = safe_search or _reader_default_discovery_query(surface="books", region_id=safe_region_id)
    try:
        response = requests.get(
            "https://openlibrary.org/search.json",
            params={
                "q": query,
                "language": language,
                "limit": 10,
                "fields": "key,title,author_name,cover_i,first_publish_year,ebook_access,public_scan_b,id_project_gutenberg",
            },
            headers={"User-Agent": _reader_public_user_agent(), "Accept": "application/json"},
            timeout=(4, 12),
        )
        response.raise_for_status()
        payload = response.json() or {}
    except Exception:
        return []
    out: list[dict[str, Any]] = []
    for entry in list(payload.get("docs") or []):
        if not isinstance(entry, dict):
            continue
        title = collapse_whitespace(entry.get("title"))
        key = str(entry.get("key") or "").strip()
        if not title or not key:
            continue
        source_url = f"https://openlibrary.org{key}"
        author_names = [collapse_whitespace(name) for name in list(entry.get("author_name") or []) if collapse_whitespace(name)]
        cover_id = str(entry.get("cover_i") or "").strip()
        cover_url = f"https://covers.openlibrary.org/b/id/{cover_id}-L.jpg" if cover_id else ""
        gutenberg_refs = list(entry.get("id_project_gutenberg") or [])
        gutenberg_id = str(gutenberg_refs[0] if gutenberg_refs else "").strip()
        content_url = f"https://www.gutenberg.org/ebooks/{gutenberg_id}.txt.utf-8" if gutenberg_id else ""
        public_scan = bool(entry.get("public_scan_b"))
        license_label = "Public domain" if gutenberg_id or public_scan else "Rights vary by edition"
        publish_year = str(entry.get("first_publish_year") or "").strip()
        summary_parts = [
            "Global metadata discovery from Open Library.",
            f"First published: {publish_year}." if publish_year else "",
        ]
        out.append(
            normalize_reader_catalog_item(
                {
                    "id": f"openlibrary_{re.sub(r'[^a-z0-9]+', '_', key.lower()).strip('_')}",
                    "title": title,
                    "author": ", ".join(author_names) or "Open Library",
                    "regionId": safe_region_id,
                    "sourceLanguage": language,
                    "contentKind": "book",
                    "provider": "openlibrary",
                    "license": license_label,
                    "sourceUrl": source_url,
                    "contentUrl": content_url,
                    "coverUrl": cover_url,
                    "summary": " ".join([part for part in summary_parts if part]).strip(),
                    "supportsReadHere": bool(content_url),
                    "collectionLabel": "Open Library",
                    "sourceMeta": {
                        "openLibraryKey": key,
                        "ebookAccess": str(entry.get("ebook_access") or "").strip(),
                        "publicScan": public_scan,
                        "attributionUrl": source_url,
                        "license": license_label,
                    },
                }
            )
        )
        if len(out) >= 8:
            break
    return out


def _reader_fetch_google_books_catalog(region_id: str, *, search_query: str = "") -> list[dict[str, Any]]:
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    safe_search = _reader_search_term(search_query)
    language = _reader_region_language_code(safe_region_id)
    query = safe_search or _reader_default_discovery_query(surface="books", region_id=safe_region_id)
    try:
        response = requests.get(
            "https://www.googleapis.com/books/v1/volumes",
            params={
                "q": query,
                "langRestrict": language,
                "printType": "books",
                "orderBy": "relevance",
                "maxResults": 8,
            },
            headers={"User-Agent": _reader_public_user_agent(), "Accept": "application/json"},
            timeout=(4, 12),
        )
        response.raise_for_status()
        payload = response.json() or {}
    except Exception:
        return []
    out: list[dict[str, Any]] = []
    for entry in list(payload.get("items") or []):
        if not isinstance(entry, dict):
            continue
        volume_id = str(entry.get("id") or "").strip()
        volume_info = dict(entry.get("volumeInfo") or {})
        access_info = dict(entry.get("accessInfo") or {})
        title = collapse_whitespace(volume_info.get("title"))
        if not title:
            continue
        authors = [collapse_whitespace(name) for name in list(volume_info.get("authors") or []) if collapse_whitespace(name)]
        image_links = dict(volume_info.get("imageLinks") or {})
        source_url = str(volume_info.get("infoLink") or volume_info.get("previewLink") or "").strip()
        attribution_url = str(volume_info.get("canonicalVolumeLink") or source_url).strip()
        epub_info = dict(access_info.get("epub") or {})
        pdf_info = dict(access_info.get("pdf") or {})
        public_domain = bool(access_info.get("publicDomain"))
        download_url = str(epub_info.get("downloadLink") or pdf_info.get("downloadLink") or "").strip()
        supports_read_here = bool(public_domain and download_url)
        license_label = "Public domain" if public_domain else "Rights vary by publisher license"
        out.append(
            normalize_reader_catalog_item(
                {
                    "id": f"google_books_{re.sub(r'[^a-z0-9]+', '_', volume_id.lower()).strip('_') or hashlib.sha1(title.encode('utf-8')).hexdigest()[:10]}",
                    "title": title,
                    "author": ", ".join(authors) or "Google Books",
                    "regionId": safe_region_id,
                    "sourceLanguage": _reader_normalize_language(volume_info.get("language"), default=language) or language,
                    "contentKind": "book",
                    "provider": "google_books",
                    "license": license_label,
                    "sourceUrl": source_url,
                    "contentUrl": download_url if supports_read_here else "",
                    "coverUrl": str(image_links.get("thumbnail") or image_links.get("smallThumbnail") or "").strip(),
                    "summary": collapse_whitespace(volume_info.get("description")) or "Commercial catalog discovery powered by Google Books.",
                    "supportsReadHere": supports_read_here,
                    "collectionLabel": "Google Books",
                    "sourceMeta": {
                        "googleVolumeId": volume_id,
                        "viewability": str(access_info.get("viewability") or "").strip(),
                        "publicDomain": public_domain,
                        "attributionUrl": attribution_url,
                        "license": license_label,
                    },
                }
            )
        )
        if len(out) >= 8:
            break
    return out


def _reader_search_openverse_assets(kind: str, query: str, tag: str, page: int, *, page_size: int = 12) -> list[dict[str, Any]]:
    safe_kind = "audio" if str(kind or "").strip().lower() == "audio" else "image"
    params: dict[str, Any] = {
        "page_size": max(1, min(24, int(page_size))),
        "page": max(1, int(page or 1)),
    }
    safe_query = str(query or "").strip()
    safe_tag = str(tag or "").strip()
    if safe_query:
        params["q"] = safe_query
    if safe_tag and not safe_query:
        params["tags"] = safe_tag
    path = "audio" if safe_kind == "audio" else "images"
    endpoint = f"{OPENVERSE_API_BASE_URL.rstrip('/')}/{path}"
    response = requests.get(endpoint, params=params, timeout=12)
    response.raise_for_status()
    payload = response.json() or {}
    items: list[dict[str, Any]] = []
    for entry in payload.get("results") or []:
        if not isinstance(entry, dict):
            continue
        raw_tags = entry.get("tags")
        safe_tags = [str(tag_item).strip() for tag_item in list(raw_tags or []) if str(tag_item).strip()] if isinstance(raw_tags, list) else []
        items.append(
            {
                "id": str(entry.get("id") or ""),
                "provider": "openverse",
                "kind": safe_kind,
                "title": str(entry.get("title") or "Untitled asset").strip() or "Untitled asset",
                "thumbUrl": str(entry.get("thumbnail") or "").strip() or None,
                "previewUrl": str(entry.get("url") or "").strip() or None,
                "downloadUrl": str(entry.get("url") or "").strip(),
                "durationSec": round(float(entry.get("duration") or 0) / 1000.0, 3) if safe_kind == "audio" else None,
                "width": int(entry.get("width") or 0) or None,
                "height": int(entry.get("height") or 0) or None,
                "license": str(entry.get("license_url") or entry.get("license") or "").strip() or None,
                "creator": str(entry.get("creator") or "").strip() or None,
                "attributionUrl": str(entry.get("foreign_landing_url") or entry.get("creator_url") or "").strip() or None,
                "tags": safe_tags,
                "externalUrl": str(entry.get("detail_url") or entry.get("foreign_landing_url") or "").strip() or None,
            }
        )
    return items


def _reader_fetch_openverse_comic_catalog(region_id: str, *, search_query: str = "") -> list[dict[str, Any]]:
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    safe_search = _reader_search_term(search_query)
    query = safe_search or _reader_default_discovery_query(surface="comics", region_id=safe_region_id)
    try:
        entries = _reader_search_openverse_assets("image", query, "comic", 1)
    except Exception:
        return []
    out: list[dict[str, Any]] = []
    for entry in list(entries or []):
        if not isinstance(entry, dict):
            continue
        openverse_id = str(entry.get("id") or "").strip()
        image_url = str(entry.get("downloadUrl") or entry.get("previewUrl") or "").strip()
        if not image_url:
            continue
        title = collapse_whitespace(entry.get("title")) or "Openverse Comic Panel"
        attribution_url = str(entry.get("attributionUrl") or entry.get("externalUrl") or image_url).strip()
        license_value = str(entry.get("license") or "").strip()
        creator = collapse_whitespace(entry.get("creator")) or "Openverse creator"
        item_id = openverse_id or hashlib.sha1(f"{title}:{image_url}".encode("utf-8")).hexdigest()[:12]
        out.append(
            normalize_reader_catalog_item(
                {
                    "id": f"openverse_comic_{re.sub(r'[^a-z0-9]+', '_', item_id.lower()).strip('_')}",
                    "title": title,
                    "author": creator,
                    "regionId": safe_region_id,
                    "contentKind": "comic",
                    "provider": "openverse",
                    "license": license_value,
                    "sourceUrl": attribution_url,
                    "contentUrl": image_url,
                    "coverUrl": str(entry.get("thumbUrl") or entry.get("previewUrl") or image_url).strip(),
                    "summary": "Open-license comic-style artwork from Openverse API.",
                    "supportsReadHere": True,
                    "direction": "vertical-scroll",
                    "readingModeDefault": "vertical_strip",
                    "collectionLabel": "Openverse Comics",
                    "attributionUrl": attribution_url,
                    "sourceMeta": {
                        "openverseId": openverse_id,
                        "imageUrl": image_url,
                        "attributionUrl": attribution_url,
                        "license": license_value,
                    },
                }
            )
        )
        if len(out) >= 8:
            break
    return out


def _reader_pepper_carrot_cover_url(episode_url: str) -> str:
    match = re.search(r"/webcomic/(ep\d+_[^/]+)\.html$", str(episode_url or "").strip(), flags=re.IGNORECASE)
    if not match:
        return ""
    slug = str(match.group(1) or "").strip()
    episode_number_match = re.search(r"ep(\d+)_", slug, flags=re.IGNORECASE)
    if not episode_number_match:
        return ""
    episode_number = max(0, int(episode_number_match.group(1) or 0))
    return (
        f"https://www.peppercarrot.com/0_sources/{slug}/low-res/"
        f"en_Pepper-and-Carrot_by-David-Revoy_E{episode_number:02d}P00.jpg"
    )


def _reader_fetch_pepper_carrot_catalog(region_id: str, *, search_query: str = "") -> list[dict[str, Any]]:
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    safe_search = _reader_search_term(search_query).lower()
    index_url = "https://www.peppercarrot.com/en/webcomics/peppercarrot.html"
    try:
        response = requests.get(
            index_url,
            headers={"User-Agent": _reader_public_user_agent(), "Accept": "text/html,application/xhtml+xml"},
            timeout=(4, 12),
        )
        response.raise_for_status()
    except Exception:
        return []
    soup = BeautifulSoup(response.text[:2_000_000], "html.parser")
    out: list[dict[str, Any]] = []
    seen_urls: set[str] = set()
    for link in soup.find_all("a", href=True):
        episode_url = urljoin(index_url, str(link.get("href") or "").strip())
        title = collapse_whitespace(" ".join(link.stripped_strings))
        if (
            not episode_url
            or episode_url in seen_urls
            or "/webcomic/" not in episode_url
            or not episode_url.endswith(".html")
            or not title.lower().startswith("episode ")
        ):
            continue
        seen_urls.add(episode_url)
        if safe_search and safe_search not in title.lower():
            continue
        out.append(
            normalize_reader_catalog_item(
                {
                    "id": f"pepper_carrot_{re.sub(r'[^a-z0-9]+', '_', episode_url.lower()).strip('_')}",
                    "title": title,
                    "author": "David Revoy",
                    "regionId": safe_region_id,
                    "contentKind": "comic",
                    "provider": "pepper_carrot",
                    "license": "CC BY 4.0",
                    "sourceUrl": episode_url,
                    "contentUrl": episode_url,
                    "summary": "Official Pepper&Carrot webcomic episode released for commercial reuse under CC BY 4.0.",
                    "coverUrl": _reader_pepper_carrot_cover_url(episode_url),
                    "supportsReadHere": True,
                    "direction": "vertical-scroll",
                    "readingModeDefault": "vertical_strip",
                    "collectionLabel": "Pepper&Carrot",
                    "sourceMeta": {"episodeUrl": episode_url},
                }
            )
        )
        if len(out) >= 8:
            break
    return out


def _reader_merge_catalog_items(*sources: list[dict[str, Any]]) -> list[dict[str, Any]]:
    merged: list[dict[str, Any]] = []
    seen: set[str] = set()
    for source in sources:
        for item in list(source or []):
            if not isinstance(item, dict):
                continue
            safe_item = normalize_reader_catalog_item(item)
            safe_id = str(safe_item.get("id") or "").strip().lower()
            if not safe_id or safe_id in seen:
                continue
            seen.add(safe_id)
            merged.append(safe_item)
    return merged


def _reader_collect_catalog_sources(
    factories: list[Callable[[], list[dict[str, Any]]]],
    *,
    max_wait_sec: float = 8.5,
) -> list[list[dict[str, Any]]]:
    safe_factories = [factory for factory in list(factories or []) if callable(factory)]
    if not safe_factories:
        return []
    deadline = time.time() + max(1.0, float(max_wait_sec or 8.5))
    out: list[list[dict[str, Any]]] = []
    executor = ThreadPoolExecutor(max_workers=max(1, min(6, len(safe_factories))))
    pending: set[Future[Any]] = set()
    try:
        pending = {executor.submit(factory) for factory in safe_factories}
        while pending and time.time() < deadline:
            remaining_sec = max(0.05, deadline - time.time())
            done, pending = wait(pending, timeout=remaining_sec, return_when=FIRST_COMPLETED)
            for future in done:
                try:
                    payload = future.result()
                except Exception:
                    continue
                if not isinstance(payload, list):
                    continue
                out.append([dict(item) for item in payload if isinstance(item, dict)])
        for future in pending:
            future.cancel()
    finally:
        executor.shutdown(wait=False, cancel_futures=True)
    return out


def _reader_catalog_items(region_id: str, *, surface: str, search_query: str = "") -> list[dict[str, Any]]:
    safe_surface = normalize_reader_surface(surface)
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    safe_search = _reader_search_term(search_query)
    if VF_READER_IMPORTS_ONLY:
        discovery = fallback_catalog_items(
            safe_region_id,
            content_kind="comic" if safe_surface == "comics" else "book",
        )
        admin_items = _reader_admin_catalog_public_items(safe_region_id, surface=safe_surface, search_query=safe_search)
        items = _reader_merge_catalog_items(discovery, admin_items)
        if not safe_search:
            return items
        search_blob = safe_search.lower()
        return [
            item
            for item in items
            if search_blob in " ".join(
                [
                    str(item.get("title") or ""),
                    str(item.get("author") or ""),
                    str(item.get("summary") or ""),
                    str(item.get("provider") or ""),
                    str(item.get("collectionLabel") or ""),
                ]
            ).lower()
        ]
    cache_key = _reader_search_cache_key(safe_surface, safe_region_id, safe_search)
    cached = _reader_catalog_cache_get(cache_key)
    if cached is not None:
        return cached
    if safe_surface == "comics":
        comic_factories: list[Callable[[], list[dict[str, Any]]]] = [
            lambda: _reader_fetch_pepper_carrot_catalog(safe_region_id, search_query=safe_search),
            lambda: _reader_fetch_openverse_comic_catalog(safe_region_id, search_query=safe_search),
        ]
        if not safe_search:
            comic_factories.append(lambda: fallback_catalog_items(safe_region_id, content_kind="comic"))
        items = _reader_merge_catalog_items(*_reader_collect_catalog_sources(comic_factories))
        items = _reader_merge_catalog_items(items, _reader_admin_catalog_public_items(safe_region_id, surface=safe_surface, search_query=safe_search))
        return _reader_catalog_cache_set(cache_key, items)
    book_factories: list[Callable[[], list[dict[str, Any]]]] = [
        lambda: _reader_fetch_gutendex_catalog(safe_region_id, search_query=safe_search),
        lambda: _reader_fetch_wikisource_catalog(safe_region_id, search_query=safe_search),
        lambda: _reader_fetch_standard_ebooks_catalog(safe_region_id, search_query=safe_search),
        lambda: _reader_fetch_project_gutenberg_catalog(safe_region_id, search_query=safe_search),
    ]
    if safe_search or safe_region_id != "english":
        book_factories.append(lambda: _reader_fetch_openlibrary_catalog(safe_region_id, search_query=safe_search))
    if safe_search:
        book_factories.append(lambda: _reader_fetch_google_books_catalog(safe_region_id, search_query=safe_search))
    if not safe_search:
        book_factories.append(lambda: fallback_catalog_items(safe_region_id, content_kind="book"))
    items = _reader_merge_catalog_items(*_reader_collect_catalog_sources(book_factories))
    items = _reader_merge_catalog_items(items, _reader_admin_catalog_public_items(safe_region_id, surface=safe_surface, search_query=safe_search))
    return _reader_catalog_cache_set(cache_key, items)


def _reader_catalog_lookup(item_id: str, *, include_drafts: bool = False) -> Optional[dict[str, Any]]:
    safe_item_id = str(item_id or "").strip()
    if not safe_item_id:
        return None
    admin_item = _reader_admin_catalog_get(safe_item_id, include_drafts=include_drafts)
    if admin_item:
        return admin_item
    if VF_READER_IMPORTS_ONLY:
        for region in reader_regions():
            safe_region_id = str(region.get("id") or "english")
            for surface in ("books", "comics"):
                for item in _reader_catalog_items(safe_region_id, surface=surface):
                    if str(item.get("id") or "").strip() == safe_item_id:
                        return item
        return None
    with _INMEMORY_LOCK:
        for cached in list(_INMEMORY_READER_CATALOG_CACHE.values()):
            items = list((cached or {}).get("items") or [])
            for item in items:
                if not isinstance(item, dict):
                    continue
                if str(item.get("id") or "").strip() == safe_item_id:
                    return dict(item)
    for region in reader_regions():
        safe_region_id = str(region.get("id") or "english")
        for surface in ("books", "comics"):
            for item in _reader_catalog_items(safe_region_id, surface=surface):
                if str(item.get("id") or "").strip() == safe_item_id:
                    return item
    return None


def _reader_assert_page_row_budget(current_count: int, incoming: int = 1) -> None:
    next_count = max(0, int(current_count or 0)) + max(0, int(incoming or 0))
    if next_count > VF_READER_UPLOAD_MAX_PAGE_ROWS:
        raise HTTPException(
            status_code=422,
            detail=(
                f"Reader upload exceeds page limit ({VF_READER_UPLOAD_MAX_PAGE_ROWS}). "
                "Split the upload into smaller batches."
            ),
        )


def _reader_assert_ocr_budget(ocr_started_at_sec: float, ocr_images_used: int) -> None:
    used = max(0, int(ocr_images_used or 0))
    if used >= VF_READER_UPLOAD_MAX_OCR_IMAGES:
        raise HTTPException(
            status_code=422,
            detail=(
                f"Reader upload exceeds OCR image budget ({VF_READER_UPLOAD_MAX_OCR_IMAGES}). "
                "Upload fewer pages per request."
            ),
        )
    elapsed_sec = max(0.0, float(time.monotonic() - float(ocr_started_at_sec)))
    if elapsed_sec > VF_READER_UPLOAD_MAX_OCR_SECONDS:
        raise HTTPException(
            status_code=422,
            detail=(
                f"Reader upload exceeded OCR time budget ({VF_READER_UPLOAD_MAX_OCR_SECONDS:.0f}s). "
                "Upload a smaller document."
            ),
        )


def _reader_iter_archive_image_payloads(payload: bytes) -> list[tuple[str, bytes]]:
    safe_payload = bytes(payload or b"")
    if not safe_payload:
        return []
    image_suffixes = (".png", ".jpg", ".jpeg", ".webp")
    try:
        with zipfile.ZipFile(BytesIO(safe_payload), "r") as archive:
            image_infos = [
                info
                for info in archive.infolist()
                if not info.is_dir() and str(info.filename or "").lower().endswith(image_suffixes)
            ]
            if len(image_infos) > VF_READER_UPLOAD_MAX_ARCHIVE_ENTRIES:
                raise HTTPException(
                    status_code=413,
                    detail=(
                        f"Comic archive has too many image entries ({len(image_infos)} > "
                        f"{VF_READER_UPLOAD_MAX_ARCHIVE_ENTRIES})."
                    ),
                )
            image_infos.sort(key=lambda item: str(item.filename or "").lower())
            total_decompressed = 0
            results: list[tuple[str, bytes]] = []
            for info in image_infos:
                entry_name = str(info.filename or "").strip()
                entry_size = max(0, int(info.file_size or 0))
                if entry_size > VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES:
                    raise HTTPException(
                        status_code=413,
                        detail=(
                            f"Comic archive image '{entry_name}' is too large ({entry_size} bytes > "
                            f"{VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES})."
                        ),
                    )
                total_decompressed += entry_size
                if total_decompressed > VF_READER_UPLOAD_MAX_ARCHIVE_DECOMPRESSED_BYTES:
                    raise HTTPException(
                        status_code=413,
                        detail=(
                            "Comic archive is too large after decompression "
                            f"({total_decompressed} bytes > {VF_READER_UPLOAD_MAX_ARCHIVE_DECOMPRESSED_BYTES})."
                        ),
                    )
                try:
                    with archive.open(info, "r") as handle:
                        image_payload = handle.read(VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES + 1)
                except Exception:
                    continue
                if len(image_payload) > VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES:
                    raise HTTPException(
                        status_code=413,
                        detail=(
                            f"Comic archive image '{entry_name}' exceeded read limit "
                            f"({VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES} bytes)."
                        ),
                    )
                results.append((Path(entry_name or "image.png").name, bytes(image_payload)))
            return results
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"Could not read comic archive: {exc}") from exc


def _reader_extract_epub_text(payload: bytes) -> str:
    content = bytes(payload or b"")
    if not content:
        return ""
    try:
        with zipfile.ZipFile(BytesIO(content), "r") as archive:
            infos = [
                info
                for info in archive.infolist()
                if not info.is_dir() and str(info.filename or "").lower().endswith((".xhtml", ".html", ".htm", ".xml"))
            ]
            if len(infos) > VF_READER_UPLOAD_MAX_ARCHIVE_ENTRIES:
                raise HTTPException(
                    status_code=413,
                    detail=(
                        f"EPUB archive has too many text entries ({len(infos)} > "
                        f"{VF_READER_UPLOAD_MAX_ARCHIVE_ENTRIES})."
                    ),
                )
            infos.sort(key=lambda item: str(item.filename or "").lower())
            text_parts: list[str] = []
            total_decompressed = 0
            for info in infos:
                entry_name = str(info.filename or "").strip()
                entry_size = max(0, int(info.file_size or 0))
                if entry_size > VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES:
                    raise HTTPException(
                        status_code=413,
                        detail=(
                            f"EPUB entry '{entry_name}' is too large ({entry_size} bytes > "
                            f"{VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES})."
                        ),
                    )
                total_decompressed += entry_size
                if total_decompressed > VF_READER_UPLOAD_MAX_ARCHIVE_DECOMPRESSED_BYTES:
                    raise HTTPException(
                        status_code=413,
                        detail=(
                            "EPUB archive is too large after decompression "
                            f"({total_decompressed} bytes > {VF_READER_UPLOAD_MAX_ARCHIVE_DECOMPRESSED_BYTES})."
                        ),
                    )
                try:
                    with archive.open(info, "r") as handle:
                        markup_bytes = handle.read(VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES + 1)
                    if len(markup_bytes) > VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES:
                        raise HTTPException(
                            status_code=413,
                            detail=(
                                f"EPUB entry '{entry_name}' exceeded read limit "
                                f"({VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES} bytes)."
                            ),
                        )
                    markup = bytes(markup_bytes).decode("utf-8", errors="replace")
                except HTTPException:
                    raise
                except Exception:
                    continue
                soup = BeautifulSoup(markup, "html.parser")
                chunk = re.sub(r"\s+\n", "\n", soup.get_text("\n", strip=True))
                if chunk.strip():
                    text_parts.append(chunk.strip())
            return "\n\n".join(text_parts).strip()
    except HTTPException:
        raise
    except Exception:
        return ""


def _reader_extract_docx_text(payload: bytes) -> str:
    content = bytes(payload or b"")
    if not content:
        return ""
    try:
        with zipfile.ZipFile(BytesIO(content), "r") as archive:
            entry_name = "word/document.xml"
            if entry_name not in set(archive.namelist()):
                return ""
            info = archive.getinfo(entry_name)
            entry_size = max(0, int(info.file_size or 0))
            if entry_size > VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES:
                raise HTTPException(
                    status_code=413,
                    detail=(
                        f"DOCX document.xml is too large ({entry_size} bytes > "
                        f"{VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES})."
                    ),
                )
            with archive.open(info, "r") as handle:
                xml_bytes = handle.read(VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES + 1)
            if len(xml_bytes) > VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES:
                raise HTTPException(
                    status_code=413,
                    detail=(
                        "DOCX document.xml exceeded read limit "
                        f"({VF_READER_UPLOAD_MAX_ARCHIVE_ENTRY_BYTES} bytes)."
                    ),
                )
    except HTTPException:
        raise
    except Exception:
        return ""

    try:
        root = ET.fromstring(bytes(xml_bytes))
    except Exception:
        return ""
    ns = {"w": "http://schemas.openxmlformats.org/wordprocessingml/2006/main"}
    paragraphs: list[str] = []
    for paragraph in root.findall(".//w:p", ns):
        parts = [str(node.text or "") for node in paragraph.findall(".//w:t", ns) if str(node.text or "").strip()]
        merged = collapse_whitespace("".join(parts))
        if merged:
            paragraphs.append(merged)
    return "\n\n".join(paragraphs).strip()


def _reader_upload_page_rows_from_pdf(pdf_bytes: bytes) -> list[dict[str, Any]]:
    page_rows: list[dict[str, Any]] = []
    extracted, page_stats, likely_scanned = _extract_pdf_text_layer(pdf_bytes)
    normalized_text = _normalize_import_text(extracted)
    if normalized_text:
        cursor = 0
        for page_index, stat in enumerate(list(page_stats or []), start=1):
            chars = max(0, int((stat or {}).get("chars") or 0))
            chunk = normalized_text[cursor:cursor + chars].strip() if chars > 0 else ""
            cursor += chars
            if not chunk:
                continue
            page_rows.append({"page": page_index, "text": chunk})
    if page_rows:
        return page_rows
    fallback_text = ""
    if likely_scanned:
        try:
            fallback_text = _extract_text_with_gemini_fallback(pdf_bytes, "application/pdf", "auto", "reader_pdf")
        except Exception:
            fallback_text = ""
    if not fallback_text:
        fallback_text = _normalize_import_text(extracted)
    if fallback_text:
        return [{"page": 1, "text": fallback_text}]
    return []


def _reader_build_image_page_row(upload_id: str, file_name: str, payload: bytes) -> dict[str, Any]:
    safe_name = _safe_upload_name(file_name, "page.png")
    relative_name = f"images/{safe_name}"
    saved_path = _reader_save_binary_artifact(upload_id, relative_name, payload)
    extracted_text = ""
    mime_type = mimetypes.guess_type(safe_name)[0] or "image/png"
    image_width = 0
    image_height = 0
    if Image is not None:
        try:
            with Image.open(BytesIO(payload)) as image:
                image_width, image_height = image.size
        except Exception:
            image_width = 0
            image_height = 0
    try:
        extracted_text = _extract_text_with_local_ocr(payload)
    except Exception:
        extracted_text = ""
    if not extracted_text:
        try:
            extracted_text = _extract_text_with_gemini_fallback(payload, mime_type, "auto", "reader_image")
        except Exception:
            extracted_text = ""
    return {
        "text": _normalize_import_text(extracted_text) or Path(safe_name).stem.replace("_", " "),
        "imagePath": saved_path,
        "imageWidth": image_width,
        "imageHeight": image_height,
        "aspectRatio": round((image_height / max(1, image_width)), 3) if image_width > 0 and image_height > 0 else 0,
    }


def _reader_detect_upload_content_kind(
    explicit_content_type: object,
    prepared_files: list[dict[str, Any]],
    *,
    title: str = "",
) -> str:
    if str(explicit_content_type or "").strip():
        return normalize_reader_content_kind(explicit_content_type)
    book_score = 0
    comic_score = 0
    for item in list(prepared_files or []):
        suffix = str((item or {}).get("suffix") or "").strip().lower()
        pdf_text_chars = int((item or {}).get("pdfTextChars") or 0)
        pdf_likely_scanned = bool((item or {}).get("pdfLikelyScanned"))
        if suffix in {".txt", ".md", ".epub", ".docx"}:
            book_score += 6
        elif suffix in {".cbz", ".zip", ".png", ".jpg", ".jpeg", ".webp"}:
            comic_score += 6
        elif suffix == ".pdf":
            if pdf_text_chars >= 1200 and not pdf_likely_scanned:
                book_score += 5
            elif pdf_text_chars >= 300:
                book_score += 2
            if pdf_likely_scanned or pdf_text_chars < 450:
                comic_score += 4
    title_haystack = str(title or "").strip().lower()
    if re.search(r"\b(webtoon|manhwa|manga|comic|panel|chapter)\b", title_haystack):
        comic_score += 2
    return "comic" if comic_score > book_score else "book"


def _reader_infer_reading_mode(
    *,
    content_kind: str,
    title: str = "",
    region_id: str = "english",
    direction_hint: str = "",
    provider: str = "",
    source_url: str = "",
    file_names: Optional[list[str]] = None,
    page_rows: Optional[list[dict[str, Any]]] = None,
) -> str:
    safe_content_kind = normalize_reader_content_kind(content_kind)
    if safe_content_kind != "comic":
        return "document"
    if str(direction_hint or "").strip():
        return _reader_direction_to_reading_mode(direction_hint, content_kind=safe_content_kind)
    haystack = " ".join(
        [
            str(title or ""),
            str(provider or ""),
            str(source_url or ""),
            " ".join([str(item) for item in list(file_names or []) if str(item).strip()]),
        ]
    ).lower()
    if re.search(r"\b(webtoon|vertical|scroll|strip|manhwa|toon)\b", haystack):
        return "vertical_strip"
    aspect_ratios = [
        float(item.get("aspectRatio") or 0)
        for item in list(page_rows or [])
        if isinstance(item, dict) and float(item.get("aspectRatio") or 0) > 0
    ]
    tall_pages = len([ratio for ratio in aspect_ratios if ratio >= 2.1])
    if aspect_ratios and tall_pages >= max(1, math.ceil(len(aspect_ratios) * 0.4)):
        return "vertical_strip"
    if re.search(r"\b(manga|shonen|shoujo|seinen|josei|tankobon|right to left|rtl)\b", haystack):
        return "rtl_paged"
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    if safe_region_id == "japanese":
        return "rtl_paged"
    if safe_region_id == "korean":
        return "vertical_strip"
    return "ltr_paged"


def _reader_require_legal_ack(uid: str) -> dict[str, Any]:
    payload = _reader_legal_ack_get(uid)
    if not bool(payload.get("accepted")):
        raise HTTPException(
            status_code=403,
            detail={
                "error": "Reader rights acknowledgement required.",
                "code": "reader_legal_ack_required",
            },
        )
    return payload


def _reader_normalize_upload_item(payload: dict[str, Any]) -> dict[str, Any]:
    safe_payload = dict(payload or {})
    region = reader_region(safe_payload.get("regionId") or "english")
    content_kind = normalize_reader_content_kind(safe_payload.get("contentKind"))
    title = str(safe_payload.get("title") or "Untitled Upload").strip() or "Untitled Upload"
    upload_id = str(safe_payload.get("id") or "").strip()
    source_meta = dict(safe_payload.get("sourceMeta") or {})
    reading_mode_default = str(
        safe_payload.get("readingModeDefault")
        or source_meta.get("readingModeDefault")
        or _reader_infer_reading_mode(
            content_kind=content_kind,
            title=title,
            region_id=str(region.get("id") or "english"),
            direction_hint=str(safe_payload.get("direction") or ""),
            file_names=[str(item) for item in list(safe_payload.get("fileNames") or []) if str(item).strip()],
        )
    )
    stats = dict(source_meta.get("stats") or {})
    source_language = _reader_normalize_language(
        safe_payload.get("sourceLanguage") or source_meta.get("sourceLanguage"),
        default=_reader_normalize_language(region.get("locale"), default="en"),
    ) or "en"
    return {
        "id": upload_id,
        "uid": str(safe_payload.get("uid") or "").strip(),
        "title": title,
        "author": str(safe_payload.get("author") or "You").strip() or "You",
        "surface": "uploads",
        "contentKind": content_kind,
        "regionId": str(region.get("id") or "english"),
        "regionLabel": str(region.get("label") or "English"),
        "provider": "voiceflow_upload",
        "license": "User supplied",
        "ownershipBasis": _reader_normalize_ownership_basis(safe_payload.get("ownershipBasis")),
        "createdAt": str(safe_payload.get("createdAt") or _safe_now_iso()),
        "updatedAt": str(safe_payload.get("updatedAt") or _safe_now_iso()),
        "sourceMeta": source_meta,
        "textPath": str(safe_payload.get("textPath") or "").strip(),
        "manifestPath": str(safe_payload.get("manifestPath") or "").strip(),
        "fileNames": [str(item) for item in list(safe_payload.get("fileNames") or []) if str(item).strip()],
        "direction": normalize_reader_direction(safe_payload.get("direction"), content_kind=content_kind),
        "summary": str(safe_payload.get("summary") or "").strip(),
        "collectionLabel": "Recently imported",
        "readingModeDefault": reading_mode_default,
        "sourceLanguage": source_language,
        "coverUrl": _reader_upload_cover_url(safe_payload),
        "stats": {
            "fileCount": int(stats.get("fileCount") or len(list(safe_payload.get("fileNames") or []))),
            "totalChars": int(stats.get("totalChars") or 0),
            "totalPanels": int(stats.get("totalPanels") or 0),
            "pageCount": int(stats.get("pageCount") or 0),
        },
    }


def _reader_upload_asset_url(upload_id: str, absolute_path: str) -> str:
    safe_upload_id = str(upload_id or "").strip()
    safe_path = str(absolute_path or "").strip()
    if not safe_upload_id or not safe_path:
        return ""
    base_dir = _reader_upload_dir(safe_upload_id).resolve()
    try:
        relative = Path(safe_path).resolve().relative_to(base_dir).as_posix()
    except Exception:
        return ""
    return f"/reader/uploads/{quote(safe_upload_id)}/assets/{quote(relative)}"


def _reader_item_stats(item: dict[str, Any]) -> dict[str, Any]:
    safe_item = dict(item or {})
    safe_content_kind = normalize_reader_content_kind(safe_item.get("contentKind"))
    stats = dict(safe_item.get("stats") or {})
    if safe_content_kind == "book":
        if not int(stats.get("totalChars") or 0):
            stats["totalChars"] = len(str(safe_item.get("sampleText") or ""))
    else:
        if not int(stats.get("totalPanels") or 0):
            stats["totalPanels"] = int(stats.get("pageCount") or 0)
    if not int(stats.get("fileCount") or 0):
        stats["fileCount"] = len(list(safe_item.get("fileNames") or []))
    return {
        "totalChars": int(stats.get("totalChars") or 0),
        "totalPanels": int(stats.get("totalPanels") or 0),
        "pageCount": int(stats.get("pageCount") or stats.get("totalPanels") or 0),
        "fileCount": int(stats.get("fileCount") or 0),
    }


def _commercial_license_token(value: object) -> str:
    raw_value = str(value or "").strip().lower()
    if not raw_value:
        return ""
    if "creativecommons.org/publicdomain/zero/" in raw_value:
        return "cc0-1.0"
    if "creativecommons.org/publicdomain/mark/" in raw_value:
        return "pdm"
    cc_match = re.search(r"creativecommons\.org/licenses/([^/]+)/(\d\.\d)", raw_value)
    if cc_match:
        family = re.sub(r"[^a-z0-9]+", "-", str(cc_match.group(1) or "").strip().lower()).strip("-")
        version = re.sub(r"[^0-9.]+", "", str(cc_match.group(2) or "").strip())
        if family and version:
            return f"cc-{family}-{version}"
        if family:
            return f"cc-{family}"
    if "public domain" in raw_value:
        return "public-domain"
    normalized = re.sub(r"[^a-z0-9]+", "-", raw_value).strip("-")
    return normalized


def _commercial_provider_decision(
    provider: object,
    *,
    license_value: object = "",
    attribution_url: object = "",
) -> tuple[str, Optional[str]]:
    safe_provider = str(provider or "").strip().lower()
    safe_attribution = str(attribution_url or "").strip()
    provider_label = str(provider or "Provider").strip() or "Provider"
    if not VF_COMMERCIAL_MODE:
        return "allowed", None
    if not safe_provider:
        return "blocked", "Provider is missing and denied by strict commercial policy."
    if safe_provider in COMMERCIAL_PROVIDER_ALWAYS_ALLOWED:
        return "allowed", None
    if safe_provider in VF_COMMERCIAL_PROVIDER_ALLOWLIST and safe_provider not in COMMERCIAL_PROVIDER_LICENSE_GATED:
        return "allowed", None
    if safe_provider in COMMERCIAL_PROVIDER_LICENSE_GATED:
        license_token = _commercial_license_token(license_value)
        if not license_token:
            return "review", f"{provider_label} item is missing clear license metadata."
        if VF_COMMERCIAL_LICENSE_ALLOWLIST and license_token not in VF_COMMERCIAL_LICENSE_ALLOWLIST:
            return "blocked", f"{provider_label} license '{license_token}' is not in VF_COMMERCIAL_LICENSE_ALLOWLIST."
        if not safe_attribution:
            return "review", f"{provider_label} item is missing attribution URL metadata."
        return "allowed", None
    if safe_provider in COMMERCIAL_PROVIDER_BLOCKLIST_DEFAULT and safe_provider not in VF_COMMERCIAL_PROVIDER_ALLOWLIST:
        return "blocked", f"Provider '{safe_provider}' is blocked by strict commercial policy."
    if safe_provider in VF_COMMERCIAL_PROVIDER_ALLOWLIST:
        return "allowed", None
    return "blocked", f"Provider '{safe_provider}' is denied by default in strict commercial mode."


def _commercial_annotate_item(item: dict[str, Any]) -> dict[str, Any]:
    safe_item = dict(item or {})
    source_meta = safe_item.get("sourceMeta")
    safe_source_meta = dict(source_meta) if isinstance(source_meta, dict) else {}
    status, reason = _commercial_provider_decision(
        safe_item.get("provider"),
        license_value=safe_item.get("license") or safe_source_meta.get("license"),
        attribution_url=safe_item.get("attributionUrl") or safe_source_meta.get("attributionUrl"),
    )
    safe_item["commercialUseStatus"] = status
    safe_item["commercialUseReason"] = reason if reason else None
    return safe_item


def _reader_is_discovery_item_allowed(item: dict[str, Any]) -> bool:
    safe_item = dict(item or {})
    if str(safe_item.get("surface") or "").strip() == "uploads":
        return True
    if not VF_COMMERCIAL_MODE:
        return True
    return str(safe_item.get("commercialUseStatus") or "").strip().lower() == "allowed"


def _commercial_policy_blocked_providers(items: Optional[list[dict[str, Any]]] = None) -> list[str]:
    if not VF_COMMERCIAL_MODE:
        return []
    blocked = set(COMMERCIAL_PROVIDER_BLOCKLIST_DEFAULT) - set(VF_COMMERCIAL_PROVIDER_ALLOWLIST)
    for item in list(items or []):
        if not isinstance(item, dict):
            continue
        if str(item.get("commercialUseStatus") or "").strip().lower() == "allowed":
            continue
        provider = str(item.get("provider") or "").strip().lower()
        if provider:
            blocked.add(provider)
    return sorted(blocked)


def _commercial_policy_payload(items: Optional[list[dict[str, Any]]] = None) -> dict[str, Any]:
    return {
        "commercialPolicyVersion": COMMERCIAL_POLICY_VERSION,
        "blockedProviders": _commercial_policy_blocked_providers(items),
    }


def _reader_normalize_ownership_basis(raw_value: object, *, raise_on_invalid: bool = False) -> str:
    safe_value = str(raw_value or "").strip().lower() or "user_responsible"
    allowed_values = {str(item.get("value") or "").strip().lower() for item in READER_OWNERSHIP_BASIS_OPTIONS}
    if safe_value in allowed_values:
        return safe_value
    if raise_on_invalid:
        raise HTTPException(
            status_code=400,
            detail=(
                "Invalid ownershipBasis. Use one of: "
                + ", ".join(sorted(value for value in allowed_values if value))
            ),
        )
    return "user_responsible"


def _reader_commercial_payload(items: Optional[list[dict[str, Any]]] = None) -> dict[str, Any]:
    policy_payload = _commercial_policy_payload(items)
    return {
        "enabled": bool(VF_COMMERCIAL_MODE),
        **policy_payload,
        "policyVersion": str(policy_payload.get("commercialPolicyVersion") or "").strip(),
        "ownershipBasisOptions": [dict(item) for item in READER_OWNERSHIP_BASIS_OPTIONS],
    }


def _commercial_assert_allowed_for_action(item: dict[str, Any], *, action: str) -> dict[str, Any]:
    annotated = _commercial_annotate_item(item)
    status = str(annotated.get("commercialUseStatus") or "review").strip().lower()
    if status == "allowed":
        return annotated
    reason = str(annotated.get("commercialUseReason") or "Commercial use blocked by policy.").strip()
    raise HTTPException(
        status_code=403,
        detail={
            "error": reason,
            "code": "commercial_policy_blocked",
            "action": str(action or "use_catalog_item"),
            "provider": str(annotated.get("provider") or "").strip(),
            "commercialUseStatus": status,
        },
    )


def _reader_resume_payload(progress: dict[str, Any], *, session_id: str = "") -> dict[str, Any]:
    safe_progress = dict(progress or {})
    consumed_chars = max(0, int(safe_progress.get("consumedChars") or 0))
    current_panel_index = max(0, int(safe_progress.get("currentPanelIndex") or 0))
    updated_at = str(safe_progress.get("updatedAt") or "").strip()
    updated_at_ms = int(safe_progress.get("updatedAtMs") or 0)
    has_progress = consumed_chars > 0 or current_panel_index > 0
    progress_pct = float(safe_progress.get("progressPct") or 0)
    restore_state = _reader_build_restore_state(
        safe_progress.get("restoreState"),
        active_item_index=int(safe_progress.get("activeItemIndex") or 0),
        active_unit_id=str(safe_progress.get("activeUnitId") or ""),
        viewport_anchor=str(safe_progress.get("viewportAnchor") or ""),
    )
    return {
        "hasProgress": has_progress,
        "consumedChars": consumed_chars,
        "currentPanelIndex": current_panel_index,
        "progressPct": progress_pct,
        "updatedAt": updated_at,
        "updatedAtMs": updated_at_ms,
        "sessionId": str(session_id or "").strip(),
        "restoreState": restore_state,
    }


def _reader_session_active_item_index(session: dict[str, Any]) -> int:
    safe_session = dict(session or {})
    safe_content_kind = normalize_reader_content_kind(safe_session.get("contentKind"))
    if safe_content_kind == "comic":
        total_panels = max(0, int(safe_session.get("totalPanels") or 0))
        return min(max(0, int(safe_session.get("currentPanelIndex") or 0)), max(0, total_panels - 1))
    consumed_chars = max(0, int(safe_session.get("consumedChars") or 0))
    windows = [dict(item) for item in list(safe_session.get("windows") or []) if isinstance(item, dict)]
    for index, item in enumerate(windows):
        if int(item.get("endChar") or 0) > consumed_chars:
            return index
    return max(0, len(windows) - 1)


def _reader_current_restore_state(session: dict[str, Any]) -> dict[str, Any]:
    safe_session = dict(session or {})
    active_item_index = _reader_session_active_item_index(safe_session)
    active_unit_id = str(safe_session.get("activeUnitId") or "").strip()
    viewport_anchor = str(safe_session.get("viewportAnchor") or "").strip()
    return _reader_build_restore_state(
        safe_session.get("restoreState"),
        active_item_index=active_item_index,
        active_unit_id=active_unit_id,
        viewport_anchor=viewport_anchor,
    )


def _reader_apply_restore_state(
    session: dict[str, Any],
    restore_state: object = None,
    *,
    active_item_index: Optional[int] = None,
    active_unit_id: str = "",
    viewport_anchor: str = "",
) -> dict[str, Any]:
    safe_session = dict(session or {})
    current_active_item_index = (
        _reader_session_active_item_index(safe_session)
        if active_item_index is None
        else max(0, int(active_item_index))
    )
    normalized = _reader_build_restore_state(
        restore_state,
        active_item_index=current_active_item_index,
        active_unit_id=active_unit_id or str(safe_session.get("activeUnitId") or ""),
        viewport_anchor=viewport_anchor or str(safe_session.get("viewportAnchor") or ""),
    )
    safe_session["restoreState"] = normalized
    safe_session["activeItemIndex"] = int(normalized.get("activeItemIndex") or 0)
    safe_session["activeUnitId"] = str(normalized.get("activeUnitId") or "")
    safe_session["viewportAnchor"] = str(normalized.get("viewportAnchor") or "")
    return safe_session


def _reader_progress_payload_from_session(session: dict[str, Any]) -> dict[str, Any]:
    safe_session = dict(session or {})
    multi_speaker_enabled = _reader_normalize_multi_speaker_enabled(
        safe_session.get("multiSpeakerEnabled"),
        default=True,
    )
    restore_state = _reader_current_restore_state(safe_session)
    return {
        "consumedChars": int(safe_session.get("consumedChars") or 0),
        "currentPanelIndex": int(safe_session.get("currentPanelIndex") or 0),
        "directionOverride": str(safe_session.get("direction") or ""),
        "readingMode": str(safe_session.get("readingMode") or ""),
        "autoAdvanceProfile": str(safe_session.get("autoAdvanceProfile") or "off"),
        "musicTrackId": str(safe_session.get("musicTrackId") or "m_none"),
        "sourceLanguage": str(safe_session.get("sourceLanguage") or "en"),
        "targetLanguage": str(safe_session.get("targetLanguage") or safe_session.get("sourceLanguage") or "en"),
        "pageViewMode": str(safe_session.get("pageViewMode") or "original"),
        "ttsLanguageMode": str(safe_session.get("ttsLanguageMode") or "auto"),
        "multiSpeakerEnabled": bool(multi_speaker_enabled),
        "voiceMode": _reader_normalize_voice_mode(
            safe_session.get("voiceMode"),
            default="multi" if multi_speaker_enabled else "single",
        ),
        "narratorVoiceId": str((safe_session.get("castMemory") or {}).get("Narrator") or safe_session.get("defaultVoiceId") or "v22"),
        "unitOverrides": _reader_collect_unit_overrides(safe_session),
        "voiceFallbacks": dict(safe_session.get("voiceFallbacks") or {}),
        "audioEngine": _reader_normalize_audio_engine(safe_session.get("audioEngine"), default="tts_hd"),
        "audioEngineStatus": _reader_normalize_audio_engine_status(
            safe_session.get("audioEngineStatus"),
            default="active",
        ),
        "restoreState": restore_state,
        "activeItemIndex": int(restore_state.get("activeItemIndex") or 0),
        "activeUnitId": str(restore_state.get("activeUnitId") or ""),
        "viewportAnchor": str(restore_state.get("viewportAnchor") or ""),
    }


def _reader_session_readiness(session: dict[str, Any]) -> dict[str, Any]:
    safe_session = dict(session or {})
    safe_content_kind = normalize_reader_content_kind(safe_session.get("contentKind"))
    items = safe_session.get("windows") if safe_content_kind == "book" else safe_session.get("panels")
    prep = _reader_normalize_prep(
        safe_session.get("prep"),
        total_items=_reader_session_unit_count(safe_session),
        default_state="ready" if not _reader_is_async_remote_comic_session(safe_session) else "queued",
        default_stage="audio",
    )
    completed = 0
    pending = 0
    total = 0
    for item in list(items or []):
        if not isinstance(item, dict):
            continue
        total += 1
        status = str(
            (item.get("job") or {}).get("status")
            or (item.get("audioJob") or {}).get("status")
            or item.get("status")
            or item.get("audioStatus")
            or ""
        ).strip().lower()
        if status == "completed":
            completed += 1
        elif status in {"queued", "running", "processing", "started"}:
            pending += 1
    if completed > 0:
        return {"state": "ready", "label": f"{completed} playable item{'s' if completed != 1 else ''}", "playableItems": completed}
    if str(prep.get("state") or "") == "error":
        return {
            "state": "blocked",
            "label": "Playback unavailable",
            "playableItems": 0,
            "reason": str(prep.get("message") or "Reader could not prepare a playable item.").strip(),
        }
    if pending > 0 or total > 0 or str(prep.get("state") or "") in {"queued", "running", "degraded", "ready"}:
        return {
            "state": "preparing",
            "label": str(prep.get("message") or "Preparing first playable item").strip() or "Preparing first playable item",
            "playableItems": 0,
        }
    return {"state": "blocked", "label": "Playback unavailable", "playableItems": 0}


def _reader_session_is_reusable(session: dict[str, Any]) -> bool:
    readiness = _reader_session_readiness(session)
    if str(readiness.get("state") or "") in {"ready", "preparing"}:
        return True
    return False


def _reader_find_live_session(uid: str, work_key: str) -> Optional[dict[str, Any]]:
    safe_work_key = str(work_key or "").strip()
    for item in _reader_session_list(uid):
        if str(item.get("workKey") or "").strip() != safe_work_key:
            continue
        refreshed = _reader_refresh_session(item)
        if _reader_session_is_reusable(refreshed):
            saved = _reader_session_set(refreshed)
            return saved
    return None


def _reader_decorate_catalog_item(
    uid: str,
    item: dict[str, Any],
    *,
    progress_lookup: Optional[dict[str, dict[str, Any]]] = None,
    session_lookup: Optional[dict[str, dict[str, Any]]] = None,
) -> dict[str, Any]:
    safe_item = dict(item or {})
    safe_content_kind = normalize_reader_content_kind(safe_item.get("contentKind"))
    safe_surface = normalize_reader_surface(safe_item.get("surface") or ("comics" if safe_content_kind == "comic" else "books"))
    safe_item["title"] = str(safe_item.get("title") or "Untitled").strip() or "Untitled"
    safe_item["author"] = str(safe_item.get("author") or "Unknown").strip() or "Unknown"
    safe_item["summary"] = str(safe_item.get("summary") or safe_item.get("excerpt") or "Open to preview details and launch the player.").strip()
    safe_item["coverUrl"] = str(
        safe_item.get("coverUrl")
        or _reader_fallback_cover_url(content_kind=safe_content_kind, surface=safe_surface)
    ).strip()
    work_key = f"{'upload' if safe_surface == 'uploads' else 'catalog'}:{str(safe_item.get('id') or '').strip()}"
    if isinstance(progress_lookup, dict):
        progress = dict(progress_lookup.get(work_key) or {})
    else:
        progress = dict(_reader_progress_get(uid, work_key))
    if isinstance(session_lookup, dict):
        live_session = dict(session_lookup.get(work_key) or {})
    else:
        live_session = dict(_reader_find_live_session(uid, work_key) or {})
    stats = _reader_item_stats(safe_item)
    resume = _reader_resume_payload(progress, session_id=str(live_session.get("id") or ""))
    if safe_content_kind == "book" and int(stats.get("totalChars") or 0) > 0:
        resume["progressPct"] = round((resume["consumedChars"] / max(1, int(stats["totalChars"]))) * 100, 2)
    elif safe_content_kind == "comic" and int(stats.get("totalPanels") or 0) > 0:
        total_panels = max(1, int(stats["totalPanels"]))
        current_panel_index = max(0, int(resume.get("currentPanelIndex") or 0))
        resume["progressPct"] = round((min(total_panels, current_panel_index + 1) / total_panels) * 100, 2)
    if live_session:
        readiness = _reader_session_readiness(live_session)
        prep = _reader_normalize_prep(
            live_session.get("prep"),
            total_items=_reader_session_unit_count(live_session),
            default_state="ready" if not _reader_is_async_remote_comic_session(live_session) else "queued",
            default_stage="audio",
        )
    else:
        supports_read_here = bool(safe_item.get("supportsReadHere") or safe_surface == "uploads")
        readiness = {
            "state": "ready" if supports_read_here else "blocked",
            "label": "Ready to prepare" if supports_read_here else "Read-here unavailable",
            "playableItems": 0,
        }
        prep = _reader_normalize_prep(
            None,
            total_items=int(stats.get("totalPanels") or stats.get("totalChars") or 0),
            default_state="ready" if supports_read_here else "blocked",
            default_stage="audio",
        )
    provider = str(safe_item.get("provider") or "catalog").strip().lower()
    collection_label = str(safe_item.get("collectionLabel") or "").strip()
    if not collection_label:
        if safe_surface == "uploads":
            collection_label = "Recently imported"
        elif provider == "project_gutenberg":
            collection_label = "Project Gutenberg"
        elif provider == "standard_ebooks":
            collection_label = "Standard Ebooks"
        elif provider == "pepper_carrot":
            collection_label = "Pepper&Carrot"
        elif provider == "gutendex":
            collection_label = "Gutendex"
        elif provider == "wikisource":
            collection_label = "Wikisource"
        elif provider == "openlibrary":
            collection_label = "Open Library"
        elif provider == "google_books":
            collection_label = "Google Books"
        elif provider == "openverse":
            collection_label = "Openverse Comics"
        else:
            collection_label = "Reader Catalog"
    source_language = _reader_normalize_language(
        progress.get("sourceLanguageOverride") or progress.get("sourceLanguage") or safe_item.get("sourceLanguage"),
        default=_reader_normalize_source_language(safe_item, region_id=str(safe_item.get("regionId") or "english")),
    ) or "en"
    reading_mode_default = str(
        safe_item.get("readingModeDefault")
        or _reader_infer_reading_mode(
            content_kind=safe_content_kind,
            title=str(safe_item.get("title") or ""),
            region_id=str(safe_item.get("regionId") or "english"),
            direction_hint=str(safe_item.get("direction") or ""),
            provider=str(safe_item.get("provider") or ""),
            source_url=str(safe_item.get("sourceUrl") or ""),
            file_names=[str(item_name) for item_name in list(safe_item.get("fileNames") or []) if str(item_name).strip()],
        )
    )
    safe_item.update(
        {
            "collectionLabel": collection_label,
            "readingModeDefault": reading_mode_default,
            "resume": resume,
            "sessionId": str(live_session.get("id") or ""),
            "readiness": readiness,
            "prep": prep if isinstance(prep, dict) else _reader_normalize_prep(None, default_state="blocked", default_stage="audio"),
            "stats": stats,
            "sourceLanguage": source_language,
            "languageLabel": _reader_language_label(source_language),
            "translationSupport": {
                "page": bool(safe_item.get("supportsReadHere") or safe_surface == "uploads"),
                "tts": bool(safe_item.get("supportsReadHere") or safe_surface == "uploads"),
            },
        }
    )
    return _commercial_annotate_item(safe_item)


def _reader_build_library_payload(uid: str, *, surface: str = "all", region_id: str = "english", search_query: str = "") -> dict[str, Any]:
    safe_surface = str(surface or "all").strip().lower()
    safe_region_id = str(reader_region(region_id).get("id") or "english")
    if safe_surface not in {"all", "books", "comics", "uploads"}:
        safe_surface = "all"
    safe_search = _reader_search_term(search_query)
    requested_surfaces = {"books", "comics", "uploads"} if safe_surface == "all" else {safe_surface}
    uploads = [_reader_normalize_upload_item(item) for item in _reader_upload_list(uid)]
    books = (
        [normalize_reader_catalog_item(item) for item in _reader_catalog_items(safe_region_id, surface="books", search_query=safe_search)]
        if "books" in requested_surfaces
        else []
    )
    comics = (
        [normalize_reader_catalog_item(item) for item in _reader_catalog_items(safe_region_id, surface="comics", search_query=safe_search)]
        if "comics" in requested_surfaces
        else []
    )
    progress_docs = _reader_progress_list(uid)
    progress_lookup = {
        str(item.get("workKey") or "").strip(): dict(item)
        for item in progress_docs
        if str(item.get("workKey") or "").strip()
    }
    session_lookup: dict[str, dict[str, Any]] = {}
    active_sessions: list[dict[str, Any]] = []
    for item in _reader_session_list(uid):
        refreshed = _reader_refresh_session(item)
        if not _reader_session_is_reusable(refreshed):
            continue
        saved = _reader_session_set(refreshed)
        if _reader_is_async_remote_comic_session(saved) and not _reader_prep_is_terminal(saved.get("prep")):
            _reader_enqueue_remote_comic_hydration(uid, str(saved.get("id") or "").strip())
        work_key = str(saved.get("workKey") or "").strip()
        if work_key and work_key not in session_lookup:
            session_lookup[work_key] = saved
        active_sessions.append(_reader_session_public_view(saved))
    active_sessions.sort(
        key=lambda item: (
            _reader_iso_to_ms(item.get("updatedAtMs") or item.get("updatedAt")),
            _reader_iso_to_ms(item.get("createdAtMs") or item.get("createdAt")),
        ),
        reverse=True,
    )
    all_items_raw = [
        _reader_decorate_catalog_item(uid, item, progress_lookup=progress_lookup, session_lookup=session_lookup)
        for item in [*uploads, *books, *comics]
    ]
    all_items = [item for item in all_items_raw if _reader_is_discovery_item_allowed(item)]
    if safe_surface == "books":
        visible_items = [item for item in all_items if normalize_reader_content_kind(item.get("contentKind")) == "book"]
    elif safe_surface == "comics":
        visible_items = [item for item in all_items if normalize_reader_content_kind(item.get("contentKind")) == "comic"]
    elif safe_surface == "uploads":
        visible_items = [item for item in all_items if str(item.get("surface") or "") == "uploads"]
    else:
        visible_items = list(all_items)
    continue_reading = [
        item for item in all_items
        if bool(((item.get("resume") or {}).get("hasProgress"))) or str(item.get("sessionId") or "").strip()
    ]
    continue_reading.sort(
        key=lambda item: (
            _reader_iso_to_ms(item.get("updatedAtMs") or (item.get("resume") or {}).get("updatedAtMs")),
            _reader_iso_to_ms(item.get("updatedAt") or (item.get("resume") or {}).get("updatedAt")),
            float(((item.get("resume") or {}).get("progressPct") or 0)),
        ),
        reverse=True,
    )
    new_arrivals = sorted(
        all_items,
        key=lambda item: (
            _reader_iso_to_ms(item.get("updatedAtMs") or item.get("updatedAt") or item.get("createdAtMs") or item.get("createdAt")),
            float(((item.get("resume") or {}).get("progressPct") or 0)),
        ),
        reverse=True,
    )
    recently_imported = sorted(
        [item for item in all_items if str(item.get("surface") or "") == "uploads"],
        key=lambda item: str(item.get("createdAt") or ""),
        reverse=True,
    )
    trending = [item for item in all_items if str(item.get("surface") or "") != "uploads"]
    trending.sort(
        key=lambda item: (
            str(item.get("provider") or "") == "pepper_carrot",
            str(item.get("provider") or "") == "standard_ebooks",
            str(item.get("provider") or "") == "project_gutenberg",
            float(((item.get("resume") or {}).get("progressPct") or 0)),
        ),
        reverse=True,
    )
    providers = sorted({str(item.get("provider") or "").strip() for item in visible_items if str(item.get("provider") or "").strip()})
    collections = sorted({str(item.get("collectionLabel") or "").strip() for item in visible_items if str(item.get("collectionLabel") or "").strip()})
    return {
        "surface": safe_surface,
        "regionId": safe_region_id,
        "regions": [dict(region) for region in reader_regions()],
        "items": visible_items,
        "activeSession": active_sessions[0] if active_sessions else None,
        "activeSessions": active_sessions,
        "counts": {
            "all": len(all_items),
            "visible": len(visible_items),
            "books": len(
                [
                    item
                    for item in all_items
                    if (
                        normalize_reader_content_kind(item.get("contentKind")) == "book"
                        if VF_READER_IMPORTS_ONLY
                        else str(item.get("surface") or "") == "books"
                    )
                ]
            ),
            "comics": len(
                [
                    item
                    for item in all_items
                    if (
                        normalize_reader_content_kind(item.get("contentKind")) == "comic"
                        if VF_READER_IMPORTS_ONLY
                        else str(item.get("surface") or "") == "comics"
                    )
                ]
            ),
            "uploads": len([item for item in all_items if str(item.get("surface") or "") == "uploads"]),
            "resumable": len(continue_reading),
        },
        "facets": {
            "providers": providers,
            "collections": collections,
            "progressStates": ["all", "in_progress", "ready", "new"],
        },
        "shelves": {
            "continueReading": continue_reading[:8],
            "trending": trending[:8],
            "newArrivals": new_arrivals[:8],
            "recentlyImported": recently_imported[:8],
        },
        **_commercial_policy_payload(all_items_raw),
    }


def _reader_fetch_text_from_url(url: str) -> str:
    safe_url = str(url or "").strip()
    if not safe_url:
        return ""
    try:
        response = requests.get(
            safe_url,
            headers={
                "User-Agent": _reader_public_user_agent(),
                "Accept": "text/plain,text/html,application/xhtml+xml",
            },
            timeout=(4, 12),
        )
        response.raise_for_status()
    except Exception:
        return ""
    content_type = str(response.headers.get("content-type") or "").lower()
    if "html" in content_type:
        soup = BeautifulSoup(response.text[:2_000_000], "html.parser")
        return collapse_whitespace(soup.get_text("\n", strip=True))
    return response.text.strip()


def _reader_catalog_book_text(item: dict[str, Any]) -> str:
    safe_item = dict(item or {})
    sample_text = str(safe_item.get("sampleText") or "").strip()
    if sample_text:
        return sample_text
    content_url = str(safe_item.get("contentUrl") or "").strip()
    if content_url:
        text = _reader_fetch_text_from_url(content_url)
        if text:
            return text
    source_url = str(safe_item.get("sourceUrl") or "").strip()
    if source_url:
        text = _reader_fetch_text_from_url(source_url)
        if text:
            return text
    return ""


def _reader_default_cast_for_speaker(speaker: str, index: int) -> str:
    safe_speaker = str(speaker or "").strip().lower()
    if safe_speaker in {"narrator", "default"}:
        return "v22"
    rotation = ["v21", "v22", "v3", "v4", "v5", "v6", "v15", "v16"]
    return rotation[max(0, int(index)) % len(rotation)]


def _reader_simple_line_map(text: str, cast_memory: Optional[dict[str, str]] = None) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    safe_text = str(text or "").replace("\r\n", "\n").replace("\r", "\n").strip()
    cast = dict(cast_memory or {})
    line_map: list[dict[str, Any]] = []
    speaker_order: list[str] = []
    for raw_line in safe_text.split("\n"):
        line = raw_line.strip()
        if not line:
            continue
        match = re.match(r"^([A-Za-z][A-Za-z0-9 _.'-]{0,40}):\s+(.+)$", line)
        if not match:
            continue
        speaker = str(match.group(1) or "").strip()
        spoken = str(match.group(2) or "").strip()
        if not speaker or not spoken:
            continue
        if speaker not in speaker_order:
            speaker_order.append(speaker)
        line_map.append({"lineIndex": len(line_map), "speaker": speaker, "text": spoken})
    if not line_map:
        return [], []
    speaker_voices: list[dict[str, Any]] = []
    for index, speaker in enumerate(speaker_order):
        voice_id = str(cast.get(speaker) or _reader_default_cast_for_speaker(speaker, index)).strip()
        cast[speaker] = voice_id
        speaker_voices.append({"speaker": speaker, "voice_id": voice_id})
    return line_map, speaker_voices


def _reader_resolve_multi_speaker_payload(
    session: dict[str, Any],
    *,
    text: str,
    cast_memory: Optional[dict[str, str]],
    default_voice_id: str,
) -> tuple[dict[str, Any], list[dict[str, Any]], list[dict[str, Any]], Optional[str], str]:
    safe_session = dict(session or {})
    next_cast_memory = dict(cast_memory or {})
    if not _reader_normalize_multi_speaker_enabled(safe_session.get("multiSpeakerEnabled"), default=True):
        safe_session["castMemory"] = next_cast_memory
        safe_session["effectiveMultiSpeakerMode"] = "single"
        return safe_session, [], [], None, "single"

    line_map, _ = _reader_simple_line_map(text, next_cast_memory)
    normalized_line_map = normalize_multi_speaker_line_map_shared(line_map)
    if not normalized_line_map:
        safe_session["castMemory"] = next_cast_memory
        safe_session["effectiveMultiSpeakerMode"] = "single"
        return safe_session, [], [], None, "single"

    speaker_order: list[str] = []
    seen_speakers: set[str] = set()
    for item in normalized_line_map:
        speaker_name = str(item.get("speaker") or "").strip()
        speaker_key = speaker_name.lower()
        if not speaker_name or speaker_key in seen_speakers:
            continue
        seen_speakers.add(speaker_key)
        speaker_order.append(speaker_name)

    default_runtime_voice_name = _resolve_gem_runtime_voice_name(default_voice_id or "Fenrir", fallback="Fenrir")
    resolved_speaker_voices: list[dict[str, Any]] = []
    for index, speaker_name in enumerate(speaker_order):
        requested_voice_id = str(
            next_cast_memory.get(speaker_name)
            or _reader_default_cast_for_speaker(speaker_name, index)
            or default_voice_id
        ).strip() or default_voice_id
        safe_session, resolved_voice_id = _reader_resolve_voice_for_session(
            safe_session,
            speaker=speaker_name,
            requested_voice_id=requested_voice_id,
        )
        next_cast_memory[speaker_name] = resolved_voice_id
        resolved_speaker_voices.append(
            {
                "speaker": speaker_name,
                "voice_id": resolved_voice_id,
                "voiceName": _resolve_gem_runtime_voice_name(resolved_voice_id, fallback=default_runtime_voice_name),
            }
        )

    safe_session["castMemory"] = next_cast_memory
    if len(speaker_order) >= 2 and len(normalized_line_map) >= 2:
        safe_session["effectiveMultiSpeakerMode"] = "studio_pair_groups"
        return safe_session, normalized_line_map, resolved_speaker_voices, "studio_pair_groups", "studio_pair_groups"

    safe_session["effectiveMultiSpeakerMode"] = "line_map"
    return safe_session, normalized_line_map, resolved_speaker_voices, "legacy_windows", "line_map"


def _reader_job_status_summary(uid: str, job_id: str) -> dict[str, Any]:
    safe_job_id = str(job_id or "").strip()
    if not safe_job_id:
        return {"status": "idle"}
    try:
        job = _TTS_V2_ENGINE.get_job(uid=uid, is_admin=False, job_id=safe_job_id)
        payload = _TTS_V2_ENGINE.status_payload(job=job, include_result=False, include_chunks=True, include_chunk_audio=False)
        live = payload.get("live") if isinstance(payload.get("live"), dict) else {}
        return {
            "jobId": safe_job_id,
            "status": str(payload.get("status") or "queued"),
            "engine": str(payload.get("engine") or "PRIME"),
            "chunkCursorNext": int(payload.get("chunkCursorNext") or 0),
            "playableChunks": int((live or {}).get("playableChunks") or 0),
            "playableDurationMs": int((live or {}).get("playableDurationMs") or 0),
            "downloadUrl": f"/tts/v2/jobs/{safe_job_id}/result/audio",
        }
    except TtsV2AuthorizationError:
        return {"status": "forbidden", "jobId": safe_job_id}
    except TtsV2JobNotFoundError:
        return {"status": "missing", "jobId": safe_job_id}
    except Exception:
        return {"status": "missing", "jobId": safe_job_id}


def _reader_tts_job_result_audio_bytes(uid: str, job_id: str, *, is_admin: bool) -> Optional[bytes]:
    safe_job_id = str(job_id or "").strip()
    if not safe_job_id:
        return None
    try:
        audio, _ = _TTS_V2_ENGINE.get_result_audio(uid=uid, is_admin=is_admin, job_id=safe_job_id)
        return bytes(audio or b"")
    except Exception:
        return None


def _reader_cancel_tts_job(uid: str, job_id: str, *, is_admin: bool) -> bool:
    safe_job_id = str(job_id or "").strip()
    if not safe_job_id:
        return False
    try:
        _TTS_V2_ENGINE.cancel_job(uid=uid, is_admin=is_admin, job_id=safe_job_id)
        return True
    except Exception:
        return False


def _reader_extract_job_id_from_response(response: Response) -> str:
    if isinstance(response, JSONResponse):
        try:
            payload = json.loads(bytes(response.body or b"{}").decode("utf-8"))
        except Exception:
            payload = {}
        return str(payload.get("jobId") or payload.get("job_id") or payload.get("requestId") or "").strip()
    return ""


def _reader_set_warning_deadline(session: dict[str, Any]) -> dict[str, Any]:
    safe_session = dict(session or {})
    if int(safe_session.get("deleteAtMs") or 0) <= _reader_now_ms():
        safe_session["deleteAtMs"] = _reader_now_ms() + int(READER_SESSION_DELETE_WARNING_MS)
    return safe_session


def _reader_can_cache_more(session: dict[str, Any], additional_chars: int) -> bool:
    safe_cached = max(0, int(dict(session or {}).get("cachedChars") or 0))
    safe_additional = max(0, int(additional_chars or 0))
    return (safe_cached + safe_additional) <= int(READER_SESSION_CACHE_CHAR_LIMIT)


def _reader_purge_cached_audio(session: dict[str, Any]) -> dict[str, Any]:
    safe_session = dict(session or {})
    exported_window_indexes = {int(item) for item in list(safe_session.get("exportedWindowIndexes") or [])}
    purged_chars = 0
    next_windows: list[dict[str, Any]] = []
    for item in list(safe_session.get("windows") or []):
        if not isinstance(item, dict):
            continue
        safe_item = dict(item)
        if safe_item.get("jobId") and int(safe_item.get("index") or 0) not in exported_window_indexes:
            purged_chars += int(safe_item.get("charCount") or 0)
            safe_item["purged"] = True
            safe_item["jobId"] = ""
            safe_item["status"] = "purged"
        next_windows.append(safe_item)
    exported_panel_indexes = {int(item) for item in list(safe_session.get("exportedPanelIndexes") or [])}
    next_panels: list[dict[str, Any]] = []
    for item in list(safe_session.get("panels") or []):
        if not isinstance(item, dict):
            continue
        safe_item = dict(item)
        if safe_item.get("audioJobId") and int(safe_item.get("index") or 0) not in exported_panel_indexes:
            purged_chars += len(str(safe_item.get("text") or ""))
            safe_item["purged"] = True
            safe_item["audioJobId"] = ""
            safe_item["audioStatus"] = "purged"
        next_panels.append(safe_item)
    safe_session["windows"] = next_windows
    safe_session["panels"] = next_panels
    safe_session["cachedChars"] = max(0, int(safe_session.get("cachedChars") or 0) - purged_chars)
    safe_session["deleteAtMs"] = 0
    return safe_session


def _reader_refresh_session(session: dict[str, Any]) -> dict[str, Any]:
    safe_session = dict(session or {})
    safe_session["audioEngine"] = _reader_normalize_audio_engine(
        safe_session.get("audioEngine"),
        default="tts_hd",
    )
    safe_session["audioEngineStatus"] = _reader_normalize_audio_engine_status(
        safe_session.get("audioEngineStatus"),
        default="active",
    )
    delete_at_ms = int(safe_session.get("deleteAtMs") or 0)
    if delete_at_ms > 0 and delete_at_ms <= _reader_now_ms():
        safe_session = _reader_purge_cached_audio(safe_session)
    uid = str(safe_session.get("uid") or "").strip()
    refreshed_windows: list[dict[str, Any]] = []
    scheduled_window_end_char = 0
    for item in list(safe_session.get("windows") or []):
        if not isinstance(item, dict):
            continue
        safe_item = dict(item)
        job_id = str(safe_item.get("jobId") or "").strip()
        if job_id:
            job_summary = _reader_job_status_summary(uid, job_id)
            safe_item["job"] = job_summary
            safe_item["status"] = str(job_summary.get("status") or safe_item.get("status") or "queued")
            scheduled_window_end_char = max(scheduled_window_end_char, int(safe_item.get("endChar") or 0))
        refreshed_windows.append(safe_item)
    refreshed_panels: list[dict[str, Any]] = []
    scheduled_panel_count = 0
    for item in list(safe_session.get("panels") or []):
        if not isinstance(item, dict):
            continue
        safe_item = dict(item)
        job_id = str(safe_item.get("audioJobId") or "").strip()
        if job_id:
            job_summary = _reader_job_status_summary(uid, job_id)
            safe_item["audioJob"] = job_summary
            safe_item["audioStatus"] = str(job_summary.get("status") or safe_item.get("audioStatus") or "queued")
            scheduled_panel_count = max(scheduled_panel_count, int(safe_item.get("index") or 0) + 1)
        refreshed_panels.append(safe_item)
    safe_session["windows"] = refreshed_windows
    safe_session["panels"] = refreshed_panels
    safe_session["scheduledWindowEndChar"] = scheduled_window_end_char
    safe_session["scheduledPanelCount"] = scheduled_panel_count
    active_item_hint = safe_session.get("activeItemIndex")
    if active_item_hint is None:
        active_item_hint = _reader_session_active_item_index(safe_session)
    return _reader_apply_restore_state(
        safe_session,
        safe_session.get("restoreState"),
        active_item_index=int(active_item_hint),
        active_unit_id=str(safe_session.get("activeUnitId") or ""),
        viewport_anchor=str(safe_session.get("viewportAnchor") or ""),
    )


def _reader_public_unit_view(
    unit: dict[str, Any],
    *,
    page_view_mode: str,
    target_language: str,
    content_kind: str,
) -> dict[str, Any]:
    safe_unit = dict(unit or {})
    source_text = _reader_unit_source_text(safe_unit)
    translated_text = str(safe_unit.get("translatedText") or "").strip()
    translated_language = _reader_normalize_language(safe_unit.get("translatedLanguage"))
    if not translated_text and translated_language == target_language:
        translated_text = source_text
    safe_unit["sourceText"] = source_text
    safe_unit["text"] = source_text
    if translated_text:
        safe_unit["translatedText"] = translated_text
    safe_unit["displayText"] = translated_text if page_view_mode == "translated" and translated_text else source_text
    safe_unit["translationStatus"] = str(safe_unit.get("translationStatus") or ("ready" if translated_text and translated_language == target_language else "pending"))
    safe_unit["estimatedReadMs"] = int(safe_unit.get("estimatedReadMs") or _reader_estimated_read_ms(source_text, content_kind=content_kind))
    safe_unit["textOverrideStatus"] = str(
        safe_unit.get("textOverrideStatus")
        or ("edited" if str(safe_unit.get("overrideText") or "").strip() else "none")
    )
    safe_unit["pacing"] = _reader_unit_pacing_meta(safe_unit, content_kind=content_kind)
    return safe_unit


def _reader_session_public_view(session: dict[str, Any]) -> dict[str, Any]:
    safe_session = _reader_warm_translation_units(_reader_refresh_session(session))
    total_chars = int(safe_session.get("totalChars") or 0)
    consumed_chars = max(0, int(safe_session.get("consumedChars") or 0))
    total_panels = int(safe_session.get("totalPanels") or 0)
    current_panel_index = max(0, int(safe_session.get("currentPanelIndex") or 0))
    restore_state = _reader_current_restore_state(safe_session)
    restore_active_item = restore_state.get("activeItemIndex")
    active_item_index = int(_reader_session_active_item_index(safe_session) if restore_active_item is None else restore_active_item)
    readiness = _reader_session_readiness(safe_session)
    prep = _reader_normalize_prep(
        safe_session.get("prep"),
        total_items=_reader_session_unit_count(safe_session),
        default_state="ready" if not _reader_is_async_remote_comic_session(safe_session) else "queued",
        default_stage="audio",
    )
    source_language = _reader_normalize_language(safe_session.get("sourceLanguage"), default="en") or "en"
    target_language = _reader_normalize_language(safe_session.get("targetLanguage"), default=source_language) or source_language
    page_view_mode = _reader_normalize_page_view_mode(
        safe_session.get("pageViewMode"),
        source_language=source_language,
        target_language=target_language,
    )
    safe_content_kind = normalize_reader_content_kind(safe_session.get("contentKind"))
    audio_engine = _reader_normalize_audio_engine(
        safe_session.get("audioEngine"),
        default="native_audio_dialog",
    )
    audio_engine_status = _reader_normalize_audio_engine_status(
        safe_session.get("audioEngineStatus"),
        default="active",
    )
    multi_speaker_enabled = _reader_normalize_multi_speaker_enabled(safe_session.get("multiSpeakerEnabled"), default=True)
    return {
        "id": str(safe_session.get("id") or ""),
        "createdAtMs": int(safe_session.get("createdAtMs") or 0),
        "updatedAtMs": int(safe_session.get("updatedAtMs") or 0),
        "createdAt": str(safe_session.get("createdAt") or ""),
        "updatedAt": str(safe_session.get("updatedAt") or ""),
        "title": str(safe_session.get("title") or "Untitled"),
        "contentKind": str(safe_session.get("contentKind") or "book"),
        "surface": str(safe_session.get("surface") or "books"),
        "regionId": str(safe_session.get("regionId") or "english"),
        "direction": str(safe_session.get("direction") or "vertical-scroll"),
        "readingMode": str(safe_session.get("readingMode") or "document"),
        "workKey": str(safe_session.get("workKey") or ""),
        "sourceKind": str(safe_session.get("sourceKind") or "catalog"),
        "provider": str(safe_session.get("provider") or "catalog"),
        "license": str(safe_session.get("license") or ""),
        "coverUrl": str(safe_session.get("coverUrl") or ""),
        "summary": str(safe_session.get("summary") or ""),
        "sourceUrl": str(safe_session.get("sourceUrl") or ""),
        "collectionLabel": str(safe_session.get("collectionLabel") or ""),
        "sourceLanguage": source_language,
        "targetLanguage": target_language,
        "pageViewMode": page_view_mode,
        "ttsLanguageMode": _reader_normalize_tts_language_mode(safe_session.get("ttsLanguageMode")),
        "audioEngine": audio_engine,
        "audioEngineStatus": audio_engine_status,
        "multiSpeakerEnabled": multi_speaker_enabled,
        "voiceMode": _reader_normalize_voice_mode(
            safe_session.get("voiceMode"),
            default="multi" if multi_speaker_enabled else "single",
        ),
        "narratorVoiceId": str((safe_session.get("castMemory") or {}).get("Narrator") or safe_session.get("defaultVoiceId") or "v22"),
        "effectiveMultiSpeakerMode": str(
            safe_session.get("effectiveMultiSpeakerMode")
            or ("single" if not multi_speaker_enabled else "")
        ),
        "translationState": str(safe_session.get("translationState") or "idle"),
        "translationLeadRatio": float(safe_session.get("translationLeadRatio") or 0.0),
        "voiceFallbacks": dict(safe_session.get("voiceFallbacks") or {}),
        "musicTrackId": str(safe_session.get("musicTrackId") or "m_none"),
        "autoAdvanceProfile": str(safe_session.get("autoAdvanceProfile") or "off"),
        "castMemory": dict(safe_session.get("castMemory") or {}),
        "consumedChars": consumed_chars,
        "totalChars": total_chars,
        "currentPanelIndex": current_panel_index,
        "totalPanels": total_panels,
        "progressPct": (
            round((min(total_panels, current_panel_index + 1) / max(1, total_panels)) * 100, 2)
            if safe_content_kind == "comic" and total_panels > 0
            else round((consumed_chars / total_chars) * 100, 2)
            if total_chars > 0
            else round((min(total_panels, current_panel_index + 1) / max(1, total_panels)) * 100, 2)
        ),
        "cachedChars": int(safe_session.get("cachedChars") or 0),
        "cacheLimitChars": int(READER_SESSION_CACHE_CHAR_LIMIT),
        "deleteAtMs": int(safe_session.get("deleteAtMs") or 0),
        "warningActive": int(safe_session.get("deleteAtMs") or 0) > 0,
        "readiness": readiness,
        "prep": prep,
        "resumeToken": str(safe_session.get("workKey") or ""),
        "activeItemIndex": active_item_index,
        "restoreState": restore_state,
        "savepointDownloadUrl": f"/reader/sessions/{str(safe_session.get('id') or '')}/export",
        "unitOverrides": _reader_collect_unit_overrides(safe_session),
        "stats": {
            "totalChars": total_chars,
            "totalPanels": total_panels,
            "pageCount": total_panels,
            "fileCount": int(((safe_session.get("stats") or {}).get("fileCount") or 0)),
        },
        "billing": {
            "vfPerChar": float(READER_BILLING_VF_PER_CHAR),
            "rule": "1 char = 1.5 VF",
            "label": "Reader pricing: 1 char = 1.5 VF",
            "engine": "PRIME",
            "engineLabel": "Gemini 2.5 Flash TTS" if audio_engine != "native_audio_dialog" else "Gemini 2.5 Native Audio Dialog",
            "modelRouting": {
                "primary": VF_READER_TTS_PRIMARY_MODEL,
                "fallback": VF_READER_TTS_FALLBACK_MODEL,
                "policy": "strict_order",
            },
            "engineRouting": {
                "selected": audio_engine,
                "status": audio_engine_status,
                "tts_hd": {
                    "engine": "PRIME",
                    "label": "Gemini 2.5 Flash TTS",
                    "primaryModel": VF_READER_TTS_PRIMARY_MODEL,
                    "fallbackModel": VF_READER_TTS_FALLBACK_MODEL,
                },
                "native_audio_dialog": {
                    "engine": "PRIME",
                    "label": "Gemini 2.5 Native Audio Dialog",
                    "model": VF_READER_NATIVE_AUDIO_MODEL,
                    "enabled": bool(VF_READER_NATIVE_AUDIO_ENABLED),
                },
            },
        },
        "limits": {
            "textWindowChars": int(READER_TEXT_WINDOW_CHARS),
            "prefetchThresholdChars": int(READER_TEXT_PREFETCH_THRESHOLD_CHARS),
            "panelBatchSize": int(READER_PANEL_BATCH_SIZE),
            "panelTriggerIndex": int(READER_PANEL_PREFETCH_TRIGGER_INDEX),
            "deleteWarningMs": int(READER_SESSION_DELETE_WARNING_MS),
        },
        "windows": [
            _reader_public_unit_view(
                dict(item),
                page_view_mode=page_view_mode,
                target_language=target_language,
                content_kind="book",
            )
            for item in list(safe_session.get("windows") or [])
            if isinstance(item, dict)
        ],
        "panels": [
            _reader_public_unit_view(
                dict(item),
                page_view_mode=page_view_mode,
                target_language=target_language,
                content_kind="comic",
            )
            for item in list(safe_session.get("panels") or [])
            if isinstance(item, dict)
        ],
    }


def _reader_extract_upload_book_text(upload_item: dict[str, Any]) -> str:
    safe_item = _reader_normalize_upload_item(upload_item)
    return _reader_read_text_artifact(str(safe_item.get("textPath") or ""))


def _reader_extract_upload_comic_manifest(upload_item: dict[str, Any]) -> list[dict[str, Any]]:
    safe_item = _reader_normalize_upload_item(upload_item)
    manifest = _reader_read_json_artifact(str(safe_item.get("manifestPath") or ""))
    if not isinstance(manifest, list):
        return []
    upload_id = str(safe_item.get("id") or "").strip()
    out: list[dict[str, Any]] = []
    for item in manifest:
        if not isinstance(item, dict):
            continue
        safe_panel = dict(item)
        image_url = _reader_upload_asset_url(upload_id, str(safe_panel.get("imagePath") or ""))
        if image_url:
            safe_panel["imageUrl"] = image_url
        out.append(safe_panel)
    return out


def _reader_build_remote_image_page_row(
    image_url: str,
    *,
    fallback_text: str,
    page_index: int,
    use_fallback_text: bool = True,
) -> dict[str, Any]:
    safe_url = str(image_url or "").strip()
    if not safe_url:
        return {
            "text": fallback_text if use_fallback_text else "",
            "imageUrl": "",
            "imagePath": "",
            "imageWidth": 0,
            "imageHeight": 0,
            "aspectRatio": 0,
            "hydrationState": "error",
            "message": "Remote image URL is missing.",
        }
    image_payload = b""
    mime_type = mimetypes.guess_type(safe_url)[0] or "image/jpeg"
    try:
        response = requests.get(
            safe_url,
            headers={"User-Agent": _reader_public_user_agent(), "Accept": "image/*"},
            timeout=(4, 20),
        )
        response.raise_for_status()
        image_payload = bytes(response.content or b"")
        mime_type = str(response.headers.get("content-type") or mime_type).split(";", 1)[0].strip() or mime_type
    except Exception:
        return {
            "text": fallback_text if use_fallback_text else "",
            "imageUrl": safe_url,
            "imagePath": "",
            "imageWidth": 0,
            "imageHeight": 0,
            "aspectRatio": 0,
            "hydrationState": "error",
            "message": "Reader could not fetch the remote page image.",
        }

    image_width = 0
    image_height = 0
    if Image is not None:
        try:
            with Image.open(BytesIO(image_payload)) as image:
                image_width, image_height = image.size
        except Exception:
            image_width = 0
            image_height = 0

    extracted_text = ""
    try:
        extracted_text = _extract_text_with_local_ocr(image_payload)
    except Exception:
        extracted_text = ""
    if not extracted_text and page_index < 3:
        try:
            extracted_text = _extract_text_with_gemini_fallback(image_payload, mime_type, "auto", f"reader_remote_image_{page_index + 1}")
        except Exception:
            extracted_text = ""

    cached_path = _reader_cache_remote_asset(safe_url, image_payload, mime_type)
    cached_url = _reader_remote_asset_url(cached_path)
    normalized_text = _normalize_import_text(extracted_text)
    hydration_state = "ready" if normalized_text else "error"
    message = "" if normalized_text else "Reader OCR could not extract text from this page."

    return {
        "text": normalized_text or (fallback_text if use_fallback_text else ""),
        "imageUrl": cached_url or safe_url,
        "imagePath": cached_path,
        "imageWidth": image_width,
        "imageHeight": image_height,
        "aspectRatio": round((image_height / max(1, image_width)), 3) if image_width > 0 and image_height > 0 else 0,
        "hydrationState": hydration_state,
        "message": message,
    }


def _reader_remote_comic_fallback_title(item: dict[str, Any]) -> str:
    safe_item = normalize_reader_catalog_item(item)
    source_meta = dict(safe_item.get("sourceMeta") or {})
    chapter_label = str(source_meta.get("chapterLabel") or "").strip()
    return " ".join(
        token
        for token in [str(safe_item.get("title") or "").strip(), chapter_label]
        if token
    ).strip() or str(safe_item.get("title") or "Reader comic").strip()


def _reader_catalog_comic_page_sources(item: dict[str, Any]) -> list[str]:
    safe_item = normalize_reader_catalog_item(item)
    provider = str(safe_item.get("provider") or "").strip().lower()
    if provider == "voiceflow_admin_catalog":
        source_meta = dict(safe_item.get("sourceMeta") or {})
        panel_manifest = source_meta.get("panelManifest") if isinstance(source_meta.get("panelManifest"), list) else []
        page_sources: list[str] = []
        for row in list(panel_manifest or []):
            if not isinstance(row, dict):
                continue
            image_url = str(row.get("remoteImageUrl") or row.get("imageUrl") or "").strip()
            if not image_url:
                image_path = str(row.get("imagePath") or "").strip()
                if image_path:
                    image_url = _reader_remote_asset_url(image_path)
            if image_url:
                page_sources.append(image_url)
        return page_sources
    if provider == "openverse":
        source_meta = dict(safe_item.get("sourceMeta") or {})
        image_url = (
            str(source_meta.get("imageUrl") or "").strip()
            or str(safe_item.get("contentUrl") or "").strip()
            or str(safe_item.get("coverUrl") or "").strip()
        )
        return [image_url] if image_url else []
    if provider != "pepper_carrot":
        return []
    source_meta = dict(safe_item.get("sourceMeta") or {})
    episode_url = (
        str(source_meta.get("episodeUrl") or "").strip()
        or str(safe_item.get("contentUrl") or "").strip()
        or str(safe_item.get("sourceUrl") or "").strip()
    )
    if not episode_url:
        return []
    try:
        response = requests.get(
            episode_url,
            headers={"User-Agent": _reader_public_user_agent(), "Accept": "text/html,application/xhtml+xml"},
            timeout=(4, 12),
        )
        response.raise_for_status()
    except Exception:
        return []
    soup = BeautifulSoup(response.text[:2_000_000], "html.parser")
    page_sources: list[str] = []
    seen_urls: set[str] = set()
    for image in soup.find_all("img", src=True):
        image_url = urljoin(episode_url, str(image.get("src") or "").strip())
        lower_url = image_url.lower()
        if (
            not image_url
            or image_url in seen_urls
            or "/0_sources/" not in lower_url
            or "pepper-and-carrot" not in lower_url
            or "/low-res/" not in lower_url
            or not lower_url.endswith((".jpg", ".jpeg", ".png", ".webp"))
        ):
            continue
        seen_urls.add(image_url)
        page_sources.append(image_url)
    return page_sources


def _reader_catalog_comic_manifest(item: dict[str, Any]) -> list[dict[str, Any]]:
    safe_item = normalize_reader_catalog_item(item)
    provider = str(safe_item.get("provider") or "").strip().lower()
    if provider == "voiceflow_admin_catalog":
        source_meta = dict(safe_item.get("sourceMeta") or {})
        panel_manifest = source_meta.get("panelManifest") if isinstance(source_meta.get("panelManifest"), list) else []
        if not panel_manifest:
            return []
        direction = _reader_reading_mode_to_direction(
            safe_item.get("readingModeDefault") or safe_item.get("direction"),
            content_kind="comic",
        )
        safe_direction = normalize_reader_direction(direction, content_kind="comic")
        panels: list[dict[str, Any]] = []
        for index, row in enumerate(list(panel_manifest or [])):
            if not isinstance(row, dict):
                continue
            image_url = str(row.get("remoteImageUrl") or row.get("imageUrl") or "").strip()
            if not image_url:
                image_path = str(row.get("imagePath") or "").strip()
                if image_path:
                    image_url = _reader_remote_asset_url(image_path)
            panels.append(
                {
                    "panelId": str(row.get("panelId") or f"panel_{index + 1:04d}"),
                    "pageId": str(row.get("pageId") or f"page_{index + 1:04d}"),
                    "index": index,
                    "direction": safe_direction,
                    "text": str(row.get("text") or row.get("displayText") or row.get("sourceText") or "").strip(),
                    "sourceText": str(row.get("sourceText") or row.get("text") or "").strip(),
                    "displayText": str(row.get("displayText") or row.get("text") or "").strip(),
                    "translatedText": str(row.get("translatedText") or "").strip(),
                    "translatedLanguage": str(row.get("translatedLanguage") or "").strip(),
                    "translationStatus": str(row.get("translationStatus") or "pending").strip() or "pending",
                    "speaker": str(row.get("speaker") or "Narrator").strip() or "Narrator",
                    "emotion": str(row.get("emotion") or "").strip(),
                    "sfx": list(row.get("sfx") or []),
                    "estimatedReadMs": int(row.get("estimatedReadMs") or 0),
                    "imageUrl": image_url,
                    "remoteImageUrl": image_url,
                    "audioJobId": str(row.get("audioJobId") or "").strip(),
                    "audioStatus": str(row.get("audioStatus") or "idle").strip() or "idle",
                    "purged": bool(row.get("purged")),
                    "prepStatus": str(row.get("prepStatus") or "pending").strip() or "pending",
                }
            )
        return panels
    page_sources = _reader_catalog_comic_page_sources(safe_item)
    if not page_sources:
        return []
    direction = _reader_reading_mode_to_direction(
        safe_item.get("readingModeDefault") or safe_item.get("direction"),
        content_kind="comic",
    )
    safe_direction = normalize_reader_direction(direction, content_kind="comic")
    panels: list[dict[str, Any]] = []
    for index, page_url in enumerate(page_sources):
        panels.append(
            {
                "panelId": f"panel_{index + 1:04d}",
                "pageId": f"page_{index + 1:04d}",
                "index": index,
                "direction": safe_direction,
                "text": "",
                "sourceText": "",
                "displayText": "",
                "translatedText": "",
                "translatedLanguage": "",
                "translationStatus": "pending",
                "speaker": "Narrator",
                "emotion": "",
                "sfx": [],
                "estimatedReadMs": 0,
                "imageUrl": page_url,
                "remoteImageUrl": page_url,
                "audioJobId": "",
                "audioStatus": "idle",
                "purged": False,
                "prepStatus": "pending",
            }
        )
    return panels


def _reader_is_async_remote_comic_session(session: dict[str, Any]) -> bool:
    safe_session = dict(session or {})
    if normalize_reader_content_kind(safe_session.get("contentKind")) != "comic":
        return False
    if str(safe_session.get("sourceKind") or "").strip().lower() != "catalog":
        return False
    if str(safe_session.get("provider") or "").strip().lower() not in _READER_ASYNC_REMOTE_COMIC_PROVIDERS:
        return False
    return bool([str(item).strip() for item in list(safe_session.get("remotePageSources") or []) if str(item).strip()])


def _reader_remote_panel_order(total_items: int) -> list[int]:
    safe_total_items = max(0, int(total_items or 0))
    head = list(range(0, min(3, safe_total_items)))
    tail = list(range(min(3, safe_total_items), safe_total_items))
    return [*head, *tail]


def _reader_sync_remote_prep(
    session: dict[str, Any],
    *,
    stage: Optional[str] = None,
    state_override: Optional[str] = None,
    message: Optional[str] = None,
) -> dict[str, Any]:
    safe_session = dict(session or {})
    if not _reader_is_async_remote_comic_session(safe_session):
        return safe_session
    panels = [dict(item) for item in list(safe_session.get("panels") or []) if isinstance(item, dict)]
    total_items = max(len(panels), len([str(item).strip() for item in list(safe_session.get("remotePageSources") or []) if str(item).strip()]))
    completed_items = len([item for item in panels if str(item.get("prepStatus") or "").strip().lower() == "ready"])
    failed_items = len([item for item in panels if str(item.get("prepStatus") or "").strip().lower() == "error"])
    prep = _reader_normalize_prep(
        safe_session.get("prep"),
        total_items=total_items,
        default_state="queued",
        default_stage="manifest",
    )
    if stage:
        prep["stage"] = str(stage or "manifest").strip().lower() or "manifest"
    if state_override:
        prep["state"] = str(state_override or prep.get("state") or "queued").strip().lower() or "queued"
    else:
        remaining_items = max(0, total_items - completed_items - failed_items)
        if remaining_items > 0:
            prep["state"] = "queued" if str(prep.get("state") or "") == "queued" and completed_items <= 0 and failed_items <= 0 else "running"
        elif total_items <= 0:
            prep["state"] = "error"
        elif completed_items <= 0 and failed_items >= total_items:
            prep["state"] = "error"
        elif failed_items > 0:
            prep["state"] = "degraded"
        else:
            prep["state"] = "ready"
    prep["completedItems"] = completed_items
    prep["failedItems"] = failed_items
    prep["totalItems"] = total_items
    if message is not None:
        safe_message = str(message or "").strip()
        if safe_message:
            prep["message"] = safe_message
        else:
            prep.pop("message", None)
    elif failed_items > 0 and prep["state"] in {"running", "degraded"}:
        prep["message"] = (
            f"{failed_items} page{'s' if failed_items != 1 else ''} failed during remote preparation."
            if prep["state"] == "degraded"
            else f"{failed_items} page{'s' if failed_items != 1 else ''} failed so far; continuing."
        )
    elif prep["state"] == "queued":
        prep["message"] = "Queued remote comic preparation."
    elif prep["state"] == "running":
        prep["message"] = "Hydrating remote comic pages."
    elif prep["state"] == "ready":
        prep["message"] = "Remote comic pages are hydrated."
    elif prep["state"] == "error":
        prep["message"] = "Remote comic preparation failed."
    safe_session["prep"] = prep
    return safe_session


def _reader_schedule_hydrated_remote_panels(session: dict[str, Any], uid: str) -> dict[str, Any]:
    safe_session = dict(session or {})
    if not _reader_is_async_remote_comic_session(safe_session):
        return safe_session
    try:
        next_session = _reader_schedule_panel_batch(safe_session, _reader_internal_request(uid))
    except Exception:
        return safe_session
    panels = [dict(item) for item in list(next_session.get("panels") or []) if isinstance(item, dict)]
    for index, item in enumerate(panels):
        if str(item.get("prepStatus") or "").strip().lower() == "pending" and str(item.get("text") or item.get("sourceText") or "").strip():
            if str(item.get("audioJobId") or "").strip():
                item["prepStatus"] = "ready"
                panels[index] = item
    next_session["panels"] = panels
    return next_session


def _reader_hydrate_remote_comic_session(uid: str, session_id: str) -> None:
    try:
        session = _reader_session_get(uid, session_id)
        if not session or not _reader_is_async_remote_comic_session(session):
            return
        session = _reader_sync_remote_prep(session, stage="assets", state_override="running")
        session = _reader_session_set(session)
        page_sources = [str(item).strip() for item in list(session.get("remotePageSources") or []) if str(item).strip()]
        fallback_title = str(session.get("remoteFallbackTitle") or session.get("title") or "Reader comic").strip() or "Reader comic"
        for page_index in _reader_remote_panel_order(len(page_sources)):
            current = _reader_session_get(uid, session_id)
            if not current or not _reader_is_async_remote_comic_session(current):
                return
            panels = [dict(item) for item in list(current.get("panels") or []) if isinstance(item, dict)]
            if page_index >= len(panels):
                continue
            panel = dict(panels[page_index] or {})
            if str(panel.get("prepStatus") or "").strip().lower() in {"ready", "error"}:
                continue
            page_url = page_sources[page_index]
            panel_text = collapse_whitespace(panel.get("sourceText") or panel.get("text") or "")
            has_local_asset = bool(str(panel.get("imagePath") or "").strip()) or str(panel.get("imageUrl") or "").strip().startswith("/reader/assets/")
            if panel_text and has_local_asset:
                panel["prepStatus"] = "ready"
                panels[page_index] = panel
                current["panels"] = panels
                current = _reader_sync_remote_prep(current, stage="audio")
                current = _reader_schedule_hydrated_remote_panels(current, uid)
                _reader_session_set(_reader_sync_remote_prep(current))
                continue

            hydrated = _reader_build_remote_image_page_row(
                page_url,
                fallback_text=f"{fallback_title} page {page_index + 1}",
                page_index=page_index,
                use_fallback_text=False,
            )
            current = _reader_session_get(uid, session_id)
            if not current or not _reader_is_async_remote_comic_session(current):
                return
            panels = [dict(item) for item in list(current.get("panels") or []) if isinstance(item, dict)]
            if page_index >= len(panels):
                continue
            panel = dict(panels[page_index] or {})
            if str(hydrated.get("imageUrl") or "").strip():
                panel["imageUrl"] = str(hydrated.get("imageUrl") or "").strip()
            if str(hydrated.get("imagePath") or "").strip():
                panel["imagePath"] = str(hydrated.get("imagePath") or "").strip()
            panel["remoteImageUrl"] = page_url
            panel["imageWidth"] = int(hydrated.get("imageWidth") or 0)
            panel["imageHeight"] = int(hydrated.get("imageHeight") or 0)
            panel["aspectRatio"] = float(hydrated.get("aspectRatio") or 0)
            hydrated_text = collapse_whitespace(hydrated.get("text") or "")
            if str(hydrated.get("hydrationState") or "").strip().lower() != "ready" or not hydrated_text:
                panel["text"] = ""
                panel["sourceText"] = ""
                panel["displayText"] = ""
                panel["translationStatus"] = "error"
                panel["audioStatus"] = "error"
                panel["prepStatus"] = "error"
                panel["prepMessage"] = str(hydrated.get("message") or "Reader could not hydrate this remote page.").strip()
                panels[page_index] = panel
                current["panels"] = panels
                _reader_session_set(_reader_sync_remote_prep(current, stage="ocr"))
                continue
            panel["text"] = hydrated_text
            panel["sourceText"] = hydrated_text
            panel["displayText"] = hydrated_text
            panel["translationStatus"] = "pending"
            panel["speaker"] = str(panel.get("speaker") or "Narrator").strip() or "Narrator"
            panel["emotion"] = guess_panel_emotion(hydrated_text)
            panel["sfx"] = guess_panel_sfx(hydrated_text)
            panel["estimatedReadMs"] = int(panel.get("estimatedReadMs") or _reader_estimated_read_ms(hydrated_text, content_kind="comic"))
            panel["prepStatus"] = "ready"
            panel.pop("prepMessage", None)
            panels[page_index] = panel
            current["panels"] = panels
            current = _reader_sync_remote_prep(current, stage="audio")
            current = _reader_schedule_hydrated_remote_panels(current, uid)
            _reader_session_set(_reader_sync_remote_prep(current))
        current = _reader_session_get(uid, session_id)
        if current and _reader_is_async_remote_comic_session(current):
            _reader_session_set(_reader_sync_remote_prep(current, stage="audio"))
    finally:
        with _READER_HYDRATION_LOCK:
            _READER_HYDRATION_ACTIVE.discard(str(session_id or "").strip())


def _reader_enqueue_remote_comic_hydration(uid: str, session_id: str) -> None:
    safe_session_id = str(session_id or "").strip()
    if not safe_session_id:
        return
    with _READER_HYDRATION_LOCK:
        if safe_session_id in _READER_HYDRATION_ACTIVE:
            return
        _READER_HYDRATION_ACTIVE.add(safe_session_id)
    thread = threading.Thread(
        target=_reader_hydrate_remote_comic_session,
        args=(str(uid or "").strip(), safe_session_id),
        name=f"reader-hydration-{safe_session_id[:12]}",
        daemon=True,
    )
    thread.start()


def _reader_resume_remote_comic_hydration_jobs() -> None:
    with _INMEMORY_LOCK:
        sessions = [dict(item) for item in _INMEMORY_READER_SESSIONS.values()]
    for session in sessions:
        safe_session = dict(session or {})
        if not _reader_is_async_remote_comic_session(safe_session):
            continue
        prep = _reader_normalize_prep(
            safe_session.get("prep"),
            total_items=_reader_session_unit_count(safe_session),
            default_state="queued",
            default_stage="manifest",
        )
        if _reader_prep_is_terminal(prep):
            continue
        _reader_enqueue_remote_comic_hydration(str(safe_session.get("uid") or "").strip(), str(safe_session.get("id") or "").strip())


def _reader_register_voice_fallback(
    session: dict[str, Any],
    *,
    speaker: str,
    fallback: Optional[dict[str, str]],
) -> dict[str, Any]:
    safe_session = dict(session or {})
    voice_fallbacks = dict(safe_session.get("voiceFallbacks") or {})
    safe_speaker = str(speaker or "Narrator").strip() or "Narrator"
    if fallback:
        voice_fallbacks[safe_speaker] = dict(fallback)
    else:
        voice_fallbacks.pop(safe_speaker, None)
    safe_session["voiceFallbacks"] = voice_fallbacks
    return safe_session


def _reader_resolve_voice_for_session(
    session: dict[str, Any],
    *,
    speaker: str,
    requested_voice_id: str,
) -> tuple[dict[str, Any], str]:
    safe_session = dict(session or {})
    resolved_voice_id, fallback = _reader_resolve_voice_choice(
        requested_voice_id,
        _reader_normalize_language(safe_session.get("targetLanguage"), default="en"),
    )
    safe_session = _reader_register_voice_fallback(safe_session, speaker=speaker, fallback=fallback)
    return safe_session, resolved_voice_id


def _reader_tts_text_for_unit(session: dict[str, Any], unit: dict[str, Any]) -> str:
    source_text = _reader_unit_source_text(unit)
    if _reader_effective_tts_language_mode(session) != "target":
        return source_text
    target_language = _reader_normalize_language(session.get("targetLanguage"), default="")
    translated_language = _reader_normalize_language(unit.get("translatedLanguage"), default="")
    translated_text = str(unit.get("translatedText") or "").strip()
    if translated_text and target_language and translated_language == target_language:
        return translated_text
    return source_text


def _reader_tts_model_route(audio_engine: str) -> tuple[str, list[str]]:
    safe_engine = _reader_normalize_audio_engine(audio_engine, default="tts_hd")
    if safe_engine == "native_audio_dialog":
        model = str(VF_READER_NATIVE_AUDIO_MODEL or "").strip() or "gemini-2.5-flash-native-audio-dialog"
        return model, [model]
    model_candidates = list(
        dict.fromkeys(
            str(model).strip()
            for model in [VF_READER_TTS_PRIMARY_MODEL, VF_READER_TTS_FALLBACK_MODEL]
            if str(model).strip()
        )
    )
    if not model_candidates:
        model_candidates = ["gemini-2.5-flash"]
    return model_candidates[0], model_candidates


def _reader_create_tts_job(
    request: Request,
    *,
    session: dict[str, Any],
    text: str,
    request_id: str,
    voice_id: str,
    language: str,
    multi_speaker_mode: Optional[str] = None,
    line_map: Optional[list[dict[str, Any]]] = None,
    speaker_voices: Optional[list[dict[str, Any]]] = None,
    route_audio_engine: Optional[str] = None,
) -> str:
    model, model_candidates = _reader_tts_model_route(
        route_audio_engine or str(session.get("audioEngine") or "tts_hd")
    )
    live_chunk_profile = _resolve_live_chunk_profile()
    speaker_voice_rows = [dict(item) for item in list(speaker_voices or []) if isinstance(item, dict)]
    inferred_mode = "multi_speaker" if len(speaker_voice_rows) >= 6 else "single_speaker"
    payload = {
        "engine": "VECTOR",
        "mode": inferred_mode,
        "text": str(text or "").strip(),
        "model": model,
        "modelCandidates": model_candidates,
        "voiceName": str(voice_id or "").strip() or None,
        "voiceId": str(voice_id or "v21").strip() or "v21",
        "voice_id": str(voice_id or "v21").strip() or "v21",
        "language": str(language or "en").strip() or "en",
        "request_id": request_id,
        "stream": True,
        "live_chunk_chars": int(live_chunk_profile["chunkChars"]),
        "live_chunk_words": int(live_chunk_profile["chunkWords"]),
        "multi_speaker_mode": multi_speaker_mode,
        "multi_speaker_line_map": line_map or None,
        "speaker_voices": speaker_voice_rows or None,
    }
    response = _create_tts_v2_job_response(request, payload, require_session=False)
    job_id = _reader_extract_job_id_from_response(response)
    if not job_id:
        raise HTTPException(status_code=502, detail="Failed to queue Reader TTS job.")
    return job_id


def _reader_create_tts_job_routed(
    request: Request,
    *,
    session: dict[str, Any],
    text: str,
    request_id: str,
    voice_id: str,
    language: str,
    multi_speaker_mode: Optional[str] = None,
    line_map: Optional[list[dict[str, Any]]] = None,
    speaker_voices: Optional[list[dict[str, Any]]] = None,
    route_audio_engine: Optional[str] = None,
) -> str:
    kwargs: dict[str, Any] = {
        "session": session,
        "text": text,
        "request_id": request_id,
        "voice_id": voice_id,
        "language": language,
        "multi_speaker_mode": multi_speaker_mode,
        "line_map": line_map,
        "speaker_voices": speaker_voices,
    }
    if route_audio_engine is not None:
        try:
            return _reader_create_tts_job(
                request,
                **kwargs,
                route_audio_engine=route_audio_engine,
            )
        except TypeError as exc:
            if "route_audio_engine" not in str(exc):
                raise
    return _reader_create_tts_job(request, **kwargs)


def _reader_create_tts_job_with_audio_engine_fallback(
    request: Request,
    *,
    session: dict[str, Any],
    text: str,
    request_id: str,
    voice_id: str,
    language: str,
    multi_speaker_mode: Optional[str] = None,
    line_map: Optional[list[dict[str, Any]]] = None,
    speaker_voices: Optional[list[dict[str, Any]]] = None,
) -> tuple[dict[str, Any], str, str]:
    safe_session = dict(session or {})
    preferred_engine = _reader_normalize_audio_engine(
        safe_session.get("audioEngine"),
        default="tts_hd",
    )
    route_engine = preferred_engine
    if route_engine == "native_audio_dialog" and not VF_READER_NATIVE_AUDIO_ENABLED:
        route_engine = "tts_hd"
        safe_session["audioEngineStatus"] = "unavailable"
    try:
        job_id = _reader_create_tts_job_routed(
            request,
            session=safe_session,
            text=text,
            request_id=request_id,
            voice_id=voice_id,
            language=language,
            multi_speaker_mode=multi_speaker_mode,
            line_map=line_map,
            speaker_voices=speaker_voices,
            route_audio_engine=route_engine,
        )
        if route_engine != "native_audio_dialog":
            safe_session["audioEngineStatus"] = _reader_normalize_audio_engine_status(
                safe_session.get("audioEngineStatus"),
                default="active",
            )
        else:
            safe_session["audioEngineStatus"] = "active"
        return safe_session, job_id, route_engine
    except Exception:
        if route_engine != "native_audio_dialog":
            raise
        fallback_job_id = _reader_create_tts_job_routed(
            request,
            session=safe_session,
            text=text,
            request_id=request_id,
            voice_id=voice_id,
            language=language,
            multi_speaker_mode=multi_speaker_mode,
            line_map=line_map,
            speaker_voices=speaker_voices,
            route_audio_engine="tts_hd",
        )
        safe_session["audioEngineStatus"] = "fallback_to_tts"
        return safe_session, fallback_job_id, "tts_hd"


def _reader_schedule_text_window(session: dict[str, Any], request: Request) -> dict[str, Any]:
    safe_session = _reader_warm_translation_units(session)
    windows = [dict(item) for item in list(safe_session.get("windows") or []) if isinstance(item, dict)]
    cast_memory = dict(safe_session.get("castMemory") or {})
    safe_session, default_voice_id = _reader_resolve_voice_for_session(
        safe_session,
        speaker="Narrator",
        requested_voice_id=str(cast_memory.get("Narrator") or safe_session.get("defaultVoiceId") or "v22"),
    )
    tts_language = (
        _reader_normalize_language(safe_session.get("targetLanguage"), default="en")
        if _reader_effective_tts_language_mode(safe_session) == "target"
        else _reader_normalize_language(safe_session.get("sourceLanguage"), default="en")
    ) or "en"
    for index, item in enumerate(windows):
        if str(item.get("jobId") or "").strip() or bool(item.get("purged")):
            continue
        tts_text = _reader_tts_text_for_unit(safe_session, item)
        char_count = len(tts_text)
        if not _reader_can_cache_more(safe_session, char_count):
            safe_session = _reader_set_warning_deadline(safe_session)
            break
        safe_session, line_map, resolved_speaker_voices, multi_speaker_mode, _ = _reader_resolve_multi_speaker_payload(
            safe_session,
            text=tts_text,
            cast_memory=cast_memory,
            default_voice_id=default_voice_id,
        )
        cast_memory = dict(safe_session.get("castMemory") or {})
        safe_session, job_id, routed_engine = _reader_create_tts_job_with_audio_engine_fallback(
            request,
            session=safe_session,
            text=tts_text,
            request_id=f"{str(safe_session.get('id') or 'reader')}_window_{index}",
            voice_id=default_voice_id,
            language=tts_language,
            multi_speaker_mode=multi_speaker_mode,
            line_map=line_map or None,
            speaker_voices=resolved_speaker_voices or None,
        )
        item["jobId"] = job_id
        item["status"] = "queued"
        item["audioEngine"] = routed_engine
        if routed_engine == "tts_hd" and _reader_normalize_audio_engine(safe_session.get("audioEngine"), default="tts_hd") == "native_audio_dialog":
            item["fallbackFromNativeAudio"] = True
        windows[index] = item
        safe_session["windows"] = windows
        safe_session["cachedChars"] = int(safe_session.get("cachedChars") or 0) + char_count
        safe_session["castMemory"] = cast_memory
        break
    return safe_session


def _reader_schedule_panel_batch(session: dict[str, Any], request: Request) -> dict[str, Any]:
    safe_session = _reader_warm_translation_units(session)
    panels = [dict(item) for item in list(safe_session.get("panels") or []) if isinstance(item, dict)]
    cast_memory = dict(safe_session.get("castMemory") or {})
    safe_session, default_voice_id = _reader_resolve_voice_for_session(
        safe_session,
        speaker="Narrator",
        requested_voice_id=str(cast_memory.get("Narrator") or safe_session.get("defaultVoiceId") or "v22"),
    )
    tts_language = (
        _reader_normalize_language(safe_session.get("targetLanguage"), default="en")
        if _reader_effective_tts_language_mode(safe_session) == "target"
        else _reader_normalize_language(safe_session.get("sourceLanguage"), default="en")
    ) or "en"
    scheduled = 0
    for index, item in enumerate(panels):
        if scheduled >= int(READER_PANEL_BATCH_SIZE):
            break
        if str(item.get("audioJobId") or "").strip() or bool(item.get("purged")):
            continue
        tts_text = _reader_tts_text_for_unit(safe_session, item)
        if not str(tts_text or "").strip():
            continue
        if str(item.get("prepStatus") or "").strip().lower() == "error":
            continue
        char_count = len(tts_text)
        if not _reader_can_cache_more(safe_session, char_count):
            safe_session = _reader_set_warning_deadline(safe_session)
            break
        safe_session, line_map, resolved_speaker_voices, multi_speaker_mode, _ = _reader_resolve_multi_speaker_payload(
            safe_session,
            text=tts_text,
            cast_memory=cast_memory,
            default_voice_id=default_voice_id,
        )
        cast_memory = dict(safe_session.get("castMemory") or {})
        safe_session, job_id, routed_engine = _reader_create_tts_job_with_audio_engine_fallback(
            request,
            session=safe_session,
            text=tts_text,
            request_id=f"{str(safe_session.get('id') or 'reader')}_panel_{index}",
            voice_id=default_voice_id,
            language=tts_language,
            multi_speaker_mode=multi_speaker_mode,
            line_map=line_map or None,
            speaker_voices=resolved_speaker_voices or None,
        )
        item["audioJobId"] = job_id
        item["audioStatus"] = "queued"
        item["audioEngine"] = routed_engine
        if routed_engine == "tts_hd" and _reader_normalize_audio_engine(safe_session.get("audioEngine"), default="tts_hd") == "native_audio_dialog":
            item["fallbackFromNativeAudio"] = True
        panels[index] = item
        safe_session["cachedChars"] = int(safe_session.get("cachedChars") or 0) + char_count
        scheduled += 1
    safe_session["panels"] = panels
    return safe_session


def _reader_recover_failed_native_jobs(session: dict[str, Any], request: Request) -> dict[str, Any]:
    safe_session = _reader_refresh_session(session)
    if _reader_normalize_audio_engine(safe_session.get("audioEngine"), default="tts_hd") != "native_audio_dialog":
        return safe_session

    cast_memory = dict(safe_session.get("castMemory") or {})
    safe_session, default_voice_id = _reader_resolve_voice_for_session(
        safe_session,
        speaker="Narrator",
        requested_voice_id=str(cast_memory.get("Narrator") or safe_session.get("defaultVoiceId") or "v22"),
    )
    tts_language = (
        _reader_normalize_language(safe_session.get("targetLanguage"), default="en")
        if _reader_effective_tts_language_mode(safe_session) == "target"
        else _reader_normalize_language(safe_session.get("sourceLanguage"), default="en")
    ) or "en"

    windows = [dict(item) for item in list(safe_session.get("windows") or []) if isinstance(item, dict)]
    panels = [dict(item) for item in list(safe_session.get("panels") or []) if isinstance(item, dict)]

    recovered_any = False

    for index, item in enumerate(windows):
        status = str((item.get("job") or {}).get("status") or item.get("status") or "").strip().lower()
        if status not in {"failed", "error"}:
            continue
        if bool(item.get("fallbackFromNativeAudio")):
            continue
        item_engine = _reader_normalize_audio_engine(
            item.get("audioEngine"),
            default=str(safe_session.get("audioEngine") or "tts_hd"),
        )
        if item_engine != "native_audio_dialog":
            continue
        tts_text = _reader_tts_text_for_unit(safe_session, item)
        if not str(tts_text or "").strip():
            continue
        safe_session, line_map, resolved_speaker_voices, multi_speaker_mode, _ = _reader_resolve_multi_speaker_payload(
            safe_session,
            text=tts_text,
            cast_memory=cast_memory,
            default_voice_id=default_voice_id,
        )
        cast_memory = dict(safe_session.get("castMemory") or {})
        try:
            fallback_job_id = _reader_create_tts_job_routed(
                request,
                session=safe_session,
                text=tts_text,
                request_id=f"{str(safe_session.get('id') or 'reader')}_window_{index}_fallback",
                voice_id=default_voice_id,
                language=tts_language,
                multi_speaker_mode=multi_speaker_mode,
                line_map=line_map or None,
                speaker_voices=resolved_speaker_voices or None,
                route_audio_engine="tts_hd",
            )
        except Exception:
            safe_session["audioEngineStatus"] = "unavailable"
            continue
        item["fallbackFromNativeAudio"] = True
        item["fallbackFromJobId"] = str(item.get("jobId") or "")
        item["jobId"] = fallback_job_id
        item["status"] = "queued"
        item["audioEngine"] = "tts_hd"
        windows[index] = item
        recovered_any = True

    for index, item in enumerate(panels):
        status = str((item.get("audioJob") or {}).get("status") or item.get("audioStatus") or "").strip().lower()
        if status not in {"failed", "error"}:
            continue
        if bool(item.get("fallbackFromNativeAudio")):
            continue
        item_engine = _reader_normalize_audio_engine(
            item.get("audioEngine"),
            default=str(safe_session.get("audioEngine") or "tts_hd"),
        )
        if item_engine != "native_audio_dialog":
            continue
        tts_text = _reader_tts_text_for_unit(safe_session, item)
        if not str(tts_text or "").strip():
            continue
        safe_session, line_map, resolved_speaker_voices, multi_speaker_mode, _ = _reader_resolve_multi_speaker_payload(
            safe_session,
            text=tts_text,
            cast_memory=cast_memory,
            default_voice_id=default_voice_id,
        )
        cast_memory = dict(safe_session.get("castMemory") or {})
        try:
            fallback_job_id = _reader_create_tts_job_routed(
                request,
                session=safe_session,
                text=tts_text,
                request_id=f"{str(safe_session.get('id') or 'reader')}_panel_{index}_fallback",
                voice_id=default_voice_id,
                language=tts_language,
                multi_speaker_mode=multi_speaker_mode,
                line_map=line_map or None,
                speaker_voices=resolved_speaker_voices or None,
                route_audio_engine="tts_hd",
            )
        except Exception:
            safe_session["audioEngineStatus"] = "unavailable"
            continue
        item["fallbackFromNativeAudio"] = True
        item["fallbackFromJobId"] = str(item.get("audioJobId") or "")
        item["audioJobId"] = fallback_job_id
        item["audioStatus"] = "queued"
        item["audioEngine"] = "tts_hd"
        panels[index] = item
        recovered_any = True

    if recovered_any:
        safe_session["windows"] = windows
        safe_session["panels"] = panels
        safe_session["audioEngineStatus"] = "fallback_to_tts"
    safe_session["castMemory"] = cast_memory
    return safe_session


