@app.post("/admin/reader/catalog/items")
async def admin_reader_catalog_create(
    request: Request,
    files: List[UploadFile] = File(...),
    title: str = Form(""),
    author: str = Form(""),
    contentType: str = Form("novel"),
    ownershipBasis: str = Form("licensed"),
    regionId: str = Form("english"),
    license: str = Form(""),
    summary: str = Form(""),
    collectionLabel: str = Form("Reader Library"),
    directionOverride: str = Form(""),
    publishState: str = Form("published"),
) -> JSONResponse:
    admin_uid, actor = _require_permission(request, PERM_OPS_MUTATE)
    _require_admin_mutation_unlock(request, expected_uid=admin_uid)
    safe_content_kind = normalize_reader_content_kind("comic" if str(contentType or "").strip().lower() == "manga" else contentType)
    safe_region_id = str(reader_region(regionId).get("id") or "english")
    safe_ownership_basis = _reader_normalize_ownership_basis(ownershipBasis, raise_on_invalid=False)
    safe_publish_state = _reader_admin_catalog_publish_state(publishState)
    safe_title = str(title or "").strip() or "Untitled"
    safe_author = str(author or "").strip() or "Unknown"
    safe_summary = collapse_whitespace(summary)[:800] or "Open to preview details and launch the player."
    safe_collection_label = str(collectionLabel or "").strip() or "Reader Library"
    safe_license = str(license or "").strip()
    item_id = f"reader_admin_{uuid.uuid4().hex}"
    safe_direction_override = str(directionOverride or "").strip()
    if safe_content_kind != "comic":
        safe_direction_override = ""
    reading_mode_default = (
        _reader_normalize_reading_mode(safe_direction_override or "document", content_kind="comic")
        if safe_content_kind == "comic"
        else "document"
    )
    direction_value = (
        _reader_reading_mode_to_direction(reading_mode_default, content_kind="comic")
        if safe_content_kind == "comic"
        else normalize_reader_direction("vertical-scroll", content_kind="book")
    )
    panel_manifest: list[dict[str, Any]] = []
    sample_text_parts: list[str] = []
    cover_url = ""
    file_names: list[str] = []
    for index, upload in enumerate(list(files or [])):
        safe_name = _safe_upload_name(upload.filename, f"file_{index + 1}")
        file_names.append(safe_name)
        payload = bytes(await upload.read())
        suffix = Path(safe_name).suffix.lower()
        mime_type = upload.content_type or mimetypes.guess_type(safe_name)[0] or "application/octet-stream"
        if safe_content_kind == "comic":
            if suffix in {".png", ".jpg", ".jpeg", ".webp"}:
                asset_path, image_url = _reader_admin_catalog_store_public_asset(item_id, safe_name, payload, mime_type)
                panel_manifest.append(
                    {
                        "panelId": f"panel_{len(panel_manifest) + 1:04d}",
                        "pageId": f"page_{len(panel_manifest) + 1:04d}",
                        "index": len(panel_manifest),
                        "direction": direction_value,
                        "text": Path(safe_name).stem.replace("_", " ").strip(),
                        "sourceText": Path(safe_name).stem.replace("_", " ").strip(),
                        "displayText": Path(safe_name).stem.replace("_", " ").strip(),
                        "translatedText": "",
                        "translatedLanguage": "",
                        "translationStatus": "pending",
                        "speaker": "Narrator",
                        "emotion": "",
                        "sfx": [],
                        "estimatedReadMs": 0,
                        "imagePath": asset_path,
                        "imageUrl": image_url,
                        "remoteImageUrl": image_url,
                        "audioJobId": "",
                        "audioStatus": "idle",
                        "purged": False,
                        "prepStatus": "pending",
                    }
                )
                if not cover_url:
                    cover_url = image_url
            elif suffix == ".pdf":
                rows = _reader_upload_page_rows_from_pdf(payload) or [{"page": 1, "text": safe_title}]
                for row_index, row in enumerate(rows):
                    page_number = int(row.get("page") or row_index + 1)
                    placeholder = _reader_admin_catalog_placeholder_svg(safe_title, f"Page {page_number}")
                    asset_path, image_url = _reader_admin_catalog_store_public_asset(
                        item_id,
                        f"{safe_name}-{page_number}.svg",
                        placeholder,
                        "image/svg+xml",
                    )
                    panel_text = str(row.get("text") or "").strip()
                    panel_manifest.append(
                        {
                            "panelId": f"panel_{len(panel_manifest) + 1:04d}",
                            "pageId": f"page_{len(panel_manifest) + 1:04d}",
                            "index": len(panel_manifest),
                            "direction": direction_value,
                            "text": panel_text,
                            "sourceText": panel_text,
                            "displayText": panel_text,
                            "translatedText": "",
                            "translatedLanguage": "",
                            "translationStatus": "pending",
                            "speaker": "Narrator",
                            "emotion": "",
                            "sfx": [],
                            "estimatedReadMs": 0,
                            "imagePath": asset_path,
                            "imageUrl": image_url,
                            "remoteImageUrl": image_url,
                            "audioJobId": "",
                            "audioStatus": "idle",
                            "purged": False,
                            "prepStatus": "pending",
                        }
                    )
                    if not cover_url:
                        cover_url = image_url
            elif suffix in {".txt", ".md", ".docx", ".epub"}:
                if suffix in {".txt", ".md"}:
                    sample_text_parts.append(payload.decode("utf-8", errors="replace"))
                elif suffix == ".docx":
                    sample_text_parts.append(_reader_extract_docx_text(payload))
                elif suffix == ".epub":
                    sample_text_parts.append(_reader_extract_epub_text(payload))
                else:
                    sample_text_parts.append(Path(safe_name).stem.replace("_", " "))
        else:
            if suffix in {".txt", ".md"}:
                sample_text_parts.append(payload.decode("utf-8", errors="replace"))
            elif suffix == ".docx":
                sample_text_parts.append(_reader_extract_docx_text(payload))
            elif suffix == ".epub":
                sample_text_parts.append(_reader_extract_epub_text(payload))
            elif suffix == ".pdf":
                rows = _reader_upload_page_rows_from_pdf(payload)
                sample_text_parts.extend([str(row.get("text") or "") for row in rows if str(row.get("text") or "").strip()])
            elif suffix in {".png", ".jpg", ".jpeg", ".webp"} and not cover_url:
                _, cover_url = _reader_admin_catalog_store_public_asset(item_id, safe_name, payload, mime_type)

    if not cover_url:
        placeholder_label = safe_title or safe_author or "Reader Catalog"
        cover_url = _reader_admin_catalog_store_public_asset(
            item_id,
            f"{item_id}-cover.svg",
            _reader_admin_catalog_placeholder_svg(placeholder_label, safe_collection_label),
            "image/svg+xml",
        )[1]
    sample_text = collapse_whitespace("\n\n".join([item for item in sample_text_parts if str(item).strip()]))[:10_000]
    if safe_content_kind == "book" and not sample_text:
        sample_text = safe_summary
    if safe_content_kind == "comic" and not panel_manifest:
        placeholder_asset = _reader_admin_catalog_store_public_asset(
            item_id,
            f"{item_id}-page-1.svg",
            _reader_admin_catalog_placeholder_svg(safe_title, "Page 1"),
            "image/svg+xml",
        )
        panel_manifest.append(
            {
                "panelId": "panel_0001",
                "pageId": "page_0001",
                "index": 0,
                "direction": direction_value,
                "text": "",
                "sourceText": "",
                "displayText": "",
                "translatedText": "",
                "translatedLanguage": "",
                "translationStatus": "pending",
                "speaker": "Narrator",
                "emotion": "",
                "sfx": [],
                "estimatedReadMs": 0,
                "imagePath": placeholder_asset[0],
                "imageUrl": placeholder_asset[1],
                "remoteImageUrl": placeholder_asset[1],
                "audioJobId": "",
                "audioStatus": "idle",
                "purged": False,
                "prepStatus": "pending",
            }
        )
        cover_url = placeholder_asset[1]

    item_payload = _reader_admin_catalog_write(
        {
            "id": item_id,
            "title": safe_title,
            "author": safe_author,
            "regionId": safe_region_id,
            "contentKind": safe_content_kind,
            "surface": "comics" if safe_content_kind == "comic" else "books",
            "provider": "voiceflow_admin_catalog",
            "license": safe_license,
            "sourceUrl": "",
            "contentUrl": cover_url if safe_content_kind == "comic" else "",
            "archiveTxtUrl": "",
            "summary": safe_summary,
            "excerpt": safe_summary,
            "sampleText": sample_text,
            "coverUrl": cover_url,
            "supportsReadHere": bool(sample_text or panel_manifest),
            "sourceMeta": {
                "fileNames": file_names,
                "panelManifest": panel_manifest,
                "sampleText": sample_text,
                "contentType": "manga" if safe_content_kind == "comic" else "novel",
            },
            "createdAt": _safe_now_iso(),
            "updatedAt": _safe_now_iso(),
            "direction": direction_value,
            "readingModeDefault": reading_mode_default,
            "collectionLabel": safe_collection_label,
            "publishState": safe_publish_state,
            "publishedAt": _safe_now_iso() if safe_publish_state == "published" else "",
            "ownershipBasis": safe_ownership_basis,
            "stats": {
                "fileCount": len(file_names),
                "pageCount": len(panel_manifest) if safe_content_kind == "comic" else len([item for item in sample_text_parts if str(item).strip()]),
                "totalPanels": len(panel_manifest) if safe_content_kind == "comic" else 0,
                "totalChars": len(sample_text),
            },
        }
    )
    _audit_append_event(
        action="reader_catalog_item_create",
        resource_type="reader_catalog_item",
        resource_id=str(item_payload.get("id") or ""),
        after={"publishState": str(item_payload.get("publishState") or "")},
        meta={"contentKind": safe_content_kind},
        request=request,
        actor_uid=admin_uid,
        actor_role=str(actor.get("role") or ""),
    )
    return JSONResponse({"ok": True, "item": item_payload})


@app.patch("/admin/reader/catalog/items/{item_id}")
def admin_reader_catalog_patch(
    item_id: str,
    payload: ReaderAdminCatalogPatchRequest,
    request: Request,
) -> JSONResponse:
    admin_uid, actor = _require_permission(request, PERM_OPS_MUTATE)
    _require_admin_mutation_unlock(request, expected_uid=admin_uid)
    current = _reader_admin_catalog_get(item_id, include_drafts=True)
    if not current:
        raise HTTPException(status_code=404, detail="Reader admin catalog item not found.")
    next_item = dict(current)
    if payload.title is not None:
        next_item["title"] = str(payload.title or "").strip() or "Untitled"
    if payload.author is not None:
        next_item["author"] = str(payload.author or "").strip() or "Unknown"
    if payload.regionId is not None:
        next_item["regionId"] = str(reader_region(payload.regionId).get("id") or "english")
    if payload.license is not None:
        next_item["license"] = str(payload.license or "").strip()
    if payload.ownershipBasis is not None:
        next_item["ownershipBasis"] = _reader_normalize_ownership_basis(payload.ownershipBasis, raise_on_invalid=False)
    direction_value = payload.directionOverride if payload.directionOverride is not None else payload.direction
    if direction_value is not None:
        safe_direction = str(direction_value or "").strip()
        next_item["direction"] = safe_direction
        next_item["readingModeDefault"] = (
            _reader_normalize_reading_mode(safe_direction, content_kind=normalize_reader_content_kind(next_item.get("contentKind")))
            if normalize_reader_content_kind(next_item.get("contentKind")) == "comic"
            else "document"
        )
    if payload.summary is not None:
        next_item["summary"] = collapse_whitespace(payload.summary)[:800] or "Open to preview details and launch the player."
        next_item["excerpt"] = next_item["summary"]
    if payload.collectionLabel is not None:
        next_item["collectionLabel"] = str(payload.collectionLabel or "").strip() or "Reader Library"
    if payload.publishState is not None:
        next_item["publishState"] = _reader_admin_catalog_publish_state(payload.publishState)
    saved = _reader_admin_catalog_write(next_item)
    _audit_append_event(
        action="reader_catalog_item_patch",
        resource_type="reader_catalog_item",
        resource_id=str(saved.get("id") or item_id),
        after={"publishState": str(saved.get("publishState") or "")},
        meta={},
        request=request,
        actor_uid=admin_uid,
        actor_role=str(actor.get("role") or ""),
    )
    return JSONResponse({"ok": True, "item": saved})


@app.delete("/admin/reader/catalog/items/{item_id}")
def admin_reader_catalog_delete(item_id: str, request: Request) -> JSONResponse:
    admin_uid, actor = _require_permission(request, PERM_OPS_MUTATE)
    _require_admin_mutation_unlock(request, expected_uid=admin_uid)
    removed = _reader_admin_catalog_delete(item_id)
    if not removed:
        raise HTTPException(status_code=404, detail="Reader admin catalog item not found.")
    _audit_append_event(
        action="reader_catalog_item_delete",
        resource_type="reader_catalog_item",
        resource_id=str(item_id or ""),
        after={"deleted": True},
        meta={},
        request=request,
        actor_uid=admin_uid,
        actor_role=str(actor.get("role") or ""),
    )
    return JSONResponse({"ok": True, "deleted": True})


@app.get("/reader/assets/{asset_path:path}")
def reader_cached_asset(asset_path: str, request: Request) -> FileResponse:
    _require_request_uid(request)
    base_dir = READER_REMOTE_ASSETS_DIR.resolve()
    target = _reader_resolve_allowed_path(base_dir, asset_path, error_status=403, error_detail="Reader asset path is not allowed.")
    if not target.exists() or not target.is_file():
        raise HTTPException(status_code=404, detail="Reader asset not found.")
    media_type = mimetypes.guess_type(str(target))[0] or "application/octet-stream"
    return FileResponse(
        str(target),
        media_type=media_type,
        filename=target.name,
        headers={"Cache-Control": "private, max-age=3600"},
    )


@app.get("/reader/uploads/{upload_id}/assets/{asset_path:path}")
def reader_upload_asset(upload_id: str, asset_path: str, request: Request) -> FileResponse:
    uid = _require_request_uid(request)
    upload_item = _reader_upload_get(uid, upload_id)
    if not upload_item:
        raise HTTPException(status_code=404, detail="Reader upload not found.")
    base_dir = _reader_upload_dir(upload_id).resolve()
    target = _reader_resolve_allowed_path(base_dir, asset_path, error_status=403, error_detail="Reader asset path is not allowed.")
    if not target.exists() or not target.is_file():
        raise HTTPException(status_code=404, detail="Reader asset not found.")
    media_type = mimetypes.guess_type(str(target))[0] or "application/octet-stream"
    return FileResponse(str(target), media_type=media_type, filename=target.name)


@app.post("/reader/uploads")
async def reader_upload_create(
    request: Request,
    files: List[UploadFile] = File(...),
    title: str = Form(""),
    contentType: str = Form(""),
    ownershipBasis: str = Form("user_responsible"),
    regionId: str = Form("english"),
    directionOverride: str = Form(""),
) -> JSONResponse:
    uid = _require_request_uid(request)
    _reader_require_legal_ack(uid)
    safe_region_id = str(reader_region(regionId).get("id") or "english")
    safe_ownership_basis = _reader_normalize_ownership_basis(ownershipBasis, raise_on_invalid=False)
    upload_id = f"reader_upload_{uuid.uuid4().hex}"
    file_names: list[str] = []
    prepared_files: list[dict[str, Any]] = []
    extracted_text_parts: list[str] = []
    page_rows: list[dict[str, Any]] = []
    uploaded_total_bytes = 0
    ocr_started_at_sec = time.monotonic()
    ocr_images_used = 0

    for upload in list(files or []):
        safe_name = _safe_upload_name(upload.filename, "upload")
        suffix = Path(safe_name).suffix.lower()
        file_names.append(safe_name)
        upload_dir = _reader_upload_dir(upload_id).resolve()
        original_path = _reader_resolve_allowed_path(upload_dir, f"originals/{safe_name}", error_status=400, error_detail="Reader upload file path is not allowed.")
        written_bytes = await _write_upload_file_chunked(
            upload,
            original_path,
            max_bytes=VF_READER_UPLOAD_MAX_FILE_BYTES,
        )
        uploaded_total_bytes += int(written_bytes or 0)
        if uploaded_total_bytes > VF_READER_UPLOAD_MAX_TOTAL_BYTES:
            raise HTTPException(
                status_code=413,
                detail=(
                    f"Reader upload exceeds total size limit ({VF_READER_UPLOAD_MAX_TOTAL_BYTES} bytes). "
                    "Split the upload into smaller files."
                ),
            )
        payload = original_path.read_bytes()
        prepared_file: dict[str, Any] = {
            "name": safe_name,
            "suffix": suffix,
            "payload": payload,
            "sizeBytes": int(written_bytes or len(payload)),
        }
        if suffix == ".pdf":
            extracted, page_stats, likely_scanned = _extract_pdf_text_layer(payload)
            prepared_file["pdfTextChars"] = len(str(extracted or ""))
            prepared_file["pdfLikelyScanned"] = bool(likely_scanned)
            prepared_file["pageCount"] = len(page_stats)
        prepared_files.append(prepared_file)

    safe_content_kind = _reader_detect_upload_content_kind(contentType, prepared_files, title=title)

    for prepared in prepared_files:
        payload = bytes(prepared.get("payload") or b"")
        safe_name = str(prepared.get("name") or "upload")
        suffix = str(prepared.get("suffix") or "").lower()
        if safe_content_kind == "book":
            if suffix in {".txt", ".md"}:
                extracted_text_parts.append(payload.decode("utf-8", errors="replace"))
            elif suffix == ".docx":
                extracted_text_parts.append(_reader_extract_docx_text(payload))
            elif suffix == ".epub":
                extracted_text_parts.append(_reader_extract_epub_text(payload))
            elif suffix == ".pdf":
                rows = _reader_upload_page_rows_from_pdf(payload)
                _reader_assert_page_row_budget(len(page_rows), len(rows))
                page_rows.extend(rows)
                extracted_text_parts.extend([str(item.get("text") or "") for item in rows if str(item.get("text") or "").strip()])
            elif suffix in {".png", ".jpg", ".jpeg", ".webp"}:
                _reader_assert_page_row_budget(len(page_rows), 1)
                _reader_assert_ocr_budget(ocr_started_at_sec, ocr_images_used)
                row = _reader_build_image_page_row(upload_id, safe_name, payload)
                ocr_images_used += 1
                page_rows.append(row)
                extracted_text_parts.append(str(row.get("text") or ""))
        else:
            if suffix == ".pdf":
                rows = _reader_upload_page_rows_from_pdf(payload)
                _reader_assert_page_row_budget(len(page_rows), len(rows))
                page_rows.extend(rows)
            elif suffix in {".cbz", ".zip"}:
                archive_rows = _reader_iter_archive_image_payloads(payload)
                _reader_assert_page_row_budget(len(page_rows), len(archive_rows))
                for archive_name, image_payload in archive_rows:
                    _reader_assert_ocr_budget(ocr_started_at_sec, ocr_images_used)
                    page_rows.append(_reader_build_image_page_row(upload_id, archive_name, image_payload))
                    ocr_images_used += 1
            elif suffix in {".png", ".jpg", ".jpeg", ".webp"}:
                _reader_assert_page_row_budget(len(page_rows), 1)
                _reader_assert_ocr_budget(ocr_started_at_sec, ocr_images_used)
                page_rows.append(_reader_build_image_page_row(upload_id, safe_name, payload))
                ocr_images_used += 1

    normalized_text = _normalize_import_text("\n\n".join([item for item in extracted_text_parts if str(item).strip()]))
    reading_mode_default = _reader_infer_reading_mode(
        content_kind=safe_content_kind,
        title=str(title or (Path(file_names[0]).stem if file_names else "Reader Upload")).strip(),
        region_id=safe_region_id,
        direction_hint=directionOverride,
        provider="voiceflow_upload",
        file_names=file_names,
        page_rows=page_rows,
    )
    source_language = _reader_guess_source_language(
        normalized_text or "\n".join([str(item.get("text") or "") for item in page_rows[:3] if isinstance(item, dict)]),
        region_id=safe_region_id,
        fallback=_reader_normalize_language(reader_region(safe_region_id).get("locale"), default="en") or "en",
    )
    manifest: list[dict[str, Any]] = []
    if safe_content_kind == "comic":
        resolved_title = str(title or (Path(file_names[0]).stem if file_names else "Comic Upload")).strip() or "Comic Upload"
        manifest = build_panel_manifest(
            page_rows,
            title=resolved_title,
            direction=_reader_reading_mode_to_direction(reading_mode_default, content_kind="comic"),
        )
        if not manifest:
            raise HTTPException(status_code=422, detail="Could not build a comic or manga manifest from the upload.")
    elif not normalized_text:
        raise HTTPException(status_code=422, detail="Could not extract readable text from the upload.")

    text_path = _reader_write_text_artifact(upload_id, normalized_text) if normalized_text else ""
    manifest_path = _reader_write_json_artifact(upload_id, "manifest.json", manifest) if manifest else ""
    saved = _reader_upload_write(
        uid,
        _reader_normalize_upload_item(
            {
                "id": upload_id,
                "uid": uid,
                "title": str(title or (Path(file_names[0]).stem if file_names else "Reader Upload")).strip(),
                "contentKind": safe_content_kind,
                "surface": "uploads",
                "regionId": safe_region_id,
                "ownershipBasis": safe_ownership_basis,
                "sourceLanguage": source_language,
                "textPath": text_path,
                "manifestPath": manifest_path,
                "fileNames": file_names,
                "direction": _reader_reading_mode_to_direction(reading_mode_default, content_kind=safe_content_kind),
                "readingModeDefault": reading_mode_default,
                "summary": (normalized_text[:240] if normalized_text else f"{len(manifest)} panels prepared for Reader playback."),
                "sourceMeta": {
                    "fileCount": len(file_names),
                    "pageCount": len(page_rows) if page_rows else len(manifest),
                    "readingModeDefault": reading_mode_default,
                    "sourceLanguage": source_language,
                    "stats": {
                        "fileCount": len(file_names),
                        "pageCount": len(page_rows) if page_rows else len(manifest),
                        "totalPanels": len(manifest),
                        "totalChars": len(normalized_text),
                    },
                    "detectedContentKind": safe_content_kind,
                    "rightsGate": "voiceflow_reader_ack",
                },
            }
        ),
    )
    return JSONResponse({"ok": True, "upload": _commercial_annotate_item(saved)})


@app.post("/reader/sessions")
def reader_session_create(payload: ReaderSessionCreateRequest, request: Request) -> JSONResponse:
    uid = _require_request_uid(request)
    upload_item: Optional[dict[str, Any]] = None
    catalog_item: Optional[dict[str, Any]] = None
    remote_page_sources: list[str] = []
    remote_fallback_title = ""
    source_kind = "catalog"
    if str(payload.uploadId or "").strip():
        upload_item = _reader_upload_get(uid, str(payload.uploadId or "").strip())
        if not upload_item:
            raise HTTPException(status_code=404, detail="Reader upload not found.")
        source_kind = "upload"
    elif str(payload.itemId or "").strip():
        catalog_item = _reader_catalog_lookup(str(payload.itemId or "").strip())
        if not catalog_item:
            raise HTTPException(status_code=404, detail="Reader catalog item not found.")
    else:
        raise HTTPException(status_code=400, detail="itemId or uploadId is required.")

    work_key = f"{source_kind}:{str((upload_item or catalog_item or {}).get('id') or '').strip()}"
    progress = _reader_progress_get(uid, work_key)
    reader_preferences = _reader_preferences_get(uid)
    reading_mode_override = str(
        payload.readingModeOverride
        or payload.directionOverride
        or progress.get("readingMode")
        or progress.get("directionOverride")
        or reader_preferences.get("readingMode")
        or ""
    ).strip()
    auto_advance_profile = _reader_normalize_auto_advance_profile(
        payload.autoAdvanceProfile or progress.get("autoAdvanceProfile") or reader_preferences.get("autoAdvanceProfile")
    )
    requested_multi_speaker_enabled = _reader_normalize_multi_speaker_enabled(
        (
            payload.multiSpeakerEnabled
            if payload.multiSpeakerEnabled is not None
            else progress.get("multiSpeakerEnabled")
            if progress.get("multiSpeakerEnabled") is not None
            else reader_preferences.get("multiSpeakerEnabled")
        ),
        default=True,
    )
    requested_voice_mode = _reader_normalize_voice_mode(
        payload.voiceMode,
        default="multi" if requested_multi_speaker_enabled else "single",
    )
    if payload.voiceMode is not None:
        requested_multi_speaker_enabled = requested_voice_mode == "multi"
    source_language_override = _reader_normalize_language(
        payload.sourceLanguageOverride or progress.get("sourceLanguageOverride") or progress.get("sourceLanguage"),
        default="",
    )
    requested_narrator_voice_id = str(
        payload.narratorVoiceId or progress.get("narratorVoiceId") or reader_preferences.get("narratorVoiceId") or ""
    ).strip()
    requested_audio_engine = _reader_normalize_audio_engine(
        payload.audioEngine or progress.get("audioEngine") or reader_preferences.get("audioEngine"),
        default="native_audio_dialog",
    )
    requested_restore_state = _reader_build_restore_state(
        progress.get("restoreState"),
        active_item_index=int(progress.get("activeItemIndex") or 0),
        active_unit_id=str(progress.get("activeUnitId") or ""),
        viewport_anchor=str(progress.get("viewportAnchor") or ""),
    )
    if not bool(payload.forceNew):
        existing_session = _reader_find_live_session(uid, work_key)
        if existing_session:
            previous_source = _reader_normalize_language(existing_session.get("sourceLanguage"), default="en") or "en"
            previous_target = _reader_normalize_language(existing_session.get("targetLanguage"), default=previous_source) or previous_source
            previous_tts_mode = _reader_normalize_tts_language_mode(existing_session.get("ttsLanguageMode"))
            previous_multi_speaker_enabled = _reader_normalize_multi_speaker_enabled(existing_session.get("multiSpeakerEnabled"), default=True)
            previous_narrator_voice_id = str((existing_session.get("castMemory") or {}).get("Narrator") or existing_session.get("defaultVoiceId") or "v22").strip() or "v22"
            previous_audio_engine = _reader_normalize_audio_engine(existing_session.get("audioEngine"), default="tts_hd")
            existing_session["autoAdvanceProfile"] = auto_advance_profile
            existing_session["multiSpeakerEnabled"] = requested_multi_speaker_enabled
            existing_session["voiceMode"] = requested_voice_mode
            existing_session["audioEngine"] = requested_audio_engine
            existing_session["audioEngineStatus"] = (
                "unavailable"
                if requested_audio_engine == "native_audio_dialog" and not VF_READER_NATIVE_AUDIO_ENABLED
                else "active"
            )
            existing_active_item_hint = existing_session.get("activeItemIndex")
            if existing_active_item_hint is None:
                existing_active_item_hint = _reader_session_active_item_index(existing_session)
            existing_session = _reader_apply_restore_state(
                existing_session,
                requested_restore_state,
                active_item_index=int(existing_active_item_hint),
                active_unit_id=str(requested_restore_state.get("activeUnitId") or existing_session.get("activeUnitId") or ""),
                viewport_anchor=str(requested_restore_state.get("viewportAnchor") or existing_session.get("viewportAnchor") or ""),
            )
            existing_cast_memory = dict(existing_session.get("castMemory") or {})
            if requested_narrator_voice_id:
                existing_cast_memory["Narrator"] = requested_narrator_voice_id
            existing_session["castMemory"] = existing_cast_memory
            existing_session["defaultVoiceId"] = str(existing_cast_memory.get("Narrator") or "v22").strip() or "v22"
            if reading_mode_override:
                existing_session["readingMode"] = _reader_normalize_reading_mode(
                    reading_mode_override,
                    content_kind=str(existing_session.get("contentKind") or "book"),
                )
                existing_session["direction"] = _reader_reading_mode_to_direction(
                    existing_session["readingMode"],
                    content_kind=str(existing_session.get("contentKind") or "book"),
                )
            elif not str(existing_session.get("readingMode") or "").strip():
                existing_session["readingMode"] = _reader_direction_to_reading_mode(
                    existing_session.get("direction"),
                    content_kind=str(existing_session.get("contentKind") or "book"),
                )
            resolved_source = source_language_override or previous_source
            resolved_target = _reader_normalize_language(payload.targetLanguage, default=previous_target) or previous_target
            resolved_page_view = _reader_normalize_page_view_mode(
                payload.pageViewMode or existing_session.get("pageViewMode"),
                source_language=resolved_source,
                target_language=resolved_target,
            )
            resolved_tts_mode = _reader_normalize_tts_language_mode(payload.ttsLanguageMode or existing_session.get("ttsLanguageMode"))
            existing_session["sourceLanguage"] = resolved_source
            existing_session["targetLanguage"] = resolved_target
            existing_session["pageViewMode"] = resolved_page_view
            existing_session["ttsLanguageMode"] = resolved_tts_mode
            if (
                resolved_source != previous_source
                or resolved_target != previous_target
                or resolved_tts_mode != previous_tts_mode
                or requested_multi_speaker_enabled != previous_multi_speaker_enabled
                or str(existing_session.get("defaultVoiceId") or "v22").strip() != previous_narrator_voice_id
                or requested_audio_engine != previous_audio_engine
            ):
                existing_session = _reader_reset_audio_schedule(existing_session)
                if normalize_reader_content_kind(existing_session.get("contentKind")) == "book":
                    existing_session = _reader_schedule_text_window(existing_session, request)
                else:
                    existing_session = _reader_schedule_panel_batch(existing_session, request)
            existing_session = _reader_recover_failed_native_jobs(existing_session, request)
            saved_existing = _reader_session_set(existing_session)
            if _reader_is_async_remote_comic_session(saved_existing) and not _reader_prep_is_terminal(saved_existing.get("prep")):
                _reader_enqueue_remote_comic_hydration(uid, str(saved_existing.get("id") or "").strip())
            return JSONResponse({"ok": True, "session": _reader_session_public_view(saved_existing)})
    cast_doc = _reader_cast_memory_get(uid, work_key)
    cast_memory = dict(cast_doc.get("voices") or {})
    cast_memory.setdefault("Narrator", "v22")
    if requested_narrator_voice_id:
        cast_memory["Narrator"] = requested_narrator_voice_id

    if upload_item:
        source = _commercial_annotate_item(_reader_normalize_upload_item(upload_item))
        safe_title = str(source.get("title") or "Reader Upload")
        safe_content_kind = normalize_reader_content_kind(source.get("contentKind"))
        safe_surface = "uploads"
        safe_region_id = str(source.get("regionId") or "english")
        reading_mode = _reader_normalize_reading_mode(
            reading_mode_override or source.get("readingModeDefault") or source.get("direction"),
            content_kind=safe_content_kind,
        )
        direction = _reader_reading_mode_to_direction(reading_mode, content_kind=safe_content_kind)
        source_text = _reader_extract_upload_book_text(source) if safe_content_kind == "book" else ""
        panels = _reader_extract_upload_comic_manifest(source) if safe_content_kind == "comic" else []
    else:
        source = _commercial_assert_allowed_for_action(
            normalize_reader_catalog_item(catalog_item or {}),
            action="reader_session_create",
        )
        safe_title = str(source.get("title") or "Reader Catalog")
        safe_content_kind = normalize_reader_content_kind(source.get("contentKind"))
        safe_surface = normalize_reader_surface(source.get("surface") or ("comics" if safe_content_kind == "comic" else "books"))
        safe_region_id = str(source.get("regionId") or "english")
        reading_mode = _reader_normalize_reading_mode(
            reading_mode_override
            or source.get("readingModeDefault")
            or source.get("direction"),
            content_kind=safe_content_kind,
        )
        direction = _reader_reading_mode_to_direction(reading_mode, content_kind=safe_content_kind)
        source_text = _reader_catalog_book_text(source) if safe_content_kind == "book" else ""
        panels = _reader_catalog_comic_manifest(source) if safe_content_kind == "comic" else []
        if safe_content_kind == "comic":
            remote_page_sources = [
                str(item.get("remoteImageUrl") or item.get("imageUrl") or "").strip()
                for item in panels
                if isinstance(item, dict) and str(item.get("remoteImageUrl") or item.get("imageUrl") or "").strip()
            ]
            remote_fallback_title = _reader_remote_comic_fallback_title(source)

    source_language = source_language_override or _reader_normalize_source_language(source, region_id=safe_region_id)
    if safe_content_kind == "book" and source_text:
        source_language = _reader_guess_source_language(source_text[:4000], region_id=safe_region_id, fallback=source_language)
    elif safe_content_kind == "comic" and panels:
        source_language = _reader_guess_source_language(
            "\n".join([str(item.get("text") or "") for item in panels[:3]]),
            region_id=safe_region_id,
            fallback=source_language,
        )
    target_language = _reader_normalize_language(
        payload.targetLanguage or reader_preferences.get("targetLanguage"),
        default=_reader_normalize_catalog_target_language(progress, source_language),
    ) or source_language
    page_view_mode = _reader_normalize_page_view_mode(
        payload.pageViewMode or progress.get("pageViewMode") or reader_preferences.get("pageViewMode"),
        source_language=source_language,
        target_language=target_language,
    )
    tts_language_mode = _reader_normalize_tts_language_mode(
        payload.ttsLanguageMode or progress.get("ttsLanguageMode") or reader_preferences.get("ttsLanguageMode")
    )

    consumed_chars = max(0, int(progress.get("consumedChars") or 0))
    current_panel_index = max(0, int(progress.get("currentPanelIndex") or 0))
    windows = build_text_windows(source_text) if safe_content_kind == "book" else []
    if safe_content_kind == "book" and not windows:
        raise HTTPException(status_code=422, detail="Reader session could not prepare readable text.")
    if safe_content_kind == "comic" and not panels:
        raise HTTPException(status_code=422, detail="Reader session could not prepare comic or manga panels.")
    for item in windows:
        item.setdefault("jobId", "")
        item.setdefault("status", "idle")
        item.setdefault("purged", False)
    if safe_content_kind == "book" and consumed_chars > 0:
        for item in windows:
            if int(item.get("endChar") or 0) <= consumed_chars:
                item["status"] = "played"
                item["purged"] = True
    for item in panels:
        item.setdefault("audioJobId", "")
        item.setdefault("audioStatus", "idle")
        item.setdefault("purged", False)
    if safe_content_kind == "comic" and current_panel_index > 0:
        for item in panels:
            if int(item.get("index") or 0) < current_panel_index:
                item["audioStatus"] = "played"
                item["purged"] = True

    is_async_remote_comic = (
        bool(remote_page_sources)
        and source_kind == "catalog"
        and str(source.get("provider") or "").strip().lower() in _READER_ASYNC_REMOTE_COMIC_PROVIDERS
    )

    session = {
        "id": f"reader_session_{uuid.uuid4().hex}",
        "uid": uid,
        "workKey": work_key,
        "sourceKind": source_kind,
        "itemId": str((catalog_item or {}).get("id") or ""),
        "uploadId": str((upload_item or {}).get("id") or ""),
        "title": safe_title,
        "contentKind": safe_content_kind,
        "surface": safe_surface,
        "regionId": safe_region_id,
        "direction": direction,
        "readingMode": reading_mode,
        "sourceLanguage": source_language,
        "targetLanguage": target_language,
        "pageViewMode": page_view_mode,
        "ttsLanguageMode": tts_language_mode,
        "audioEngine": requested_audio_engine,
        "audioEngineStatus": (
            "unavailable"
            if requested_audio_engine == "native_audio_dialog" and not VF_READER_NATIVE_AUDIO_ENABLED
            else "active"
        ),
        "multiSpeakerEnabled": requested_multi_speaker_enabled,
        "voiceMode": requested_voice_mode,
        "effectiveMultiSpeakerMode": "single",
        "translationState": "idle",
        "translationLeadRatio": 0.0,
        "voiceFallbacks": {},
        "createdAtMs": _reader_now_ms(),
        "updatedAtMs": _reader_now_ms(),
        "consumedChars": consumed_chars,
        "currentPanelIndex": current_panel_index,
        "totalChars": sum(int(item.get("charCount") or 0) for item in windows),
        "totalPanels": len(panels),
        "provider": str(source.get("provider") or ("voiceflow_upload" if source_kind == "upload" else "catalog")),
        "license": str(source.get("license") or ""),
        "commercialUseStatus": str(source.get("commercialUseStatus") or "allowed"),
        "commercialUseReason": source.get("commercialUseReason"),
        "coverUrl": str(source.get("coverUrl") or ""),
        "summary": str(source.get("summary") or ""),
        "sourceUrl": str(source.get("sourceUrl") or ""),
        "collectionLabel": str(source.get("collectionLabel") or ("Recently imported" if source_kind == "upload" else "Reader Catalog")),
        "stats": dict(source.get("stats") or {}),
        "windows": windows,
        "panels": panels,
        "cachedChars": 0,
        "deleteAtMs": 0,
        "exportedWindowIndexes": [],
        "exportedPanelIndexes": [],
        "castMemory": cast_memory,
        "defaultVoiceId": str(cast_memory.get("Narrator") or "v22"),
        "musicTrackId": str(progress.get("musicTrackId") or "m_none"),
        "autoAdvanceProfile": auto_advance_profile,
        "prep": _reader_default_prep(
            state="queued" if is_async_remote_comic else "ready",
            stage="manifest" if is_async_remote_comic else "audio",
            completed_items=0 if is_async_remote_comic else (len(panels) if safe_content_kind == "comic" else len(windows)),
            total_items=len(panels) if safe_content_kind == "comic" else len(windows),
            message="Queued remote comic preparation." if is_async_remote_comic else "",
        ),
        "remotePageSources": remote_page_sources,
        "remoteFallbackTitle": remote_fallback_title or safe_title,
    }
    requested_active_item_hint = requested_restore_state.get("activeItemIndex")
    if requested_active_item_hint is None:
        requested_active_item_hint = _reader_session_active_item_index(session)
    session = _reader_apply_restore_state(
        session,
        requested_restore_state,
        active_item_index=int(requested_active_item_hint),
        active_unit_id=str(requested_restore_state.get("activeUnitId") or ""),
        viewport_anchor=str(requested_restore_state.get("viewportAnchor") or ""),
    )
    if isinstance(progress.get("unitOverrides"), dict):
        session, _ = _reader_apply_unit_overrides(session, dict(progress.get("unitOverrides") or {}))
    if safe_content_kind == "book":
        session = _reader_schedule_text_window(session, request)
    elif not is_async_remote_comic:
        session = _reader_schedule_panel_batch(session, request)
    saved = _reader_session_set(session)
    if is_async_remote_comic:
        _reader_enqueue_remote_comic_hydration(uid, str(saved.get("id") or "").strip())
    return JSONResponse({"ok": True, "session": _reader_session_public_view(saved)})


@app.get("/reader/sessions/{session_id}")
def reader_session_get(session_id: str, request: Request) -> JSONResponse:
    uid = _require_request_uid(request)
    session = _reader_session_get(uid, session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Reader session not found.")
    saved = _reader_session_set(_reader_recover_failed_native_jobs(_reader_refresh_session(session), request))
    if _reader_is_async_remote_comic_session(saved) and not _reader_prep_is_terminal(saved.get("prep")):
        _reader_enqueue_remote_comic_hydration(uid, str(saved.get("id") or "").strip())
    return JSONResponse({"ok": True, "session": _reader_session_public_view(saved)})


@app.post("/reader/sessions/{session_id}/progress")
def reader_session_progress(session_id: str, payload: ReaderSessionProgressRequest, request: Request) -> JSONResponse:
    uid = _require_request_uid(request)
    session = _reader_session_get(uid, session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Reader session not found.")
    safe_session = _reader_refresh_session(session)
    previous_audio_engine = _reader_normalize_audio_engine(safe_session.get("audioEngine"), default="tts_hd")
    audio_engine_changed = False
    if payload.audioEngine is not None:
        next_audio_engine = _reader_normalize_audio_engine(payload.audioEngine, default=previous_audio_engine)
        if next_audio_engine != previous_audio_engine:
            safe_session["audioEngine"] = next_audio_engine
            safe_session["audioEngineStatus"] = (
                "unavailable"
                if next_audio_engine == "native_audio_dialog" and not VF_READER_NATIVE_AUDIO_ENABLED
                else "active"
            )
            audio_engine_changed = True
    if payload.consumedChars is not None:
        safe_session["consumedChars"] = max(0, int(payload.consumedChars or 0))
    if str(payload.targetLanguage or "").strip():
        next_target = _reader_normalize_language(payload.targetLanguage, default=str(safe_session.get("sourceLanguage") or "en"))
        if next_target and next_target != str(safe_session.get("targetLanguage") or ""):
            safe_session["targetLanguage"] = next_target
            audio_engine_changed = True
    if str(payload.pageViewMode or "").strip():
        safe_session["pageViewMode"] = _reader_normalize_page_view_mode(
            payload.pageViewMode,
            source_language=str(safe_session.get("sourceLanguage") or "en"),
            target_language=str(safe_session.get("targetLanguage") or safe_session.get("sourceLanguage") or "en"),
        )
    if payload.activeItemIndex is not None:
        safe_session["activeItemIndex"] = max(0, int(payload.activeItemIndex or 0))
    if str(payload.activeUnitId or "").strip():
        safe_session["activeUnitId"] = str(payload.activeUnitId or "").strip()
    if str(payload.viewportAnchor or "").strip():
        safe_session["viewportAnchor"] = str(payload.viewportAnchor or "").strip()
    progress_active_item_hint = safe_session.get("activeItemIndex")
    if progress_active_item_hint is None:
        progress_active_item_hint = _reader_session_active_item_index(safe_session)
    safe_session = _reader_apply_restore_state(
        safe_session,
        safe_session.get("restoreState"),
        active_item_index=int(progress_active_item_hint),
        active_unit_id=str(safe_session.get("activeUnitId") or ""),
        viewport_anchor=str(safe_session.get("viewportAnchor") or ""),
    )
    if audio_engine_changed:
        safe_session = _reader_reset_audio_schedule(safe_session)
        if normalize_reader_content_kind(safe_session.get("contentKind")) == "book":
            safe_session = _reader_schedule_text_window(safe_session, request)
        else:
            safe_session = _reader_schedule_panel_batch(safe_session, request)
    safe_session = _reader_warm_translation_units(safe_session)
    if payload.consumedChars is not None:
        while should_schedule_next_text_window(
            consumed_chars=int(safe_session.get("consumedChars") or 0),
            scheduled_window_end_char=int(safe_session.get("scheduledWindowEndChar") or 0),
        ):
            previous_cached = int(safe_session.get("cachedChars") or 0)
            previous_scheduled = int(safe_session.get("scheduledWindowEndChar") or 0)
            safe_session = _reader_schedule_text_window(safe_session, request)
            safe_session = _reader_refresh_session(safe_session)
            if int(safe_session.get("cachedChars") or 0) == previous_cached and int(safe_session.get("scheduledWindowEndChar") or 0) == previous_scheduled:
                break
    if payload.currentPanelIndex is not None:
        safe_session["currentPanelIndex"] = max(0, int(payload.currentPanelIndex or 0))
        while should_schedule_next_panel_batch(
            current_panel_index=int(safe_session.get("currentPanelIndex") or 0),
            scheduled_panel_count=int(safe_session.get("scheduledPanelCount") or 0),
        ):
            previous_cached = int(safe_session.get("cachedChars") or 0)
            previous_scheduled = int(safe_session.get("scheduledPanelCount") or 0)
            safe_session = _reader_schedule_panel_batch(safe_session, request)
            safe_session = _reader_refresh_session(safe_session)
            if int(safe_session.get("cachedChars") or 0) == previous_cached and int(safe_session.get("scheduledPanelCount") or 0) == previous_scheduled:
                break
    safe_session = _reader_recover_failed_native_jobs(safe_session, request)
    _reader_progress_set(
        uid,
        str(safe_session.get("workKey") or ""),
        _reader_progress_payload_from_session(safe_session),
    )
    saved = _reader_session_set(safe_session)
    return JSONResponse({"ok": True, "session": _reader_session_public_view(saved)})


@app.post("/reader/sessions/{session_id}/savepoint")
def reader_session_savepoint(session_id: str, payload: ReaderSessionSavepointRequest, request: Request) -> JSONResponse:
    uid = _require_request_uid(request)
    session = _reader_session_get(uid, session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Reader session not found.")
    safe_session = _reader_refresh_session(session)
    initial_narrator_voice_id = str((safe_session.get("castMemory") or {}).get("Narrator") or safe_session.get("defaultVoiceId") or "v22").strip() or "v22"
    cast_memory = dict(safe_session.get("castMemory") or {})
    if isinstance(payload.castOverrides, dict):
        for key, value in payload.castOverrides.items():
            safe_key = str(key or "").strip()
            safe_value = str(value or "").strip()
            if safe_key and safe_value:
                cast_memory[safe_key] = safe_value
    if str(payload.narratorVoiceId or "").strip():
        cast_memory["Narrator"] = str(payload.narratorVoiceId or "").strip()
    safe_session["castMemory"] = cast_memory
    safe_session["defaultVoiceId"] = str(cast_memory.get("Narrator") or safe_session.get("defaultVoiceId") or "v22").strip() or "v22"
    if str(payload.readingModeOverride or payload.directionOverride or "").strip():
        safe_session["readingMode"] = _reader_normalize_reading_mode(
            payload.readingModeOverride or payload.directionOverride,
            content_kind=str(safe_session.get("contentKind") or "book"),
        )
        safe_session["direction"] = _reader_reading_mode_to_direction(
            safe_session["readingMode"],
            content_kind=str(safe_session.get("contentKind") or "book"),
        )
    if str(payload.autoAdvanceProfile or "").strip():
        safe_session["autoAdvanceProfile"] = _reader_normalize_auto_advance_profile(payload.autoAdvanceProfile)
    previous_source = _reader_normalize_language(safe_session.get("sourceLanguage"), default="en") or "en"
    previous_target = _reader_normalize_language(safe_session.get("targetLanguage"), default=previous_source) or previous_source
    previous_tts_mode = _reader_normalize_tts_language_mode(safe_session.get("ttsLanguageMode"))
    previous_multi_speaker_enabled = _reader_normalize_multi_speaker_enabled(safe_session.get("multiSpeakerEnabled"), default=True)
    previous_audio_engine = _reader_normalize_audio_engine(safe_session.get("audioEngine"), default="tts_hd")
    if str(payload.targetLanguage or "").strip():
        safe_session["targetLanguage"] = _reader_normalize_language(payload.targetLanguage, default=previous_source) or previous_source
    if str(payload.pageViewMode or "").strip():
        safe_session["pageViewMode"] = _reader_normalize_page_view_mode(
            payload.pageViewMode,
            source_language=str(safe_session.get("sourceLanguage") or previous_source),
            target_language=str(safe_session.get("targetLanguage") or previous_target),
        )
    if str(payload.ttsLanguageMode or "").strip():
        safe_session["ttsLanguageMode"] = _reader_normalize_tts_language_mode(payload.ttsLanguageMode)
    if str(payload.musicTrackId or "").strip():
        safe_session["musicTrackId"] = str(payload.musicTrackId or "").strip()
    if payload.multiSpeakerEnabled is not None:
        safe_session["multiSpeakerEnabled"] = _reader_normalize_multi_speaker_enabled(payload.multiSpeakerEnabled, default=previous_multi_speaker_enabled)
    if payload.voiceMode is not None:
        safe_session["multiSpeakerEnabled"] = _reader_normalize_voice_mode(
            payload.voiceMode,
            default="multi" if previous_multi_speaker_enabled else "single",
        ) == "multi"
    safe_session["voiceMode"] = _reader_normalize_voice_mode(
        payload.voiceMode,
        default="multi" if _reader_normalize_multi_speaker_enabled(safe_session.get("multiSpeakerEnabled"), default=True) else "single",
    )
    overrides_changed = False
    if isinstance(payload.unitOverrides, dict):
        safe_session, overrides_changed = _reader_apply_unit_overrides(safe_session, payload.unitOverrides)
    if payload.audioEngine is not None:
        safe_session["audioEngine"] = _reader_normalize_audio_engine(payload.audioEngine, default=previous_audio_engine)
    resolved_audio_engine = _reader_normalize_audio_engine(safe_session.get("audioEngine"), default="tts_hd")
    if resolved_audio_engine == "native_audio_dialog" and not VF_READER_NATIVE_AUDIO_ENABLED:
        safe_session["audioEngineStatus"] = "unavailable"
    elif resolved_audio_engine == "tts_hd":
        safe_session["audioEngineStatus"] = "active"
    else:
        safe_session["audioEngineStatus"] = _reader_normalize_audio_engine_status(
            safe_session.get("audioEngineStatus"),
            default="active",
        )
    restore_payload = dict(payload.restoreState or {}) if isinstance(payload.restoreState, dict) else {}
    savepoint_active_item_hint = restore_payload.get("activeItemIndex")
    if savepoint_active_item_hint is None:
        savepoint_active_item_hint = _reader_session_active_item_index(safe_session)
    safe_session = _reader_apply_restore_state(
        safe_session,
        restore_payload if restore_payload else safe_session.get("restoreState"),
        active_item_index=int(savepoint_active_item_hint),
        active_unit_id=str(restore_payload.get("activeUnitId") or safe_session.get("activeUnitId") or ""),
        viewport_anchor=str(restore_payload.get("viewportAnchor") or safe_session.get("viewportAnchor") or ""),
    )
    if (
        _reader_normalize_language(safe_session.get("sourceLanguage"), default="en") != previous_source
        or _reader_normalize_language(safe_session.get("targetLanguage"), default=previous_target) != previous_target
        or _reader_normalize_tts_language_mode(safe_session.get("ttsLanguageMode")) != previous_tts_mode
        or _reader_normalize_multi_speaker_enabled(safe_session.get("multiSpeakerEnabled"), default=previous_multi_speaker_enabled) != previous_multi_speaker_enabled
        or str((safe_session.get("castMemory") or {}).get("Narrator") or safe_session.get("defaultVoiceId") or "v22").strip() != initial_narrator_voice_id
        or _reader_normalize_audio_engine(safe_session.get("audioEngine"), default="tts_hd") != previous_audio_engine
        or overrides_changed
    ):
        safe_session = _reader_reset_audio_schedule(safe_session)
        if normalize_reader_content_kind(safe_session.get("contentKind")) == "book":
            safe_session = _reader_schedule_text_window(safe_session, request)
        else:
            safe_session = _reader_schedule_panel_batch(safe_session, request)
    safe_session = _reader_recover_failed_native_jobs(_reader_warm_translation_units(safe_session), request)
    _reader_cast_memory_set(uid, str(safe_session.get("workKey") or ""), {"voices": cast_memory})
    _reader_progress_set(
        uid,
        str(safe_session.get("workKey") or ""),
        _reader_progress_payload_from_session(safe_session),
    )
    saved = _reader_session_set(safe_session)
    return JSONResponse({"ok": True, "session": _reader_session_public_view(saved)})


@app.post("/reader/sessions/{session_id}/queue/prime")
def reader_session_queue_prime(
    session_id: str,
    payload: ReaderQueuePrimeRequest,
    request: Request,
) -> JSONResponse:
    uid = _require_request_uid(request)
    session = _reader_session_get(uid, session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Reader session not found.")
    safe_session = _reader_refresh_session(session)
    safe_content_kind = normalize_reader_content_kind(safe_session.get("contentKind"))
    requested_mode = str(payload.mode or "").strip().lower()
    if requested_mode not in {"book_paragraph", "comic_panel"}:
        requested_mode = "comic_panel" if safe_content_kind == "comic" else "book_paragraph"
    lookahead_units = max(0, min(24, int(payload.lookaheadUnits or 0)))
    from_active_index = max(0, int(payload.fromActiveIndex or 0))
    units_key = "panels" if safe_content_kind == "comic" else "windows"
    units = [dict(item) for item in list(safe_session.get(units_key) or []) if isinstance(item, dict)]
    if not units:
        return JSONResponse({"ok": True, "session": _reader_session_public_view(_reader_session_set(safe_session))})
    start_index = min(max(0, len(units)), from_active_index + 1)
    if start_index >= len(units) or lookahead_units <= 0:
        saved = _reader_session_set(safe_session)
        return JSONResponse({"ok": True, "session": _reader_session_public_view(saved)})
    cast_memory = dict(safe_session.get("castMemory") or {})
    safe_session, default_voice_id = _reader_resolve_voice_for_session(
        safe_session,
        speaker="Narrator",
        requested_voice_id=str(cast_memory.get("Narrator") or safe_session.get("defaultVoiceId") or "v22"),
    )
    tts_language = (
        _reader_normalize_language(safe_session.get("targetLanguage"), default="en")
        if _reader_effective_tts_language_mode(safe_session) == "target"
        else _reader_normalize_language(safe_session.get("sourceLanguage"), default="en")
    ) or "en"
    scheduled = 0
    for index in range(start_index, min(len(units), start_index + lookahead_units)):
        item = dict(units[index] or {})
        if safe_content_kind == "comic":
            if str(item.get("audioJobId") or "").strip() or bool(item.get("purged")):
                continue
            tts_text = _reader_tts_text_for_unit(safe_session, item)
            if not str(tts_text or "").strip():
                continue
        else:
            if str(item.get("jobId") or "").strip() or bool(item.get("purged")):
                continue
            tts_text = _reader_tts_text_for_unit(safe_session, item)
            if not str(tts_text or "").strip():
                continue
        char_count = len(tts_text)
        safe_session, line_map, resolved_speaker_voices, multi_speaker_mode, _ = _reader_resolve_multi_speaker_payload(
            safe_session,
            text=tts_text,
            cast_memory=cast_memory,
            default_voice_id=default_voice_id,
        )
        cast_memory = dict(safe_session.get("castMemory") or {})
        safe_session, job_id, routed_engine = _reader_create_tts_job_with_audio_engine_fallback(
            request,
            session=safe_session,
            text=tts_text,
            request_id=f"{str(safe_session.get('id') or 'reader')}_{'panel' if safe_content_kind == 'comic' else 'window'}_{index}",
            voice_id=default_voice_id,
            language=tts_language,
            multi_speaker_mode=multi_speaker_mode,
            line_map=line_map or None,
            speaker_voices=resolved_speaker_voices or None,
        )
        if safe_content_kind == "comic":
            item["audioJobId"] = job_id
            item["audioStatus"] = "queued"
            item["audioEngine"] = routed_engine
            if routed_engine == "tts_hd" and _reader_normalize_audio_engine(safe_session.get("audioEngine"), default="tts_hd") == "native_audio_dialog":
                item["fallbackFromNativeAudio"] = True
        else:
            item["jobId"] = job_id
            item["status"] = "queued"
            item["audioEngine"] = routed_engine
            if routed_engine == "tts_hd" and _reader_normalize_audio_engine(safe_session.get("audioEngine"), default="tts_hd") == "native_audio_dialog":
                item["fallbackFromNativeAudio"] = True
        units[index] = item
        safe_session[units_key] = units
        safe_session["cachedChars"] = int(safe_session.get("cachedChars") or 0) + char_count
        scheduled += 1
        if scheduled >= lookahead_units:
            break
    safe_session["updatedAtMs"] = _reader_now_ms()
    saved = _reader_session_set(safe_session)
    return JSONResponse({"ok": True, "session": _reader_session_public_view(saved)})


@app.get("/reader/sessions/{session_id}/export")
def reader_session_export(session_id: str, request: Request) -> FileResponse:
    uid = _require_request_uid(request)
    is_admin = _request_is_admin(request, uid)
    session = _reader_session_get(uid, session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Reader session not found.")
    safe_session = _reader_refresh_session(session)
    export_chunks: list[bytes] = []
    exported_window_set = {int(value) for value in list(safe_session.get("exportedWindowIndexes") or [])}
    newly_exported_windows: list[int] = []
    for item in list(safe_session.get("windows") or []):
        if not isinstance(item, dict):
            continue
        index = int(item.get("index") or 0)
        if index in exported_window_set:
            continue
        job_id = str(item.get("jobId") or "").strip()
        if not job_id:
            continue
        audio_bytes = _reader_tts_job_result_audio_bytes(uid, job_id, is_admin=is_admin)
        if audio_bytes is None:
            continue
        export_chunks.append(audio_bytes)
        newly_exported_windows.append(index)
    exported_panel_set = {int(value) for value in list(safe_session.get("exportedPanelIndexes") or [])}
    newly_exported_panels: list[int] = []
    for item in list(safe_session.get("panels") or []):
        if not isinstance(item, dict):
            continue
        index = int(item.get("index") or 0)
        if index in exported_panel_set:
            continue
        job_id = str(item.get("audioJobId") or "").strip()
        if not job_id:
            continue
        audio_bytes = _reader_tts_job_result_audio_bytes(uid, job_id, is_admin=is_admin)
        if audio_bytes is None:
            continue
        export_chunks.append(audio_bytes)
        newly_exported_panels.append(index)
    export_path = _reader_export_path(session_id)
    existing_chunks: list[bytes] = []
    if export_path.exists():
        try:
            existing_chunks.append(export_path.read_bytes())
        except Exception:
            existing_chunks = []
    if not export_chunks and not existing_chunks:
        raise HTTPException(status_code=409, detail="No completed Reader audio is ready to export yet.")
    merged_audio = _concat_wav_chunks(existing_chunks + export_chunks)
    export_path.parent.mkdir(parents=True, exist_ok=True)
    export_path.write_bytes(merged_audio)
    exported_window_set.update(newly_exported_windows)
    exported_panel_set.update(newly_exported_panels)
    safe_session["exportedWindowIndexes"] = sorted(exported_window_set)
    safe_session["exportedPanelIndexes"] = sorted(exported_panel_set)
    exported_chars = 0
    for item in list(safe_session.get("windows") or []):
        if int(item.get("index") or 0) in newly_exported_windows:
            exported_chars += int(item.get("charCount") or 0)
    for item in list(safe_session.get("panels") or []):
        if int(item.get("index") or 0) in newly_exported_panels:
            exported_chars += len(str(item.get("text") or ""))
    safe_session["cachedChars"] = max(0, int(safe_session.get("cachedChars") or 0) - exported_chars)
    safe_session["deleteAtMs"] = 0
    _reader_session_set(safe_session)
    return FileResponse(
        str(export_path),
        media_type="audio/wav",
        filename=f"{_reader_safe_id(str(safe_session.get('title') or 'reader_audio'), 'reader_audio')}.wav",
        headers={"Cache-Control": "no-store"},
    )


@app.delete("/reader/sessions/{session_id}")
def reader_session_delete(session_id: str, request: Request) -> JSONResponse:
    uid = _require_request_uid(request)
    is_admin = _request_is_admin(request, uid)
    session = _reader_session_get(uid, session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Reader session not found.")
    safe_session = _reader_refresh_session(session)
    _reader_cast_memory_set(uid, str(safe_session.get("workKey") or ""), {"voices": dict(safe_session.get("castMemory") or {})})
    _reader_progress_set(
        uid,
        str(safe_session.get("workKey") or ""),
        _reader_progress_payload_from_session(safe_session),
    )
    for item in list(safe_session.get("windows") or []):
        job_id = str((item or {}).get("jobId") or "").strip()
        if job_id:
            _reader_cancel_tts_job(uid, job_id, is_admin=is_admin)
    for item in list(safe_session.get("panels") or []):
        job_id = str((item or {}).get("audioJobId") or "").strip()
        if job_id:
            _reader_cancel_tts_job(uid, job_id, is_admin=is_admin)
    _reader_session_delete(session_id)
    return JSONResponse({"ok": True})

@app.post("/novel/ideas/extract")
def extract_novel_idea(payload: NovelIdeaExtractRequest) -> JSONResponse:
    try:
        source = _normalize_novel_source(payload.source)
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc

    target_url = (payload.url or "").strip()
    if not target_url:
        raise HTTPException(status_code=400, detail="URL is required.")

    parsed = urlparse(target_url)
    if parsed.scheme not in {"http", "https"}:
        raise HTTPException(status_code=400, detail="URL must start with http:// or https://")

    allowed_hosts = NOVEL_IDEA_ALLOWED_HOSTS[source]
    if not _host_matches_allowed(parsed.hostname or "", allowed_hosts):
        allowed_hint = ", ".join(allowed_hosts)
        raise HTTPException(
            status_code=400,
            detail=f"Unsupported domain for {source}. Allowed: {allowed_hint}",
        )

    try:
        response = requests.get(
            target_url,
            headers={
                "User-Agent": NOVEL_IDEA_USER_AGENT,
                "Accept": "text/html,application/xhtml+xml",
                "Accept-Language": "en-US,en;q=0.9",
            },
            timeout=(6, 15),
        )
        response.raise_for_status()
    except requests.RequestException as exc:
        raise HTTPException(status_code=502, detail=f"Failed to fetch source page: {exc}") from exc

    soup = BeautifulSoup(response.text[:2_500_000], "html.parser")

    title = _extract_meta_content(
        soup,
        [
            {"property": "og:title"},
            {"name": "twitter:title"},
            {"name": "title"},
        ],
    )
    if not title:
        title_tag = soup.find("title")
        title = _clean_meta_text(title_tag.get_text(" ", strip=True) if title_tag else "")

    synopsis = _extract_meta_content(
        soup,
        [
            {"property": "og:description"},
            {"name": "description"},
            {"name": "twitter:description"},
        ],
    )

    tags: list[str] = []
    keywords = _extract_meta_content(soup, [{"name": "keywords"}])
    if keywords:
        for token in keywords.split(","):
            cleaned = _clean_meta_text(token, max_len=60)
            if cleaned and cleaned.lower() not in {item.lower() for item in tags}:
                tags.append(cleaned)

    tag_nodes = soup.find_all("meta", attrs={"property": "article:tag"})
    for node in tag_nodes:
        cleaned = _clean_meta_text(node.get("content", ""), max_len=60)
        if cleaned and cleaned.lower() not in {item.lower() for item in tags}:
            tags.append(cleaned)
        if len(tags) >= 12:
            break

    warnings: list[str] = []
    if not title:
        warnings.append("title_not_found")
    if not synopsis:
        warnings.append("synopsis_not_found")
    if not tags:
        warnings.append("tags_not_found")

    return JSONResponse(
        {
            "ok": True,
            "source": source,
            "url": target_url,
            "title": title,
            "synopsis": synopsis,
            "tags": tags,
            "warnings": warnings,
        }
    )


