def _support_ai_topic_token(value: Any) -> str:
    token = re.sub(r"[^a-z0-9]+", "_", str(value or "").strip().lower())
    return token.strip("_")


def _support_ai_normalized_text(text: str) -> tuple[str, str]:
    compact = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", str(text or "").strip().lower())).strip()
    return compact, compact.replace(" ", "_")


def _support_ai_message_matches_topic(*, text_compact: str, text_topic: str, topic: str) -> bool:
    safe_topic = _support_ai_topic_token(topic)
    if not safe_topic:
        return False
    phrase = safe_topic.replace("_", " ")
    if phrase and phrase in text_compact:
        return True
    return bool(safe_topic and safe_topic in text_topic)


def _support_ai_detect_tags(text: str) -> list[str]:
    text_compact, text_topic = _support_ai_normalized_text(text)
    if not text_compact:
        return []
    matched: set[str] = set()
    for tag, keywords in SUPPORT_AI_TOPIC_KEYWORDS.items():
        for keyword in keywords:
            if _support_ai_message_matches_topic(text_compact=text_compact, text_topic=text_topic, topic=keyword):
                matched.add(_support_ai_topic_token(tag))
                break
    return sorted(item for item in matched if item)


def _support_ai_build_limited_account_context(uid: str, user_id: str) -> dict[str, Any]:
    safe_uid = str(uid or "").strip()
    safe_user_id = str(user_id or "").strip().lower()
    entitlement = _load_entitlement(safe_uid) if safe_uid else _default_entitlement("")
    monthly, daily = _load_usage_windows(safe_uid) if safe_uid else _usage_defaults("", _utc_now())
    plan = _normalize_plan_name(str(entitlement.get("plan") or "Free"))
    account_status = str(entitlement.get("status") or "unknown").strip().lower() or "unknown"
    return {
        "uid": safe_uid,
        "userId": safe_user_id,
        "plan": plan,
        "accountStatus": account_status,
        "wallet": {
            "vffBalance": _as_positive_number(entitlement.get("vffBalance")),
            "paidVfBalance": _as_positive_number(entitlement.get("paidVfBalance")),
        },
        "usage": {
            "monthlyVfUsed": _as_positive_number(monthly.get("vfUsed")),
            "monthlyVfLimit": _as_positive_int(entitlement.get("monthlyVfLimit")),
            "dailyGenerationUsed": _as_positive_int(daily.get("generationCount")),
        },
    }


def _support_ai_format_number(value: Any) -> str:
    number = _as_positive_number(value)
    if abs(number - round(number)) <= 1e-9:
        return str(int(round(number)))
    return f"{number:.2f}".rstrip("0").rstrip(".")


def _support_ai_reply_text(*, user_text: str, account_context: dict[str, Any]) -> str:
    text = str(user_text or "").strip()
    if not text:
        return "I could not read your message clearly. Please share more details so I can help."
    wallet = account_context.get("wallet") if isinstance(account_context.get("wallet"), dict) else {}
    usage = account_context.get("usage") if isinstance(account_context.get("usage"), dict) else {}
    identity = str(account_context.get("userId") or account_context.get("uid") or "your account").strip()
    plan = str(account_context.get("plan") or "Free").strip() or "Free"
    account_status = str(account_context.get("accountStatus") or "unknown").strip() or "unknown"
    monthly_used = _support_ai_format_number(usage.get("monthlyVfUsed"))
    monthly_limit = _as_positive_int(usage.get("monthlyVfLimit"))
    daily_used = _as_positive_int(usage.get("dailyGenerationUsed"))
    free_balance = _support_ai_format_number(wallet.get("vffBalance"))
    paid_balance = _support_ai_format_number(wallet.get("paidVfBalance"))
    return (
        f"Auto support response for {identity}: "
        f"plan {plan} ({account_status}), wallet free {free_balance} VF and paid {paid_balance} VF, "
        f"usage monthly {monthly_used}/{monthly_limit} VF and daily generations {daily_used}. "
        "Please refresh the workspace and retry once. If the issue continues, reply \"still unresolved\" and a human agent will take over."
    )


def _support_ai_count_messages(conversation_id: str, from_type: str) -> int:
    safe_conv = str(conversation_id or "").strip()
    safe_from_type = str(from_type or "").strip().lower()
    if not safe_conv or not safe_from_type:
        return 0
    count = 0
    for row in _support_list_messages(safe_conv, limit=1000):
        if str(row.get("fromType") or "").strip().lower() == safe_from_type:
            count += 1
    return count


def _support_ai_action_allowed(policy: dict[str, Any], action: str) -> bool:
    allowed = [str(item or "").strip().lower() for item in list(policy.get("allowedActions") or [])]
    return str(action or "").strip().lower() in set(allowed)


def _support_try_ai_autoreply(
    *,
    conversation: dict[str, Any],
    user_message: dict[str, Any],
    request: Optional[Request],
) -> dict[str, Any]:
    now_iso = _utc_now().isoformat()
    conversation_id = str(conversation.get("conversationId") or "").strip()
    uid = str(conversation.get("uid") or "").strip()
    user_id = str(conversation.get("userId") or "").strip().lower()
    text = str(user_message.get("text") or "").strip()
    policy = _support_ai_policy_get()
    account_context = _support_ai_build_limited_account_context(uid, user_id)
    run = {
        "conversationId": conversation_id,
        "messageId": str(user_message.get("messageId") or ""),
        "uid": uid,
        "userId": user_id,
        "status": "evaluating",
        "reason": "",
        "confidence": 0.0,
        "createdAt": now_iso,
        "updatedAt": now_iso,
        "accountContext": account_context,
    }
    blocked_topics = [_support_ai_topic_token(item) for item in list(policy.get("blockedTopics") or [])]
    blocked_topics = [item for item in blocked_topics if item]
    require_human_topics = [_support_ai_topic_token(item) for item in list(policy.get("requireHumanForTags") or [])]
    require_human_topics = [item for item in require_human_topics if item]
    text_compact, text_topic = _support_ai_normalized_text(text)
    detected_tags: set[str] = set(_support_ai_detect_tags(text))
    blocked_hit = next(
        (
            topic
            for topic in blocked_topics
            if _support_ai_message_matches_topic(text_compact=text_compact, text_topic=text_topic, topic=topic)
            or topic in detected_tags
        ),
        "",
    )
    require_human_hit = next(
        (
            topic
            for topic in require_human_topics
            if _support_ai_message_matches_topic(text_compact=text_compact, text_topic=text_topic, topic=topic)
            or topic in detected_tags
        ),
        "",
    )
    if blocked_hit:
        detected_tags.add(blocked_hit)
    if require_human_hit:
        detected_tags.add(require_human_hit)
    run["detectedTags"] = sorted(detected_tags)
    max_auto = max(0, int(policy.get("maxAutoRepliesPerConversation") or 0))
    sent_ai_count = _support_ai_count_messages(conversation_id, "ai")
    confidence = _support_ai_confidence_score(text)
    threshold = max(0.0, min(1.0, float(policy.get("confidenceThreshold") or VF_SUPPORT_AI_CONFIDENCE_THRESHOLD)))
    run["confidence"] = confidence
    current_status = str(conversation.get("status") or "").strip().lower()
    current_priority = str(conversation.get("priority") or "").strip().lower()

    def _critical_priority(tags: list[str]) -> str:
        severe = {"security", "fraud", "chargeback", "legal_notice", "account_lock"}
        return "red" if any(tag in severe for tag in tags) else "yellow"

    def _escalate(reason: str, *, priority: str = "yellow", tags: Optional[list[str]] = None) -> dict[str, Any]:
        safe_priority = str(priority or "").strip().lower()
        if safe_priority not in SUPPORT_PRIORITIES or safe_priority == "green":
            safe_priority = "yellow"
        if tags:
            merged_tags = set(str(item or "").strip().lower() for item in list(run.get("detectedTags") or []))
            merged_tags.update(str(item or "").strip().lower() for item in tags)
            run["detectedTags"] = sorted(item for item in merged_tags if item)
        conversation["status"] = "needs_human"
        conversation["priority"] = safe_priority
        conversation["lastMessageAt"] = now_iso
        conversation["updatedAt"] = now_iso
        _support_conversation_upsert(conversation_id, conversation)
        run["status"] = "escalated"
        run["reason"] = reason
        run["updatedAt"] = now_iso
        written_run = _support_ai_run_upsert("", run)
        _support_open_or_touch_yellow_alert(conversation_id, reason=reason)
        _audit_append_event(
            action="support_ai_escalated",
            resource_type="support_conversation",
            resource_id=conversation_id,
            after={
                "reason": reason,
                "confidence": confidence,
                "priority": safe_priority,
                "detectedTags": list(run.get("detectedTags") or []),
            },
            request=request,
            actor_uid=uid,
            actor_role="user",
            subject_uid=uid,
            subject_user_id=user_id,
        )
        return {
            "ok": True,
            "mode": "escalated",
            "reason": reason,
            "conversation": conversation,
            "run": written_run,
        }

    if not VF_SUPPORT_AI_ENABLED or not VF_SUPPORT_AI_AUTOREPLY_ENABLED:
        return _escalate("support_ai_disabled")
    if not _as_bool(policy.get("enabled")):
        return _escalate("policy_disabled")
    if current_status == "needs_human" or (current_priority and current_priority != "green"):
        return _escalate(
            "conversation_already_critical",
            priority=current_priority if current_priority in {"yellow", "red"} else "yellow",
        )
    if not _support_ai_action_allowed(policy, "emit_support_reply"):
        run["status"] = "blocked"
        run["reason"] = "blocked_by_policy"
        run["updatedAt"] = now_iso
        written_run = _support_ai_run_upsert("", run)
        _audit_append_event(
            action="support_ai_blocked_by_policy",
            resource_type="support_conversation",
            resource_id=conversation_id,
            after={"reason": "blocked_by_policy"},
            request=request,
            actor_uid=uid,
            actor_role="user",
            subject_uid=uid,
            subject_user_id=user_id,
        )
        return _escalate("blocked_by_policy")
    if blocked_hit:
        return _escalate(
            f"blocked_topic:{blocked_hit}",
            priority=_critical_priority(sorted(detected_tags)),
            tags=[blocked_hit],
        )
    if require_human_hit:
        return _escalate(
            f"critical_tag:{require_human_hit}",
            priority=_critical_priority(sorted(detected_tags)),
            tags=[require_human_hit],
        )
    if sent_ai_count >= max_auto:
        return _escalate("max_auto_replies_reached")
    if confidence < threshold:
        return _escalate("low_confidence")

    ai_reply = _support_message_upsert(
        "",
        {
            "conversationId": conversation_id,
            "fromType": "ai",
            "uid": uid,
            "userId": user_id,
            "text": _support_ai_reply_text(user_text=text, account_context=account_context),
            "attachmentsMeta": [],
            "resolutionFlag": "ai_answered",
            "createdAt": now_iso,
        },
    )
    conversation["status"] = "ai_answered"
    conversation["priority"] = "green"
    conversation["lastMessageAt"] = now_iso
    conversation["updatedAt"] = now_iso
    _support_conversation_upsert(conversation_id, conversation)
    run["status"] = "reply_sent"
    run["reason"] = "ok"
    run["updatedAt"] = now_iso
    written_run = _support_ai_run_upsert("", run)
    _audit_append_event(
        action="support_ai_reply_sent",
        resource_type="support_conversation",
        resource_id=conversation_id,
        after={
            "confidence": confidence,
            "detectedTags": list(run.get("detectedTags") or []),
            "accountContext": account_context,
        },
        request=request,
        actor_uid=uid,
        actor_role="user",
        subject_uid=uid,
        subject_user_id=user_id,
    )
    return {"ok": True, "mode": "ai_reply", "conversation": conversation, "aiMessage": ai_reply, "run": written_run}


def _admin_list_users(limit: int, search: str = "") -> list[dict[str, Any]]:
    def _entitlement_view(entitlement_payload: dict[str, Any]) -> tuple[str, dict[str, Any], dict[str, Any]]:
        plan_name = _normalize_plan_name(str(entitlement_payload.get("plan") or "Free"))
        plan_key = _plan_key_from_name(plan_name)
        guardrails = TTS_PLAN_GUARDRAILS.get(plan_key) or TTS_PLAN_GUARDRAILS["free"]
        return (
            plan_name,
            {"earlyAccess": _plan_has_early_access(plan_key)},
            {"maxCharsPerGeneration": max(1, int(guardrails.get("maxChars") or 1))},
        )

    safe_limit = max(1, min(200, int(limit)))
    needle = str(search or "").strip().lower()
    users: list[dict[str, Any]] = []

    if _firebase_ready() and firebase_auth is not None:
        page = firebase_auth.list_users()  # type: ignore[attr-defined]
        for record in page.iterate_all():
            uid = str(getattr(record, "uid", "") or "")
            email = str(getattr(record, "email", "") or "")
            display_name = str(getattr(record, "display_name", "") or "")
            disabled = bool(getattr(record, "disabled", False))
            custom_claims = getattr(record, "custom_claims", None) or {}
            profile = _ensure_user_profile(
                uid,
                allow_auto_backfill=True,
                seed_email=email,
                seed_display_name=display_name,
                repair_user_id_collisions=True,
                suppress_backfill_errors=True,
                fetch_firebase_identity=False,
            ) or {}
            user_id = str(profile.get("userId") or "").strip().lower()
            if needle:
                haystack = f"{uid} {email} {display_name} {user_id}".lower()
                if needle not in haystack:
                    continue
            entitlement = _load_entitlement(uid, create_missing=False)
            monthly, daily = _load_usage_windows(uid, create_missing=False)
            plan_name, features, limits = _entitlement_view(entitlement)
            users.append(
                {
                    "uid": uid,
                    "userId": user_id,
                    "email": email,
                    "displayName": display_name,
                    "disabled": disabled,
                    "admin": _as_bool(custom_claims.get("admin")) or _firestore_user_is_admin(uid),
                    "plan": plan_name,
                    "status": str(entitlement.get("status") or "free_active"),
                    "features": features,
                    "limits": limits,
                    "wallet": {
                        "paidVfBalance": _as_positive_number(entitlement.get("paidVfBalance")),
                        "vffBalance": _as_positive_number(entitlement.get("vffBalance")),
                    },
                    "usage": {
                        "monthlyVfUsed": _as_positive_number(monthly.get("vfUsed")),
                        "dailyGenerationUsed": _as_positive_int(daily.get("generationCount")),
                    },
                }
            )
            if len(users) >= safe_limit:
                break
        return users

    collection = _firestore_collection("entitlements")
    if collection is None:
        with _INMEMORY_LOCK:
            for uid, payload in _INMEMORY_ENTITLEMENTS.items():
                if needle and needle not in uid.lower():
                    continue
                entitlement = _normalize_entitlement_wallet(payload)
                profile = _ensure_user_profile(
                    uid,
                    allow_auto_backfill=True,
                    repair_user_id_collisions=True,
                    suppress_backfill_errors=True,
                ) or {}
                user_id = str(profile.get("userId") or "").strip().lower()
                if needle:
                    haystack = f"{uid} {user_id}".lower()
                    if needle not in haystack:
                        continue
                plan_name, features, limits = _entitlement_view(entitlement)
                users.append(
                    {
                        "uid": uid,
                        "userId": user_id,
                        "email": "",
                        "displayName": uid,
                        "disabled": False,
                        "admin": uid in VF_ADMIN_APPROVER_UIDS,
                        "plan": plan_name,
                        "status": str(entitlement.get("status") or "free_active"),
                        "features": features,
                        "limits": limits,
                        "wallet": {
                            "paidVfBalance": _as_positive_number(entitlement.get("paidVfBalance")),
                            "vffBalance": _as_positive_number(entitlement.get("vffBalance")),
                        },
                        "usage": {"monthlyVfUsed": 0, "dailyGenerationUsed": 0},
                    }
                )
                if len(users) >= safe_limit:
                    break
            return users

    docs = collection.limit(safe_limit * 2).stream()
    for doc in docs:
        uid = str(doc.id or "")
        if needle and needle not in uid.lower():
            continue
        entitlement = _normalize_entitlement_wallet(doc.to_dict() or {})
        profile = _ensure_user_profile(
            uid,
            allow_auto_backfill=True,
            repair_user_id_collisions=True,
            suppress_backfill_errors=True,
        ) or {}
        user_id = str(profile.get("userId") or "").strip().lower()
        if needle:
            haystack = f"{uid} {user_id}".lower()
            if needle not in haystack:
                continue
        plan_name, features, limits = _entitlement_view(entitlement)
        users.append(
            {
                "uid": uid,
                "userId": user_id,
                "email": "",
                "displayName": uid,
                "disabled": False,
                "admin": _firestore_user_is_admin(uid),
                "plan": plan_name,
                "status": str(entitlement.get("status") or "free_active"),
                "features": features,
                "limits": limits,
                "wallet": {
                    "paidVfBalance": _as_positive_number(entitlement.get("paidVfBalance")),
                    "vffBalance": _as_positive_number(entitlement.get("vffBalance")),
                },
                "usage": {"monthlyVfUsed": 0, "dailyGenerationUsed": 0},
            }
        )
        if len(users) >= safe_limit:
            break
    return users


def _admin_set_user_disabled(uid: str, disabled: bool) -> None:
    if not _firebase_ready() or firebase_auth is None:
        raise HTTPException(status_code=503, detail="Firebase admin auth is not configured.")
    try:
        firebase_auth.update_user(uid, disabled=bool(disabled))  # type: ignore[attr-defined]
    except Exception as exc:
        raise HTTPException(status_code=502, detail=f"Failed to update user status: {exc}") from exc


def _admin_set_user_password(uid: str, new_password: str) -> None:
    if not _firebase_ready() or firebase_auth is None:
        raise HTTPException(status_code=503, detail="Firebase admin auth is not configured.")
    password = str(new_password or "")
    if len(password) < 8:
        raise HTTPException(status_code=400, detail="Password must be at least 8 characters.")
    try:
        firebase_auth.update_user(uid, password=password)  # type: ignore[attr-defined]
    except Exception as exc:
        raise HTTPException(status_code=502, detail=f"Failed to reset password: {exc}") from exc


def _admin_revoke_user_sessions(uid: str) -> None:
    if not _firebase_ready() or firebase_auth is None:
        raise HTTPException(status_code=503, detail="Firebase admin auth is not configured.")
    try:
        firebase_auth.revoke_refresh_tokens(uid)  # type: ignore[attr-defined]
    except Exception as exc:
        raise HTTPException(status_code=502, detail=f"Failed to revoke sessions: {exc}") from exc


@app.get("/account/profile")
def account_profile(request: Request) -> JSONResponse:
    uid = _require_request_uid(request)
    is_admin = _request_is_admin(request, uid)
    profile = _user_profile_read(uid)
    if profile is None and not is_admin and (not VF_USER_ID_REQUIRED or not VF_AUTH_ENFORCE):
        profile = _ensure_user_profile(uid, request=request, allow_auto_backfill=True)
    required = bool(
        (not is_admin)
        and VF_USER_ID_REQUIRED
        and VF_AUTH_ENFORCE
        and not str((profile or {}).get("userId") or "").strip()
    )
    suggested = "" if is_admin else _user_profile_backfill_candidate(uid, _request_claim_email(request), "")
    return JSONResponse(
        {
            "ok": True,
            "requiredUserId": required,
            "suggestedUserId": suggested,
            "profile": profile or {"uid": uid, "userId": "", "status": "admin" if is_admin else "pending"},
        }
    )


@app.post("/account/profile")
def account_profile_upsert(payload: UserProfileUpsertRequest, request: Request) -> JSONResponse:
    uid = _require_request_uid(request)
    if _request_is_admin(request, uid):
        raise HTTPException(status_code=403, detail="Admin accounts do not use userId.")
    before = _user_profile_read(uid) or {}
    row = _user_profile_upsert(
        uid,
        user_id=payload.userId,
        display_name=payload.displayName,
        email=_request_claim_email(request) or str(before.get("email") or ""),
        created_by=uid,
        updated_by=uid,
        force_change=False,
        allow_existing_immutable=False,
    )
    _audit_append_event(
        action="user_profile_set",
        resource_type="user_profile",
        resource_id=str(uid),
        before=before,
        after=row,
        request=request,
        actor_uid=uid,
        actor_role="user",
        subject_uid=uid,
    )
    return JSONResponse({"ok": True, "profile": row})


@app.post("/account/profile/bootstrap")
def account_profile_bootstrap(request: Request) -> JSONResponse:
    uid = _require_request_uid(request)
    if _request_is_admin(request, uid):
        profile = _user_profile_read(uid)
        return JSONResponse({"ok": True, "profile": profile or {"uid": uid, "userId": "", "status": "admin"}})
    profile = _ensure_user_profile(uid, request=request, allow_auto_backfill=True)
    return JSONResponse({"ok": True, "profile": profile or {"uid": uid, "userId": ""}})


