def _reprice_reserved_usage(
    uid: str,
    request_id: str,
    engine: str,
    char_count: int,
    *,
    bypass_limits: bool = False,
    bypass_reason: str = "",
) -> dict[str, Any]:
    safe_chars = _as_positive_int(char_count)
    event_doc_id = f"{uid}_{request_id}"

    if _firestore_collection("usage_events") is None:
        with _INMEMORY_LOCK:
            event = dict(_INMEMORY_USAGE_EVENTS.get(event_doc_id) or {})
        if not event:
            return _reserve_usage(
                uid,
                request_id,
                engine,
                safe_chars,
                bypass_limits=bypass_limits,
                bypass_reason=bypass_reason,
            )
        if str(event.get("status") or "").strip().lower() != "reserved":
            return {"ok": True, "alreadyFinalized": True, "event": event}
        if _as_positive_int(event.get("chars")) == safe_chars:
            return {"ok": True, "alreadyPriced": True, "event": event}
    else:
        assert _FIRESTORE_DB is not None
        event_ref = _FIRESTORE_DB.collection("usage_events").document(event_doc_id)
        event_doc = event_ref.get()
        event = event_doc.to_dict() if event_doc.exists else {}
        if not event:
            return _reserve_usage(
                uid,
                request_id,
                engine,
                safe_chars,
                bypass_limits=bypass_limits,
                bypass_reason=bypass_reason,
            )
        if str(event.get("status") or "").strip().lower() != "reserved":
            return {"ok": True, "alreadyFinalized": True, "event": event}
        if _as_positive_int(event.get("chars")) == safe_chars:
            return {"ok": True, "alreadyPriced": True, "event": event}

    _finalize_usage(uid, request_id, success=False, error_detail="usage_repriced")
    return _reserve_usage(
        uid,
        request_id,
        engine,
        safe_chars,
        bypass_limits=bypass_limits,
        bypass_reason=bypass_reason,
    )

    return JSONResponse({"ok": True, "entitlements": _entitlement_usage_payload(uid)})


@app.post("/wallet/coupons/redeem")
def wallet_coupon_redeem(payload: CouponRedeemRequest, request: Request) -> JSONResponse:
    uid = _require_request_uid(request)
    admin_limit_bypass = bool(VF_ADMIN_COUPON_LIMIT_BYPASS and _request_is_admin(request, uid))
    code = _normalize_coupon_code(payload.code)
    if not code:
        raise HTTPException(status_code=400, detail="Coupon code is required.")
    now = _utc_now()

    coupons = _firestore_collection("coupons")
    redemptions = _firestore_collection("coupon_redemptions")
    entitlements = _firestore_collection("entitlements")
    transactions = _firestore_collection("wallet_transactions")

    if coupons is None or redemptions is None or entitlements is None or transactions is None or _FIRESTORE_DB is None or firebase_firestore is None:
        with _INMEMORY_LOCK:
            safe_code = _coupon_store_ref(code)
            coupon_id = str(_INMEMORY_COUPON_CODE_INDEX.get(safe_code) or "").strip()
            if not coupon_id:
                _inmemory_rebuild_coupon_index_locked()
                coupon_id = str(_INMEMORY_COUPON_CODE_INDEX.get(safe_code) or "").strip()
            if not coupon_id:
                raise HTTPException(status_code=404, detail="Coupon not found.")
            coupon_row = _INMEMORY_COUPONS.get(coupon_id) or {}
            coupon = _coupon_backfill_fields(coupon_row or {}, now)
            if not _as_bool(coupon.get("active")):
                raise HTTPException(status_code=400, detail="Coupon is inactive.")
            if _coupon_is_expired(coupon, now):
                raise HTTPException(status_code=400, detail="Coupon has expired.")
            if _normalize_coupon_type(str(coupon.get("couponType") or "")) != COUPON_TYPE_WALLET_CREDIT:
                raise HTTPException(status_code=400, detail="Coupon is not redeemable as wallet credit.")
            policy = _normalize_coupon_usage_policy(str(coupon.get("usagePolicy") or ""))
            user_coupon_key = _coupon_user_key(coupon_id, uid)
            has_user_redeemed = any(
                str((entry or {}).get("couponId") or "").strip() == coupon_id
                and str((entry or {}).get("uid") or "").strip() == uid
                and str((entry or {}).get("channel") or "wallet").strip().lower() == "wallet"
                and str((entry or {}).get("status") or "redeemed").strip().lower() in {"reserved", "redeemed"}
                for entry in _INMEMORY_COUPON_REDEMPTIONS.values()
            )
            if not admin_limit_bypass and policy == COUPON_USAGE_SINGLE_PER_USER and has_user_redeemed:
                raise HTTPException(status_code=409, detail="Coupon already redeemed by this user.")
            if not admin_limit_bypass and _coupon_usage_limit_reached(coupon):
                raise HTTPException(status_code=400, detail="Coupon redemption limit reached.")
            credit_vf = _as_positive_int(coupon.get("creditVf"))
            if credit_vf <= 0:
                raise HTTPException(status_code=400, detail="Coupon has no redeemable value.")

            coupon["redeemedCount"] = _as_positive_int(coupon.get("redeemedCount")) + 1
            coupon["updatedAt"] = now.isoformat()
            _INMEMORY_COUPONS[coupon_id] = dict(coupon)
            redemption_key = (
                f"{coupon_id}_{uid}_{uuid.uuid4().hex}"
                if policy in {COUPON_USAGE_SINGLE_GLOBAL, COUPON_USAGE_MAX_REDEMPTIONS} or admin_limit_bypass
                else user_coupon_key
            )
            _INMEMORY_COUPON_REDEMPTIONS[redemption_key] = {
                "id": redemption_key,
                "couponId": coupon_id,
                "uid": uid,
                "code": code,
                "creditedVf": credit_vf,
                "channel": "wallet",
                "status": "redeemed",
                "usagePolicy": policy,
                "couponType": COUPON_TYPE_WALLET_CREDIT,
                "createdAt": now.isoformat(),
            }
        coupon_tx_id = (
            f"coupon_wallet_{coupon_id}_{uid}_{uuid.uuid4().hex}"
            if policy in {COUPON_USAGE_SINGLE_GLOBAL, COUPON_USAGE_MAX_REDEMPTIONS} or admin_limit_bypass
            else f"coupon_wallet_{coupon_id}_{uid}"
        )
        _credit_paid_vf(
            uid=uid,
            amount=credit_vf,
            reason="coupon_redeem",
            transaction_id=coupon_tx_id,
            metadata={
                "couponId": coupon_id,
                "code": code,
                "channel": "wallet",
                "usagePolicy": policy,
                "adminLimitBypass": bool(admin_limit_bypass),
            },
        )
        _audit_append_event(
            action="wallet_coupon_redeem",
            resource_type="coupon_redemption",
            resource_id=f"{coupon_id}:{uid}",
            after={"couponId": coupon_id, "code": code, "creditedVf": credit_vf, "channel": "wallet"},
            request=request,
            actor_uid=uid,
            actor_role="user",
            subject_uid=uid,
        )
        return JSONResponse({"ok": True, "creditedVf": credit_vf, "entitlements": _entitlement_usage_payload(uid)})

    coupon_id, coupon_lookup = _coupon_get_firestore_by_code(code)
    if not coupon_id or not coupon_lookup:
        raise HTTPException(status_code=404, detail="Coupon not found.")
    coupon_lookup = _coupon_backfill_fields(coupon_lookup, now)
    if _normalize_coupon_type(str(coupon_lookup.get("couponType") or "")) != COUPON_TYPE_WALLET_CREDIT:
        raise HTTPException(status_code=400, detail="Coupon is not redeemable as wallet credit.")
    policy = _normalize_coupon_usage_policy(str(coupon_lookup.get("usagePolicy") or ""))
    redemption_doc_id = (
        f"{coupon_id}_{uid}_{uuid.uuid4().hex}"
        if policy in {COUPON_USAGE_SINGLE_GLOBAL, COUPON_USAGE_MAX_REDEMPTIONS} or admin_limit_bypass
        else f"{coupon_id}::{uid}::wallet"
    )
    tx_doc_id = (
        f"coupon_wallet_{coupon_id}_{uid}_{uuid.uuid4().hex}"
        if policy in {COUPON_USAGE_SINGLE_GLOBAL, COUPON_USAGE_MAX_REDEMPTIONS} or admin_limit_bypass
        else f"coupon_wallet_{coupon_id}_{uid}"
    )
    coupon_ref = _FIRESTORE_DB.collection("coupons").document(coupon_id)
    redemption_ref = _FIRESTORE_DB.collection("coupon_redemptions").document(redemption_doc_id)
    entitlement_ref = _FIRESTORE_DB.collection("entitlements").document(uid)
    tx_ref = _FIRESTORE_DB.collection("wallet_transactions").document(tx_doc_id)
    transaction = _FIRESTORE_DB.transaction()

    @firebase_firestore.transactional
    def _apply(transaction_obj: Any) -> int:
        fresh_coupon_doc = coupon_ref.get(transaction=transaction_obj)
        if not fresh_coupon_doc.exists:
            raise RuntimeError("Coupon not found.")
        coupon = _coupon_backfill_fields({**(fresh_coupon_doc.to_dict() or {}), "id": coupon_id}, now)
        if not _as_bool(coupon.get("active")):
            raise RuntimeError("Coupon is inactive.")
        if _coupon_is_expired(coupon, now):
            raise RuntimeError("Coupon has expired.")
        if not admin_limit_bypass and policy == COUPON_USAGE_SINGLE_PER_USER:
            redemption_doc = redemption_ref.get(transaction=transaction_obj)
            if redemption_doc.exists:
                raise RuntimeError("Coupon already redeemed by this user.")
        if not admin_limit_bypass and _coupon_usage_limit_reached(coupon):
            raise RuntimeError("Coupon redemption limit reached.")
        credit_vf = _as_positive_int(coupon.get("creditVf"))
        if credit_vf <= 0:
            raise RuntimeError("Coupon has no redeemable value.")

        ent_doc = entitlement_ref.get(transaction=transaction_obj)
        entitlement = _normalize_entitlement_wallet(ent_doc.to_dict() if ent_doc.exists else _default_entitlement(uid), now)
        entitlement = _append_paid_vf_credit_lot(
            entitlement,
            amount=_as_positive_number(credit_vf),
            reason="coupon_redeem",
            transaction_id=tx_doc_id,
            metadata={
                "couponId": coupon_id,
                "code": code,
                "channel": "wallet",
                "usagePolicy": policy,
                "adminLimitBypass": bool(admin_limit_bypass),
            },
            now=now,
        )
        entitlement["updatedAt"] = now.isoformat()
        coupon["redeemedCount"] = _as_positive_int(coupon.get("redeemedCount")) + 1
        coupon["updatedAt"] = now.isoformat()

        transaction_obj.set(coupon_ref, coupon, merge=True)
        transaction_obj.set(
            redemption_ref,
            {
                "id": redemption_ref.id,
                "couponId": coupon_id,
                "uid": uid,
                "code": code,
                "creditedVf": credit_vf,
                "channel": "wallet",
                "status": "redeemed",
                "usagePolicy": policy,
                "couponType": COUPON_TYPE_WALLET_CREDIT,
                "createdAt": now.isoformat(),
            },
            merge=True,
        )
        transaction_obj.set(entitlement_ref, entitlement, merge=True)
        transaction_obj.set(
            tx_ref,
            {
                "id": tx_ref.id,
                "uid": uid,
                "kind": "credit",
                "bucket": "paidVF",
                "amount": credit_vf,
                "reason": "coupon_redeem",
                "metadata": {
                    "couponId": coupon_id,
                    "code": code,
                    "channel": "wallet",
                    "usagePolicy": policy,
                    "adminLimitBypass": bool(admin_limit_bypass),
                },
                "createdAt": now.isoformat(),
            },
            merge=True,
        )
        return credit_vf

    try:
        credited_vf = _apply(transaction)
    except RuntimeError as exc:
        detail = str(exc)
        status = 409 if "already redeemed" in detail.lower() else 400
        if "not found" in detail.lower():
            status = 404
        raise HTTPException(status_code=status, detail=detail) from exc

    _audit_append_event(
        action="wallet_coupon_redeem",
        resource_type="coupon_redemption",
        resource_id=f"{coupon_id}:{uid}",
        after={"couponId": coupon_id, "code": code, "creditedVf": credited_vf, "channel": "wallet"},
        request=request,
        actor_uid=uid,
        actor_role="user",
        subject_uid=uid,
    )
    return JSONResponse({"ok": True, "creditedVf": credited_vf, "entitlements": _entitlement_usage_payload(uid)})


def _load_daily_usage_reset_status() -> dict[str, Any]:
    collection = _firestore_collection("admin_ops")
    if collection is None:
        with _INMEMORY_LOCK:
            return dict(_INMEMORY_DAILY_USAGE_RESET_STATUS or {})
    try:
        doc = collection.document("daily_usage_reset_status").get()
    except Exception:
        return {}
    if not doc.exists:
        return {}
    payload = doc.to_dict() or {}
    payload["id"] = "daily_usage_reset_status"
    return payload


def _write_daily_usage_reset_status(payload: dict[str, Any]) -> None:
    row = dict(payload or {})
    collection = _firestore_collection("admin_ops")
    if collection is None:
        with _INMEMORY_LOCK:
            _INMEMORY_DAILY_USAGE_RESET_STATUS.clear()
            _INMEMORY_DAILY_USAGE_RESET_STATUS.update(row)
        return
    try:
        collection.document("daily_usage_reset_status").set(row, merge=False)
    except Exception:
        with _INMEMORY_LOCK:
            _INMEMORY_DAILY_USAGE_RESET_STATUS.clear()
            _INMEMORY_DAILY_USAGE_RESET_STATUS.update(row)


def _reset_daily_usage_all(*, dry_run: bool, requested_by: str) -> dict[str, Any]:
    now = _utc_now()
    period_key = _usage_day_period_label(now)
    day_key = _usage_day_key(now)
    mode = "in_memory"
    docs_cleared = 0
    users: set[str] = set()
    reserved_events_today: Optional[int] = None

    usage_daily = _firestore_collection("usage_daily")
    if usage_daily is None:
        with _INMEMORY_LOCK:
            matching_keys: list[str] = []
            for doc_id, row in _INMEMORY_USAGE_DAILY.items():
                if str((row or {}).get("periodKey") or "").strip() != period_key:
                    continue
                matching_keys.append(doc_id)
                uid = str((row or {}).get("uid") or "").strip()
                if uid:
                    users.add(uid)
            docs_cleared = len(matching_keys)
            if not dry_run:
                for doc_id in matching_keys:
                    _INMEMORY_USAGE_DAILY.pop(doc_id, None)
            reserved_events_today = sum(
                1
                for event in _INMEMORY_USAGE_EVENTS.values()
                if str((event or {}).get("status") or "").strip().lower() == "reserved"
                and str((event or {}).get("dayDocId") or "").strip().endswith(f"_{day_key}")
            )
    else:
        mode = "firestore"
        try:
            docs = list(usage_daily.where("periodKey", "==", period_key).stream())
        except Exception:
            docs = []
        for doc in docs:
            row = doc.to_dict() or {}
            uid = str(row.get("uid") or "").strip()
            if uid:
                users.add(uid)
        docs_cleared = len(docs)
        if not dry_run:
            for doc in docs:
                try:
                    doc.reference.delete()
                except Exception:
                    continue

    summary = {
        "ok": True,
        "dryRun": bool(dry_run),
        "mode": mode,
        "dayKey": day_key,
        "periodKey": period_key,
        "usersAffected": len(users),
        "docsCleared": docs_cleared,
        "requestedBy": str(requested_by or "").strip(),
        "ranAt": now.isoformat(),
        "reservedEventsToday": reserved_events_today,
    }
    if not dry_run:
        _write_daily_usage_reset_status(summary)
    return summary


def _cleanup_entitlements_daily_generation_limit(*, dry_run: bool, requested_by: str) -> dict[str, Any]:
    now_iso = _safe_now_iso()
    mode = "in_memory"
    docs_scanned = 0
    docs_with_legacy_field = 0
    docs_cleaned = 0
    users: set[str] = set()

    entitlements = _firestore_collection("entitlements")
    if entitlements is None:
        with _INMEMORY_LOCK:
            docs_scanned = len(_INMEMORY_ENTITLEMENTS)
            for uid, row in list(_INMEMORY_ENTITLEMENTS.items()):
                current = dict(row or {})
                if "dailyGenerationLimit" not in current:
                    continue
                docs_with_legacy_field += 1
                safe_uid = str(uid or "").strip()
                if safe_uid:
                    users.add(safe_uid)
                if dry_run:
                    continue
                current.pop("dailyGenerationLimit", None)
                current["updatedAt"] = now_iso
                _INMEMORY_ENTITLEMENTS[uid] = current
                docs_cleaned += 1
    else:
        mode = "firestore"
        try:
            docs = list(entitlements.stream())
        except Exception:
            docs = []
        docs_scanned = len(docs)
        for doc in docs:
            row = doc.to_dict() or {}
            if "dailyGenerationLimit" not in row:
                continue
            docs_with_legacy_field += 1
            uid = str(row.get("uid") or doc.id).strip()
            if uid:
                users.add(uid)
            if dry_run:
                continue
            clean_row = dict(row)
            clean_row.pop("dailyGenerationLimit", None)
            clean_row["updatedAt"] = now_iso
            try:
                doc.reference.set(clean_row, merge=False)
                docs_cleaned += 1
            except Exception:
                continue

    return {
        "ok": True,
        "dryRun": bool(dry_run),
        "mode": mode,
        "docsScanned": docs_scanned,
        "docsWithLegacyField": docs_with_legacy_field,
        "docsCleared": docs_cleaned if not dry_run else 0,
        "usersAffected": len(users),
        "requestedBy": str(requested_by or "").strip(),
        "ranAt": now_iso,
    }


_ENGINE_CANONICAL_LIST_FIELDS = {"allowedEngines"}
_ENGINE_CANONICAL_MAP_FIELDS = {
    "byEngine",
    "engines",
    "runtimeLatencyByEngine",
    "semaphoreWaitByEngine",
    "spendableNowByEngine",
    "vfRates",
}
_ENGINE_CANONICAL_VALUE_FIELDS = {
    "engine",
    "sourceEngine",
    "sourceVoiceEngine",
    "targetEngine",
    "runtimeEngine",
    "laneEngine",
    "voiceEngine",
}


def _canonicalize_engine_value_for_migration(raw_value: Any) -> str:
    token = _resolve_internal_engine_token(str(raw_value or ""))
    return token or str(raw_value or "").strip()


def _canonicalize_engine_map_for_migration(value: Any) -> tuple[dict[str, Any], bool]:
    if not isinstance(value, dict):
        return {}, False
    changed = False
    out: dict[str, Any] = {}
    for raw_key, raw_val in value.items():
        key = _resolve_internal_engine_token(str(raw_key or "")) or str(raw_key or "").strip()
        if not key:
            continue
        if key != str(raw_key or "").strip():
            changed = True
        if isinstance(raw_val, dict):
            next_val, child_changed = _canonicalize_engine_doc_fields_for_migration(raw_val)
            out[key] = next_val
            changed = changed or child_changed
        elif isinstance(raw_val, list):
            next_list: list[Any] = []
            list_changed = False
            for item in raw_val:
                if isinstance(item, (dict, list)):
                    next_item, item_changed = _canonicalize_engine_doc_value_for_migration(item)
                    next_list.append(next_item)
                    list_changed = list_changed or item_changed
                else:
                    next_list.append(item)
            out[key] = next_list
            changed = changed or list_changed
        else:
            out[key] = raw_val
    return out, changed


def _canonicalize_engine_doc_value_for_migration(value: Any) -> tuple[Any, bool]:
    if isinstance(value, dict):
        return _canonicalize_engine_doc_fields_for_migration(value)
    if isinstance(value, list):
        out: list[Any] = []
        changed = False
        for item in value:
            if isinstance(item, (dict, list)):
                next_item, item_changed = _canonicalize_engine_doc_value_for_migration(item)
                out.append(next_item)
                changed = changed or item_changed
            else:
                out.append(item)
        return out, changed
    return value, False


def _canonicalize_engine_doc_fields_for_migration(row: dict[str, Any]) -> tuple[dict[str, Any], bool]:
    changed = False
    out = dict(row or {})
    for key in list(out.keys()):
        value = out[key]
        if key in _ENGINE_CANONICAL_VALUE_FIELDS:
            next_value = _canonicalize_engine_value_for_migration(value)
            if next_value != value:
                out[key] = next_value
                changed = True
            continue
        if key in _ENGINE_CANONICAL_LIST_FIELDS and isinstance(value, list):
            next_list: list[Any] = []
            seen: set[str] = set()
            for item in value:
                token = _canonicalize_engine_value_for_migration(item)
                safe_token = str(token or "").strip()
                if not safe_token or safe_token in seen:
                    continue
                seen.add(safe_token)
                next_list.append(safe_token)
            if next_list != value:
                out[key] = next_list
                changed = True
            continue
        if key in _ENGINE_CANONICAL_MAP_FIELDS:
            next_map, map_changed = _canonicalize_engine_map_for_migration(value)
            if map_changed or next_map != value:
                out[key] = next_map
                changed = True
            continue
        if isinstance(value, dict):
            next_value, child_changed = _canonicalize_engine_doc_fields_for_migration(value)
            if child_changed:
                out[key] = next_value
                changed = True
        elif isinstance(value, list):
            next_value, child_changed = _canonicalize_engine_doc_value_for_migration(value)
            if child_changed:
                out[key] = next_value
                changed = True
    return out, changed


def _detect_legacy_engine_tokens(value: Any) -> bool:
    if isinstance(value, dict):
        for key, item in value.items():
            if key in _ENGINE_CANONICAL_MAP_FIELDS and isinstance(item, dict):
                for raw_key in item.keys():
                    raw_token = str(raw_key or "").strip()
                    if raw_token and _resolve_internal_engine_token(raw_token) != raw_token.upper():
                        return True
            if key in _ENGINE_CANONICAL_VALUE_FIELDS and isinstance(item, str):
                if _resolve_internal_engine_token(item) and _resolve_internal_engine_token(item) != str(item or "").strip().upper():
                    return True
            if key in _ENGINE_CANONICAL_LIST_FIELDS and isinstance(item, list):
                for entry in item:
                    if isinstance(entry, str):
                        if _resolve_internal_engine_token(entry) and _resolve_internal_engine_token(entry) != str(entry or "").strip().upper():
                            return True
            if _detect_legacy_engine_tokens(item):
                return True
        return False
    if isinstance(value, list):
        return any(_detect_legacy_engine_tokens(item) for item in value)
    if isinstance(value, str):
        token = _resolve_internal_engine_token(value)
        return bool(token and token != str(value or "").strip().upper())
    return False


def _rewrite_engine_canonicalization_doc(doc: dict[str, Any], *, doc_type: str) -> tuple[dict[str, Any], bool]:
    payload = dict(doc or {})
    if doc_type == "generation_history":
        uid = str(payload.get("uid") or "").strip()
        items = _history_decode_items_gzip_b64(str(payload.get("itemsGzipB64") or ""), sanitize=False)
        sanitized_items = _history_prune_expired_items(items)
        next_payload = _history_row_from_items(uid, sanitized_items, now_iso=str(payload.get("updatedAt") or _safe_now_iso()))
        next_payload["uid"] = uid
        changed = next_payload.get("itemsGzipB64") != payload.get("itemsGzipB64")
        return next_payload, changed
    next_payload, changed = _canonicalize_engine_doc_fields_for_migration(payload)
    return next_payload, changed


def _engine_canonicalization_migration(*, mode: str, requested_by: str) -> dict[str, Any]:
    safe_mode = str(mode or "dry_run").strip().lower()
    if safe_mode not in {"dry_run", "apply", "verify"}:
        raise ValueError("Invalid migration mode. Use dry_run, apply, or verify.")
    dry_run = safe_mode == "dry_run"
    apply_changes = safe_mode == "apply"
    verify_only = safe_mode == "verify"
    now_iso = _safe_now_iso()
    collections = ("entitlements", "generation_history", "usage_monthly", "usage_daily", "usage_events", "audio_generation_audit")
    summary: dict[str, Any] = {
        "ok": True,
        "mode": safe_mode,
        "dryRun": dry_run,
        "applied": apply_changes,
        "verified": verify_only,
        "requestedBy": str(requested_by or "").strip(),
        "ranAt": now_iso,
        "collections": {},
        "legacyTokensRemaining": 0,
    }

    for collection_name in collections:
        collection = _firestore_collection(collection_name)
        scanned = 0
        changed = 0
        legacy_remaining = 0
        if collection is None:
            with _INMEMORY_LOCK:
                if collection_name == "entitlements":
                    source_items = list(_INMEMORY_ENTITLEMENTS.items())
                elif collection_name == "generation_history":
                    source_items = list(_INMEMORY_GENERATION_HISTORY.items())
                elif collection_name == "usage_monthly":
                    source_items = list(_INMEMORY_USAGE_MONTHLY.items())
                elif collection_name == "usage_daily":
                    source_items = list(_INMEMORY_USAGE_DAILY.items())
                elif collection_name == "audio_generation_audit":
                    source_items = list(_INMEMORY_AUDIO_GENERATION_AUDIT.items())
                else:
                    source_items = list(_INMEMORY_USAGE_EVENTS.items())
                scanned = len(source_items)
                for doc_id, row in source_items:
                    if not isinstance(row, dict):
                        continue
                    next_row, row_changed = _rewrite_engine_canonicalization_doc(row, doc_type=collection_name)
                    if _detect_legacy_engine_tokens(next_row):
                        legacy_remaining += 1
                    if row_changed and apply_changes:
                        changed += 1
                        if collection_name == "entitlements":
                            _INMEMORY_ENTITLEMENTS[doc_id] = next_row
                        elif collection_name == "generation_history":
                            _INMEMORY_GENERATION_HISTORY[doc_id] = next_row
                        elif collection_name == "usage_monthly":
                            _INMEMORY_USAGE_MONTHLY[doc_id] = next_row
                        elif collection_name == "usage_daily":
                            _INMEMORY_USAGE_DAILY[doc_id] = next_row
                        elif collection_name == "audio_generation_audit":
                            _INMEMORY_AUDIO_GENERATION_AUDIT[doc_id] = next_row
                        else:
                            _INMEMORY_USAGE_EVENTS[doc_id] = next_row
                    elif row_changed:
                        changed += 1
        else:
            try:
                docs = list(collection.stream())
            except Exception:
                docs = []
            scanned = len(docs)
            for doc in docs:
                row = doc.to_dict() or {}
                if not isinstance(row, dict):
                    continue
                next_row, row_changed = _rewrite_engine_canonicalization_doc(row, doc_type=collection_name)
                if _detect_legacy_engine_tokens(next_row):
                    legacy_remaining += 1
                if row_changed:
                    changed += 1
                    if not dry_run:
                        try:
                            doc.reference.set(next_row, merge=False)
                        except Exception:
                            continue
        summary["collections"][collection_name] = {
            "scanned": scanned,
            "changed": changed,
            "legacyRemaining": legacy_remaining,
        }
        summary["legacyTokensRemaining"] += legacy_remaining

    queue_summary = _TTS_V2_ENGINE.canonicalize_engine_metadata(mode=safe_mode)
    summary["queueJobMetadata"] = queue_summary
    summary["legacyTokensRemaining"] += int(queue_summary.get("legacyTokensRemaining") or 0)
    if verify_only and summary["legacyTokensRemaining"] > 0:
        summary["ok"] = False
    return summary


@app.post("/admin/session-unlock/issue")
def admin_session_unlock_issue(request: Request) -> JSONResponse:
    uid = _require_admin_unlock_uid(request)
    issued = _admin_unlock_issue_for_request(request, uid)
    status_payload = _admin_unlock_status_for_request(request, uid)
    _notification_emit_persisted(
        uid,
        event_code="admin.session.unlock.issued",
        title="Admin Unlock Key Issued",
        message="A new admin unlock key was issued for this session.",
        details=f"keyExpiresAt={str(issued.get('keyExpiresAt') or '')}",
        severity="info",
        category="security",
        audience="admin",
        entity_key=uid,
        dedupe_key=f"admin.session.unlock.issued::{uid}",
        action_label="Open Admin",
        action_target={"screen": "main", "tab": "ADMIN", "adminTab": "usage"},
        email_eligible=False,
        email_pref_key="emailAdminAlerts",
    )
    return JSONResponse(
        {
            "ok": True,
            "uid": uid,
            "unlockKey": issued.get("unlockKey"),
            "keyExpiresAtMs": issued.get("keyExpiresAtMs"),
            "keyExpiresAt": issued.get("keyExpiresAt"),
            "status": status_payload,
        }
    )


